export interface MonthlyClimateData {
  month: string;
  monthIdx: number;
  tempAvg: number;
  tempMax: number;
  tempMin: number;
  rainfall: number;
  rainyDays: number;
  humidity: number;
  humidityMax: number;
  humidityMin: number;
  windSpeed: number;
  windMax: number;
  windDir: number;
  solarIntensity: number; // Shortwave radiation in MJ/m² or W/m²
  peakSunHours: number;
  heatIndex: number;
  isSunny: boolean;
  isRainy: boolean;
  isWinter: boolean;
  isWindy: boolean;
}

export interface LocationInfo {
  name: string;
  lat: number;
  lng: number;
  country?: string;
}

export interface ClimateStats {
  location: LocationInfo;
  period: string;
  monthlyData: MonthlyClimateData[];
  summary: {
    hottestMonth: string;
    coldestMonth: string;
    rainiestMonth: string;
    sunniestMonth: string;
  };
}

export enum Page {
  OVERVIEW = 'overview',
  SUNNY = 'sunny',
  RAINY = 'rainy',
  WINTER = 'winter',
  STATS = 'stats',
  GRAPHS = 'graphs'
}

import { ClimateStats, MonthlyClimateData, LocationInfo } from '../types';

const MONTH_NAMES = [
  "January", "February", "March", "April", "May", "June",
  "July", "August", "September", "October", "November", "December"
];

export async function geocode(query: string): Promise<LocationInfo[]> {
  const url = `https://geocoding-api.open-meteo.com/v1/search?name=${encodeURIComponent(query)}&count=5&language=en&format=json`;
  const response = await fetch(url);
  const data = await response.json();
  if (!data.results) return [];
  return data.results.map((r: any) => ({
    name: r.name,
    lat: r.latitude,
    lng: r.longitude,
    country: r.country
  }));
}

export async function fetchClimateData(lat: number, lng: number, locationName?: string): Promise<ClimateStats> {
  // We use the Climate API from Open-Meteo which provides 30-year normals (ERA5)
  // https://climate-api.open-meteo.com/v1/climate?latitude=...
  const url = `https://climate-api.open-meteo.com/v1/climate?latitude=${lat}&longitude=${lng}&start_date=1990-01-01&end_date=2020-12-31&models=ERA5&daily=temperature_2m_max,temperature_2m_min,temperature_2m_mean,precipitation_sum,shortwave_radiation_sum,windspeed_10m_max,relative_humidity_2m_mean`;

  const response = await fetch(url);
  if (!response.ok) throw new Error("Failed to fetch climate data");
  const raw = await response.json();

  const daily = raw.daily;
  const time = daily.time; // Format "YYYY-MM-DD"

  // Initialize buckets for each month (0-11)
  const monthBuckets = Array.from({ length: 12 }, () => ({
    tempMax: [] as number[],
    tempMin: [] as number[],
    tempMean: [] as number[],
    rain: [] as number[],
    solar: [] as number[],
    wind: [] as number[],
    humidity: [] as number[],
    rainyDays: 0,
    totalDays: 0
  }));

  // Aggregate daily data into monthly normals
  for (let i = 0; i < time.length; i++) {
    const date = new Date(time[i]);
    const m = date.getMonth();
    const bucket = monthBuckets[m];

    bucket.tempMax.push(daily.temperature_2m_max[i]);
    bucket.tempMin.push(daily.temperature_2m_min[i]);
    bucket.tempMean.push(daily.temperature_2m_mean[i]);
    bucket.rain.push(daily.precipitation_sum[i]);
    bucket.solar.push(daily.shortwave_radiation_sum[i]);
    bucket.wind.push(daily.windspeed_10m_max[i]);
    bucket.humidity.push(daily.relative_humidity_2m_mean[i]);

    if (daily.precipitation_sum[i] >= 1.0) bucket.rainyDays++;
    bucket.totalDays++;
  }

  // Calculate monthly stats
  const yearsProcessed = 31; // 1990 to 2020 inclusive
  const monthlyData: MonthlyClimateData[] = monthBuckets.map((b, idx) => {
    const avg = (arr: number[]) => arr.length ? arr.reduce((a, c) => a + c, 0) / arr.length : 0;
    const max = (arr: number[]) => arr.length ? Math.max(...arr) : 0;
    const min = (arr: number[]) => arr.length ? Math.min(...arr) : 0;

    const tAvg = avg(b.tempMean);
    const rh = avg(b.humidity);

    // Basic Heat Index approximation
    const hi = tAvg + 0.5 * (rh - 50);

    return {
      month: MONTH_NAMES[idx],
      monthIdx: idx,
      tempAvg: parseFloat(tAvg.toFixed(1)),
      tempMax: parseFloat(max(b.tempMax).toFixed(1)),
      tempMin: parseFloat(min(b.tempMin).toFixed(1)),
      rainfall: parseFloat((avg(b.rain) * 30.4).toFixed(1)), // Monthly estimate from daily avg
      rainyDays: Math.round(b.rainyDays / yearsProcessed),
      humidity: parseFloat(rh.toFixed(1)),
      humidityMax: parseFloat(max(b.humidity).toFixed(1)),
      humidityMin: parseFloat(min(b.humidity).toFixed(1)),
      windSpeed: parseFloat(avg(b.wind).toFixed(1)),
      windMax: parseFloat(max(b.wind).toFixed(1)),
      windDir: 0, // Not provided in 30yr normals typically, default 0
      solarIntensity: parseFloat(avg(b.solar).toFixed(1)),
      peakSunHours: parseFloat((avg(b.solar) / 3.6).toFixed(1)), // Conversion approximation
      heatIndex: parseFloat(hi.toFixed(1)),
      // Classifications
      isSunny: false,
      isRainy: false,
      isWinter: false,
      isWindy: false
    };
  });

  // Classification Logic
  // Sort for thresholds
  const sortedTemp = [...monthlyData].sort((a, b) => a.tempAvg - b.tempAvg);
  const sortedRain = [...monthlyData].sort((a, b) => a.rainfall - b.rainfall);
  const sortedSolar = [...monthlyData].sort((a, b) => a.solarIntensity - b.solarIntensity);
  const sortedWind = [...monthlyData].sort((a, b) => a.windSpeed - b.windSpeed);

  // Top 3 for each
  const coldestThreshold = sortedTemp[2].tempAvg;
  const rainiestThreshold = sortedRain[9].rainfall;
  const sunniestThreshold = sortedSolar[9].solarIntensity;
  const windiestThreshold = sortedWind[9].windSpeed;

  monthlyData.forEach(m => {
    if (m.tempAvg <= coldestThreshold) m.isWinter = true;
    if (m.rainfall >= rainiestThreshold) m.isRainy = true;
    if (m.solarIntensity >= sunniestThreshold && m.rainfall < rainiestThreshold) m.isSunny = true;
    if (m.windSpeed >= windiestThreshold) m.isWindy = true;
  });

  return {
    location: {
      name: locationName || "Custom Location",
      lat,
      lng
    },
    period: "1990 - 2020 (30-year Normals)",
    monthlyData,
    summary: {
      hottestMonth: sortedTemp[11].month,
      coldestMonth: sortedTemp[0].month,
      rainiestMonth: sortedRain[11].month,
      sunniestMonth: sortedSolar[11].month,
    }
  };
}

import { GoogleGenAI } from "@google/genai";
import { ClimateStats } from "../types";

export async function getClimateInsights(stats: ClimateStats): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    Act as a senior climate engineer. Analyze the following climate stats for ${stats.location.name} (${stats.location.lat}, ${stats.location.lng}).
    Provide a concise, user-friendly 2-3 sentence summary explaining what a visitor or resident should expect regarding climate comfort and seasonal patterns. 
    Use a friendly tone.

    Data Summary:
    - Hottest month: ${stats.summary.hottestMonth}
    - Coldest month: ${stats.summary.coldestMonth}
    - Rainiest month: ${stats.summary.rainiestMonth}
    - Typical Humidity: ${stats.monthlyData[6].humidity}%
    - Period: ${stats.period}
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "Climate analysis complete. Explore the data below.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Explore the detailed climate metrics below for a comprehensive view.";
  }
}

import React, { useState, useEffect } from 'react';
import { Page, ClimateStats, LocationInfo } from './types';
import { fetchClimateData, geocode } from './services/climateService';
import { getClimateInsights } from './services/geminiService';
import Header from './components/Header';
import Overview from './components/Overview';
import SeasonalDetail from './components/SeasonalDetail';
import StatsTable from './components/StatsTable';
import Visuals from './components/Visuals';

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState<Page>(Page.OVERVIEW);
  const [loading, setLoading] = useState<boolean>(true);
  const [data, setData] = useState<ClimateStats | null>(null);
  const [insights, setInsights] = useState<string>("");
  const [search, setSearch] = useState<string>("San Francisco");
  const [searchResults, setSearchResults] = useState<LocationInfo[]>([]);

  const loadData = async (lat: number, lng: number, name: string) => {
    setLoading(true);
    try {
      const stats = await fetchClimateData(lat, lng, name);
      setData(stats);
      const text = await getClimateInsights(stats);
      setInsights(text);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    // Initial Load
    loadData(37.7749, -122.4194, "San Francisco");
  }, []);

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    const results = await geocode(search);
    setSearchResults(results);
  };

  const selectLocation = (loc: LocationInfo) => {
    loadData(loc.lat, loc.lng, loc.name);
    setSearchResults([]);
    setSearch(loc.name);
  };

  if (!data && loading) {
    return (
      <div className="flex items-center justify-center h-screen bg-slate-50">
        <div className="text-center">
          <div className="animate-spin rounded-full h-16 w-16 border-b-2 border-blue-600 mx-auto mb-4"></div>
          <p className="text-slate-600 font-medium">Computing Climate Intelligence...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-6xl mx-auto px-4 pb-20 pt-6">
      <div className="mb-8 flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-3xl font-extrabold text-slate-800 tracking-tight">ClimaIntel</h1>
          <p className="text-slate-500">Global Historical Climate Data Engine</p>
        </div>

        <div className="relative">
          <form onSubmit={handleSearch} className="flex gap-2">
            <input 
              type="text" 
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              placeholder="Search city..." 
              className="px-4 py-2 rounded-xl border border-slate-200 focus:outline-none focus:ring-2 focus:ring-blue-500 w-full md:w-64"
            />
            <button type="submit" className="bg-blue-600 text-white px-4 py-2 rounded-xl hover:bg-blue-700 transition">
              Search
            </button>
          </form>
          {searchResults.length > 0 && (
            <div className="absolute top-full left-0 right-0 bg-white shadow-xl rounded-xl mt-2 z-50 border border-slate-100 overflow-hidden">
              {searchResults.map((loc, i) => (
                <button 
                  key={i} 
                  onClick={() => selectLocation(loc)}
                  className="w-full text-left px-4 py-3 hover:bg-slate-50 transition border-b border-slate-50 last:border-none"
                >
                  <span className="font-semibold">{loc.name}</span>
                  {loc.country && <span className="text-xs text-slate-400 ml-2">{loc.country}</span>}
                </button>
              ))}
            </div>
          )}
        </div>
      </div>

      {data && (
        <>
          <Header data={data} insights={insights} />

          <nav className="flex overflow-x-auto gap-1 mb-8 bg-white p-1 rounded-2xl shadow-sm border border-slate-100 scrollbar-hide">
            {[
              { id: Page.OVERVIEW, label: "Overview", icon: "🌍" },
              { id: Page.SUNNY, label: "Sunny", icon: "☀️" },
              { id: Page.RAINY, label: "Rainy", icon: "🌧️" },
              { id: Page.WINTER, label: "Winter", icon: "❄️" },
              { id: Page.STATS, label: "All Stats", icon: "📅" },
              { id: Page.GRAPHS, label: "Graphs", icon: "📈" },
            ].map(tab => (
              <button
                key={tab.id}
                onClick={() => setCurrentPage(tab.id as Page)}
                className={`flex items-center gap-2 px-4 py-2.5 rounded-xl whitespace-nowrap transition-all duration-200 ${
                  currentPage === tab.id 
                    ? 'bg-blue-600 text-white shadow-md' 
                    : 'text-slate-600 hover:bg-slate-50'
                }`}
              >
                <span>{tab.icon}</span>
                <span className="font-medium text-sm">{tab.label}</span>
              </button>
            ))}
          </nav>

          <main className="animate-in fade-in duration-500">
            {currentPage === Page.OVERVIEW && <Overview data={data} />}
            {currentPage === Page.SUNNY && <SeasonalDetail data={data} type="sunny" />}
            {currentPage === Page.RAINY && <SeasonalDetail data={data} type="rainy" />}
            {currentPage === Page.WINTER && <SeasonalDetail data={data} type="winter" />}
            {currentPage === Page.STATS && <StatsTable data={data} />}
            {currentPage === Page.GRAPHS && <Visuals data={data} />}
          </main>
        </>
      )}

      {loading && (
        <div className="fixed inset-0 bg-white/60 flex items-center justify-center z-[100]">
          <div className="animate-pulse text-blue-600 font-bold">Updating Data...</div>
        </div>
      )}
    </div>
  );
};

export default App;

