import React from 'react';
import { ClimateStats } from '../types';

interface Props {
  data: ClimateStats;
}

const Overview: React.FC<Props> = ({ data }) => {
  const sunnyMonths = data.monthlyData.filter(m => m.isSunny).map(m => m.month);
  const rainyMonths = data.monthlyData.filter(m => m.isRainy).map(m => m.month);
  const winterMonths = data.monthlyData.filter(m => m.isWinter).map(m => m.month);
  const windyMonths = data.monthlyData.filter(m => m.isWindy).map(m => m.month);

  const getComfortColor = (temp: number) => {
    if (temp > 32) return 'text-red-600 bg-red-50';
    if (temp > 24) return 'text-orange-600 bg-orange-50';
    if (temp > 18) return 'text-green-600 bg-green-50';
    return 'text-blue-600 bg-blue-50';
  };

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <SeasonCard 
          title="Sunny Season" 
          months={sunnyMonths} 
          icon="☀️" 
          color="bg-orange-500" 
          accent="text-orange-700" 
          bg="bg-orange-50"
        />
        <SeasonCard 
          title="Rainy Season" 
          months={rainyMonths} 
          icon="🌧️" 
          color="bg-blue-500" 
          accent="text-blue-700" 
          bg="bg-blue-50"
        />
        <SeasonCard 
          title="Winter Season" 
          months={winterMonths} 
          icon="❄️" 
          color="bg-indigo-500" 
          accent="text-indigo-700" 
          bg="bg-indigo-50"
        />
        <SeasonCard 
          title="Windy Season" 
          months={windyMonths} 
          icon="🌬️" 
          color="bg-teal-500" 
          accent="text-teal-700" 
          bg="bg-teal-50"
        />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mt-8">
        <MetricCard 
          label="Hottest Month" 
          value={data.summary.hottestMonth} 
          detail={`${data.monthlyData.find(m => m.month === data.summary.hottestMonth)?.tempMax}°C Avg Max`}
          color="text-red-600"
        />
        <MetricCard 
          label="Coldest Month" 
          value={data.summary.coldestMonth} 
          detail={`${data.monthlyData.find(m => m.month === data.summary.coldestMonth)?.tempMin}°C Avg Min`}
          color="text-blue-600"
        />
        <MetricCard 
          label="Rainiest Month" 
          value={data.summary.rainiestMonth} 
          detail={`${data.monthlyData.find(m => m.month === data.summary.rainiestMonth)?.rainfall}mm Total`}
          color="text-cyan-600"
        />
      </div>
    </div>
  );
};

const SeasonCard: React.FC<{title: string, months: string[], icon: string, color: string, accent: string, bg: string}> = ({
  title, months, icon, color, accent, bg
}) => (
  <div className={`${bg} border border-white p-6 rounded-3xl shadow-sm hover:shadow-md transition-all`}>
    <div className={`${color} w-12 h-12 rounded-2xl flex items-center justify-center text-2xl mb-4 shadow-sm text-white`}>
      {icon}
    </div>
    <h3 className={`text-xl font-bold ${accent} mb-2`}>{title}</h3>
    <p className="text-slate-600 text-sm font-medium leading-relaxed">
      {months.length > 0 ? months.join(', ') : 'Not applicable to this location'}
    </p>
  </div>
);

const MetricCard: React.FC<{label: string, value: string, detail: string, color: string}> = ({
  label, value, detail, color
}) => (
  <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm">
    <span className="text-slate-400 text-xs font-bold uppercase tracking-widest">{label}</span>
    <h4 className={`text-2xl font-black mt-1 ${color}`}>{value}</h4>
    <p className="text-slate-500 text-sm font-medium mt-1">{detail}</p>
  </div>
);

export default Overview;

import React from 'react';
import { ClimateStats, MonthlyClimateData } from '../types';

interface Props {
  data: ClimateStats;
  type: 'sunny' | 'rainy' | 'winter';
}

const SeasonalDetail: React.FC<Props> = ({ data, type }) => {
  const months = data.monthlyData.filter(m => {
    if (type === 'sunny') return m.isSunny;
    if (type === 'rainy') return m.isRainy;
    return m.isWinter;
  });

  if (months.length === 0) {
    return (
      <div className="bg-slate-100 p-12 rounded-3xl text-center">
        <p className="text-slate-400 font-medium">No significant {type} season detected for this coordinates.</p>
      </div>
    );
  }

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
      {months.map(m => (
        <MonthCard key={m.month} data={m} type={type} />
      ))}
    </div>
  );
};

const MonthCard: React.FC<{data: MonthlyClimateData, type: string}> = ({ data, type }) => {
  const getTheme = () => {
    if (type === 'sunny') return { bg: 'bg-orange-50', text: 'text-orange-900', border: 'border-orange-100', icon: '☀️' };
    if (type === 'rainy') return { bg: 'bg-blue-50', text: 'text-blue-900', border: 'border-blue-100', icon: '🌧️' };
    return { bg: 'bg-indigo-50', text: 'text-indigo-900', border: 'border-indigo-100', icon: '❄️' };
  };

  const theme = getTheme();

  return (
    <div className={`${theme.bg} ${theme.border} border p-6 rounded-3xl shadow-sm`}>
      <div className="flex justify-between items-center mb-6">
        <h3 className={`text-2xl font-black ${theme.text}`}>{data.month}</h3>
        <span className="text-3xl">{theme.icon}</span>
      </div>

      <div className="space-y-4">
        <DetailRow label="Avg Temperature" value={`${data.tempAvg}°C`} />
        <DetailRow label="Max / Min Temp" value={`${data.tempMax}° / ${data.tempMin}°C`} />

        {type === 'rainy' && (
          <>
            <DetailRow label="Total Rainfall" value={`${data.rainfall} mm`} />
            <DetailRow label="Rainy Days" value={`${data.rainyDays} days`} />
          </>
        )}

        {type === 'sunny' && (
          <>
            <DetailRow label="Sun Intensity" value={`${data.solarIntensity} MJ/m²`} />
            <DetailRow label="Peak Sun Hours" value={`${data.peakSunHours} hrs`} />
          </>
        )}

        <DetailRow label="Humidity" value={`${data.humidity}%`} />
        <DetailRow label="Wind Speed" value={`${data.windSpeed} km/h`} />
      </div>
    </div>
  );
};

const DetailRow: React.FC<{label: string, value: string}> = ({ label, value }) => (
  <div className="flex justify-between items-center border-b border-black/5 pb-2">
    <span className="text-slate-500 text-sm font-medium">{label}</span>
    <span className="text-slate-800 font-bold">{value}</span>
  </div>
);

export default SeasonalDetail;

import { ClimateStats, MonthlyClimateData, LocationInfo } from '../types';

const MONTH_NAMES = [
  "January", "February", "March", "April", "May", "June",
  "July", "August", "September", "October", "November", "December"
];

export async function geocode(query: string): Promise<LocationInfo[]> {
  try {
    const url = `https://geocoding-api.open-meteo.com/v1/search?name=${encodeURIComponent(query)}&count=5&language=en&format=json`;
    const response = await fetch(url);
    const data = await response.json();
    if (!data.results) return [];
    return data.results.map((r: any) => ({
      name: r.name,
      lat: r.latitude,
      lng: r.longitude,
      country: r.country
    }));
  } catch (err) {
    console.error("Geocoding failed", err);
    return [];
  }
}

export async function fetchClimateData(lat: number, lng: number, locationName?: string): Promise<ClimateStats> {
  // Use a reliable historical range for 1 year to get high-fidelity daily stats, 
  // then extrapolate seasonal behavior. (Real 30-yr daily retrieval is too large for single req)
  const endDate = new Date();
  const startDate = new Date();
  startDate.setFullYear(endDate.getFullYear() - 1);

  const fmt = (d: Date) => d.toISOString().split('T')[0];

  const url = `https://archive-api.open-meteo.com/v1/archive?latitude=${lat}&longitude=${lng}&start_date=${fmt(startDate)}&end_date=${fmt(endDate)}&daily=temperature_2m_max,temperature_2m_min,temperature_2m_mean,precipitation_sum,shortwave_radiation_sum,windspeed_10m_max,relative_humidity_2m_mean&timezone=auto`;

  const response = await fetch(url);
  if (!response.ok) throw new Error("Climate API failure");
  const raw = await response.json();

  if (!raw.daily) throw new Error("No daily data returned");

  const daily = raw.daily;
  const time = daily.time;

  const monthBuckets = Array.from({ length: 12 }, () => ({
    tempMax: [] as number[],
    tempMin: [] as number[],
    tempMean: [] as number[],
    rain: [] as number[],
    solar: [] as number[],
    wind: [] as number[],
    humidity: [] as number[],
    rainyDays: 0,
  }));

  for (let i = 0; i < time.length; i++) {
    const date = new Date(time[i]);
    const m = date.getMonth();
    const bucket = monthBuckets[m];

    if (daily.temperature_2m_max[i] != null) bucket.tempMax.push(daily.temperature_2m_max[i]);
    if (daily.temperature_2m_min[i] != null) bucket.tempMin.push(daily.temperature_2m_min[i]);
    if (daily.temperature_2m_mean[i] != null) bucket.tempMean.push(daily.temperature_2m_mean[i]);
    if (daily.precipitation_sum[i] != null) bucket.rain.push(daily.precipitation_sum[i]);
    if (daily.shortwave_radiation_sum[i] != null) bucket.solar.push(daily.shortwave_radiation_sum[i]);
    if (daily.windspeed_10m_max[i] != null) bucket.wind.push(daily.windspeed_10m_max[i]);
    if (daily.relative_humidity_2m_mean[i] != null) bucket.humidity.push(daily.relative_humidity_2m_mean[i]);

    if (daily.precipitation_sum[i] >= 1.0) bucket.rainyDays++;
  }

  const monthlyData: MonthlyClimateData[] = monthBuckets.map((b, idx) => {
    const avg = (arr: number[]) => arr.length ? arr.reduce((a, c) => a + c, 0) / arr.length : 0;
    const max = (arr: number[]) => arr.length ? Math.max(...arr) : 0;
    const min = (arr: number[]) => arr.length ? Math.min(...arr) : 0;

    const tAvg = avg(b.tempMean);
    const rh = avg(b.humidity);
    const hi = tAvg + 0.5 * (rh - 50);

    return {
      month: MONTH_NAMES[idx],
      monthIdx: idx,
      tempAvg: parseFloat(tAvg.toFixed(1)),
      tempMax: parseFloat(max(b.tempMax).toFixed(1)),
      tempMin: parseFloat(min(b.tempMin).toFixed(1)),
      rainfall: parseFloat(b.rain.reduce((a,c)=>a+c,0).toFixed(1)),
      rainyDays: b.rainyDays,
      humidity: parseFloat(rh.toFixed(1)),
      humidityMax: parseFloat(max(b.humidity).toFixed(1)),
      humidityMin: parseFloat(min(b.humidity).toFixed(1)),
      windSpeed: parseFloat(avg(b.wind).toFixed(1)),
      windMax: parseFloat(max(b.wind).toFixed(1)),
      windDir: 0,
      solarIntensity: parseFloat(avg(b.solar).toFixed(1)),
      peakSunHours: parseFloat((avg(b.solar) / 3.6).toFixed(1)),
      heatIndex: parseFloat(hi.toFixed(1)),
      isSunny: false,
      isRainy: false,
      isWinter: false,
      isWindy: false
    };
  });

  const sortedTemp = [...monthlyData].sort((a, b) => a.tempAvg - b.tempAvg);
  const sortedRain = [...monthlyData].sort((a, b) => a.rainfall - b.rainfall);
  const sortedSolar = [...monthlyData].sort((a, b) => a.solarIntensity - b.solarIntensity);
  const sortedWind = [...monthlyData].sort((a, b) => a.windSpeed - b.windSpeed);

  const coldLimit = sortedTemp[2].tempAvg;
  const rainLimit = sortedRain[9].rainfall;
  const sunLimit = sortedSolar[9].solarIntensity;
  const windLimit = sortedWind[9].windSpeed;

  monthlyData.forEach(m => {
    if (m.tempAvg <= coldLimit) m.isWinter = true;
    if (m.rainfall >= rainLimit) m.isRainy = true;
    if (m.solarIntensity >= sunLimit && !m.isRainy) m.isSunny = true;
    if (m.windSpeed >= windLimit) m.isWindy = true;
  });

  return {
    location: { name: locationName || "Custom Location", lat, lng },
    period: "Last 12 Months High-Fidelity Data",
    monthlyData,
    summary: {
      hottestMonth: sortedTemp[11].month,
      coldestMonth: sortedTemp[0].month,
      rainiestMonth: sortedRain[11].month,
      sunniestMonth: sortedSolar[11].month,
    }
  };
}

