import { ClimateStats, MonthlyClimateData, LocationInfo } from '../types';

const MONTH_NAMES = [
  "January", "February", "March", "April", "May", "June",
  "July", "August", "September", "October", "November", "December"
];

export async function geocode(query: string): Promise<LocationInfo[]> {
  try {
    const url = `https://geocoding-api.open-meteo.com/v1/search?name=${encodeURIComponent(query)}&count=5&language=en&format=json`;
    const response = await fetch(url);
    const data = await response.json();
    if (!data.results) return [];
    return data.results.map((r: any) => ({
      name: r.name,
      lat: r.latitude,
      lng: r.longitude,
      country: r.country
    }));
  } catch (err) {
    console.error("Geocoding failed", err);
    return [];
  }
}

export async function fetchClimateData(lat: number, lng: number, locationName?: string): Promise<ClimateStats> {
  // Use the Climate API which provides 30-year normals (ERA5)
  // Period: 1991-2020 (The current standard climatological normal period)
  const url = `https://climate-api.open-meteo.com/v1/climate?latitude=${lat}&longitude=${lng}&start_date=1991-01-01&end_date=2020-12-31&models=ERA5&daily=temperature_2m_max,temperature_2m_min,temperature_2m_mean,precipitation_sum,shortwave_radiation_sum,windspeed_10m_max,relative_humidity_2m_mean&timezone=auto`;

  const response = await fetch(url);
  if (!response.ok) {
    const errorBody = await response.text();
    console.error("API Error Body:", errorBody);
    throw new Error(`Climate API failure: ${response.status}`);
  }

  const raw = await response.json();
  if (!raw.daily || !raw.daily.time) {
    throw new Error("This location has no available historical climate data in our records.");
  }

  const daily = raw.daily;
  const time = daily.time;

  // Initialize buckets for each month (0-11)
  const monthBuckets = Array.from({ length: 12 }, () => ({
    tempMax: [] as number[],
    tempMin: [] as number[],
    tempMean: [] as number[],
    rain: [] as number[],
    solar: [] as number[],
    wind: [] as number[],
    humidity: [] as number[],
    rainyDaysCount: 0,
    totalDays: 0
  }));

  // Process 30 years of daily data (approx 10,950 points)
  for (let i = 0; i < time.length; i++) {
    const dateStr = time[i];
    // Simple substring is faster than new Date() for 11k iterations
    const m = parseInt(dateStr.substring(5, 7), 10) - 1; 
    const bucket = monthBuckets[m];

    // Some data points can be null for specific regions, push only valid numbers
    if (typeof daily.temperature_2m_max[i] === 'number') bucket.tempMax.push(daily.temperature_2m_max[i]);
    if (typeof daily.temperature_2m_min[i] === 'number') bucket.tempMin.push(daily.temperature_2m_min[i]);
    if (typeof daily.temperature_2m_mean[i] === 'number') bucket.tempMean.push(daily.temperature_2m_mean[i]);
    if (typeof daily.precipitation_sum[i] === 'number') {
      const p = daily.precipitation_sum[i];
      bucket.rain.push(p);
      if (p >= 1.0) bucket.rainyDaysCount++;
    }
    if (typeof daily.shortwave_radiation_sum[i] === 'number') bucket.solar.push(daily.shortwave_radiation_sum[i]);
    if (typeof daily.windspeed_10m_max[i] === 'number') bucket.wind.push(daily.windspeed_10m_max[i]);
    if (typeof daily.relative_humidity_2m_mean[i] === 'number') bucket.humidity.push(daily.relative_humidity_2m_mean[i]);

    bucket.totalDays++;
  }

  const yearsProcessed = 30;

  const monthlyData: MonthlyClimateData[] = monthBuckets.map((b, idx) => {
    const safeAvg = (arr: number[]) => arr.length ? arr.reduce((a, c) => a + c, 0) / arr.length : 0;
    const safeMax = (arr: number[]) => arr.length ? Math.max(...arr) : 0;
    const safeMin = (arr: number[]) => arr.length ? Math.min(...arr) : 0;

    const tAvg = safeAvg(b.tempMean);
    const rh = safeAvg(b.humidity);
    // Simple Heat Index approximation: T + 0.5 * (RH - 50)
    const hi = tAvg + (rh > 60 ? 0.5 * (rh - 60) : 0);

    return {
      month: MONTH_NAMES[idx],
      monthIdx: idx,
      tempAvg: parseFloat(tAvg.toFixed(1)),
      tempMax: parseFloat(safeMax(b.tempMax).toFixed(1)),
      tempMin: parseFloat(safeMin(b.tempMin).toFixed(1)),
      // Average monthly rainfall (Total for month across all years divided by 30)
      rainfall: parseFloat((b.rain.reduce((a,c) => a+c, 0) / yearsProcessed).toFixed(1)),
      // Average number of rainy days per month
      rainyDays: Math.round(b.rainyDaysCount / yearsProcessed),
      humidity: parseFloat(rh.toFixed(1)),
      humidityMax: parseFloat(safeMax(b.humidity).toFixed(1)),
      humidityMin: parseFloat(safeMin(b.humidity).toFixed(1)),
      windSpeed: parseFloat(safeAvg(b.wind).toFixed(1)),
      windMax: parseFloat(safeMax(b.wind).toFixed(1)),
      windDir: 0, 
      solarIntensity: parseFloat(safeAvg(b.solar).toFixed(1)),
      peakSunHours: parseFloat((safeAvg(b.solar) / 3.6).toFixed(1)),
      heatIndex: parseFloat(hi.toFixed(1)),
      isSunny: false,
      isRainy: false,
      isWinter: false,
      isWindy: false
    };
  });

  // Dynamic Classification thresholds based on the specific location's range
  const sortedTemp = [...monthlyData].sort((a, b) => a.tempAvg - b.tempAvg);
  const sortedRain = [...monthlyData].sort((a, b) => a.rainfall - b.rainfall);
  const sortedSolar = [...monthlyData].sort((a, b) => a.solarIntensity - b.solarIntensity);
  const sortedWind = [...monthlyData].sort((a, b) => a.windSpeed - b.windSpeed);

  // We tag the top 3-4 months for each category as "seasons"
  const coldMonths = sortedTemp.slice(0, 3).map(m => m.month);
  const wetMonths = sortedRain.slice(9, 12).map(m => m.month);
  const brightMonths = sortedSolar.slice(9, 12).map(m => m.month);
  const breezyMonths = sortedWind.slice(9, 12).map(m => m.month);

  monthlyData.forEach(m => {
    if (coldMonths.includes(m.month)) m.isWinter = true;
    if (wetMonths.includes(m.month) && m.rainfall > 20) m.isRainy = true;
    if (brightMonths.includes(m.month) && !m.isRainy) m.isSunny = true;
    if (breezyMonths.includes(m.month)) m.isWindy = true;
  });

  return {
    location: { name: locationName || "Custom Location", lat, lng },
    period: "1991 - 2020 (30-year Normals)",
    monthlyData,
    summary: {
      hottestMonth: sortedTemp[11].month,
      coldestMonth: sortedTemp[0].month,
      rainiestMonth: sortedRain[11].month,
      sunniestMonth: sortedSolar[11].month,
    }
  };
}

