const MONTH_NAMES = [
  "January", "February", "March", "April", "May", "June",
  "July", "August", "September", "October", "November", "December"
];

export async function geocode(query: string): Promise<LocationInfo[]> {
  try {
    const url = `https://geocoding-api.open-meteo.com/v1/search?name=${encodeURIComponent(query)}&count=5&language=en&format=json`;
    const response = await fetch(url);
    const data = await response.json();
    if (!data.results) return [];
    return data.results.map((r: any) => ({
      name: r.name,
      lat: r.latitude,
      lng: r.longitude,
      country: r.country
    }));
  } catch (err) {
    console.error("Geocoding failed", err);
    return [];
  }
}

export async function fetchClimateData(lat: number, lng: number, locationName?: string): Promise<ClimateStats> {
  // ERA5 30-year Normals (1991-2020)
  // We use auto-timezone to ensure accurate date-to-month mapping
  const url = `https://climate-api.open-meteo.com/v1/climate?latitude=${lat}&longitude=${lng}&start_date=1991-01-01&end_date=2020-12-31&models=ERA5&daily=temperature_2m_max,temperature_2m_min,temperature_2m_mean,precipitation_sum,shortwave_radiation_sum,windspeed_10m_max,relative_humidity_2m_mean&timezone=auto`;

  let response;
  try {
    response = await fetch(url);
  } catch (e) {
    throw new Error("Network error: Could not reach climate data server.");
  }

  if (!response.ok) {
    if (response.status === 400) {
      throw new Error("Climate data for these specific coordinates is currently unavailable in the global 30km grid.");
    }
    throw new Error(`Climate Data Provider Error (${response.status})`);
  }

  const raw = await response.json();
  if (!raw.daily || !raw.daily.time || raw.daily.time.length === 0) {
    throw new Error("No historical data found for this location.");
  }

  const daily = raw.daily;
  const time = daily.time;

  const monthBuckets = Array.from({ length: 12 }, () => ({
    tempMax: [] as number[],
    tempMin: [] as number[],
    tempMean: [] as number[],
    rain: [] as number[],
    solar: [] as number[],
    wind: [] as number[],
    humidity: [] as number[],
    rainyDaysCount: 0
  }));

  // Highly optimized loop for 11k+ data points
  for (let i = 0, len = time.length; i < len; i++) {
    const month = parseInt(time[i].substring(5, 7), 10) - 1; 
    const bucket = monthBuckets[month];

    const tMax = daily.temperature_2m_max[i];
    const tMin = daily.temperature_2m_min[i];
    const tMean = daily.temperature_2m_mean[i];
    const precip = daily.precipitation_sum[i];
    const solar = daily.shortwave_radiation_sum[i];
    const wind = daily.windspeed_10m_max[i];
    const hum = daily.relative_humidity_2m_mean[i];

    if (tMax != null) bucket.tempMax.push(tMax);
    if (tMin != null) bucket.tempMin.push(tMin);
    if (tMean != null) bucket.tempMean.push(tMean);
    if (precip != null) {
      bucket.rain.push(precip);
      if (precip >= 1.0) bucket.rainyDaysCount++;
    }
    if (solar != null) bucket.solar.push(solar);
    if (wind != null) bucket.wind.push(wind);
    if (hum != null) bucket.humidity.push(hum);
  }

  const yearsProcessed = 30;

  const monthlyData: MonthlyClimateData[] = monthBuckets.map((b, idx) => {
    const avg = (arr: number[]) => arr.length ? arr.reduce((acc, val) => acc + val, 0) / arr.length : 0;
    const max = (arr: number[]) => arr.length ? Math.max(...arr) : 0;
    const min = (arr: number[]) => arr.length ? Math.min(...arr) : 0;

    const tAvg = avg(b.tempMean);
    const rh = avg(b.humidity);

    return {
      month: MONTH_NAMES[idx],
      monthIdx: idx,
      tempAvg: parseFloat(tAvg.toFixed(1)),
      tempMax: parseFloat(max(b.tempMax).toFixed(1)),
      tempMin: parseFloat(min(b.tempMin).toFixed(1)),
      rainfall: parseFloat((b.rain.reduce((acc, val) => acc + val, 0) / yearsProcessed).toFixed(1)),
      rainyDays: Math.round(b.rainyDaysCount / yearsProcessed),
      humidity: parseFloat(rh.toFixed(1)),
      humidityMax: parseFloat(max(b.humidity).toFixed(1)),
      humidityMin: parseFloat(min(b.humidity).toFixed(1)),
      windSpeed: parseFloat(avg(b.wind).toFixed(1)),
      windMax: parseFloat(max(b.wind).toFixed(1)),
      windDir: 0, 
      solarIntensity: parseFloat(avg(b.solar).toFixed(1)),
      peakSunHours: parseFloat((avg(b.solar) / 3.6).toFixed(1)),
      heatIndex: parseFloat((tAvg + (rh > 60 ? 0.5 * (rh - 60) : 0)).toFixed(1)),
      isSunny: false,
      isRainy: false,
      isWinter: false,
      isWindy: false
    };
  });

  const sortedTemp = [...monthlyData].sort((a, b) => a.tempAvg - b.tempAvg);
  const sortedRain = [...monthlyData].sort((a, b) => a.rainfall - b.rainfall);
  const sortedSolar = [...monthlyData].sort((a, b) => a.solarIntensity - b.solarIntensity);
  const sortedWind = [...monthlyData].sort((a, b) => a.windSpeed - b.windSpeed);

  const coldMonths = sortedTemp.slice(0, 3).map(m => m.month);
  const wetMonths = sortedRain.slice(9, 12).map(m => m.month);
  const brightMonths = sortedSolar.slice(9, 12).map(m => m.month);
  const breezyMonths = sortedWind.slice(9, 12).map(m => m.month);

  monthlyData.forEach(m => {
    if (coldMonths.includes(m.month)) m.isWinter = true;
    if (wetMonths.includes(m.month) && m.rainfall > 15) m.isRainy = true;
    if (brightMonths.includes(m.month) && !m.isRainy) m.isSunny = true;
    if (breezyMonths.includes(m.month)) m.isWindy = true;
  });

  return {
    location: { name: locationName || "Custom Location", lat, lng },
    period: "1991 - 2020 (WMO Standard Normals)",
    monthlyData,
    summary: {
      hottestMonth: sortedTemp[11].month,
      coldestMonth: sortedTemp[0].month,
      rainiestMonth: sortedRain[11].month,
      sunniestMonth: sortedSolar[11].month,
    }
  };
}

import { ClimateStats, MonthlyClimateData, LocationInfo } from '../types';

const MONTH_NAMES = [
  "January", "February", "March", "April", "May", "June",
  "July", "August", "September", "October", "November", "December"
];

export function degToCardinal(deg: number): string {
  const directions = ['N', 'NE', 'E', 'SE', 'S', 'SW', 'W', 'NW'];
  const index = Math.round(deg / 45) % 8;
  return directions[index];
}

export async function geocode(query: string): Promise<LocationInfo[]> {
  try {
    const url = `https://geocoding-api.open-meteo.com/v1/search?name=${encodeURIComponent(query)}&count=5&language=en&format=json`;
    const response = await fetch(url);
    const data = await response.json();
    if (!data.results) return [];
    return data.results.map((r: any) => ({
      name: r.name,
      lat: r.latitude,
      lng: r.longitude,
      country: r.country
    }));
  } catch (err) {
