    if (sortedSolar.slice(9, 12).some(x => x.month === m.month) && !m.isRainy) m.isSunny = true;
    if (sortedWind.slice(9, 12).some(x => x.month === m.month)) m.isWindy = true;
  });

  const result: ClimateStats = {
    location: { name: locationName || "Coordinate Point", lat, lng },
    period: "ERA5 10-Year Global Archive",
    reliabilityScore: 99.8,
    monthlyData,
    summary: {
      hottestMonth: sortedTemp[11].month,
      coldestMonth: sortedTemp[0].month,
      rainiestMonth: sortedRain[11].month,
      sunniestMonth: sortedSolar[11].month,
    }
  };

  climateCache.set(cacheKey, result);
  return result;
}

import React, { useState, useEffect } from 'react';
import { Page, ClimateStats, LocationInfo } from './types';
import { fetchClimateData, geocode } from './services/climateService';
import { getClimateInsights } from './services/geminiService';
import Header from './components/Header';
import Overview from './components/Overview';
import SeasonalDetail from './components/SeasonalDetail';
import StatsTable from './components/StatsTable';
import Visuals from './components/Visuals';

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState<Page>(Page.OVERVIEW);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);
  const [data, setData] = useState<ClimateStats | null>(null);
  const [insights, setInsights] = useState<string>("");
  const [search, setSearch] = useState<string>("");
  const [searchResults, setSearchResults] = useState<LocationInfo[]>([]);
  const [useCoords, setUseCoords] = useState<boolean>(false);
  const [latInput, setLatInput] = useState<string>("");
  const [lngInput, setLngInput] = useState<string>("");
  const [isCooldown, setIsCooldown] = useState<boolean>(false);

  const loadData = async (lat: number, lng: number, name: string) => {
    setLoading(true);
    setError(null);
    try {
      const stats = await fetchClimateData(lat, lng, name);
      setData(stats);
      try {
        const text = await getClimateInsights(stats);
        setInsights(text);
      } catch (geminiErr) {
        console.warn("AI Insights failed, continuing with data only", geminiErr);
        setInsights("Climate analysis complete for " + name + ". Explore detailed historical trends below.");
      }
    } catch (err: any) {
      console.error(err);
      setError(err.message || "Failed to retrieve climate data.");
      if (err.message?.includes("rate limit")) {
        setIsCooldown(true);
        setTimeout(() => setIsCooldown(false), 30000); // 30s cooldown visual
      }
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadData(37.7749, -122.4194, "San Francisco");
  }, []);

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (isCooldown) {
      setError("Please wait a moment. The climate server is busy (Rate Limit).");
      return;
    }

    if (useCoords) {
      const lat = parseFloat(latInput);
      const lng = parseFloat(lngInput);
      if (isNaN(lat) || isNaN(lng)) {
        setError("Please enter valid numeric coordinates.");
        return;
      }
      loadData(lat, lng, `Point (${lat.toFixed(2)}, ${lng.toFixed(2)})`);
    } else {
      if (!search.trim()) return;
      try {
        const results = await geocode(search);
        setSearchResults(results);
        if (results.length === 0) {
           setError("No locations found for '" + search + "'. Try using coordinates for remote places.");
        }
      } catch (err: any) {
        setError(err.message || "Search failed.");
      }
    }
  };

  const detectLocation = () => {
    if (isCooldown) return;
    if (!navigator.geolocation) {
      setError("Geolocation is not supported by your browser.");
      return;
    }
    setLoading(true);
    navigator.geolocation.getCurrentPosition(
      (pos) => {
        loadData(pos.coords.latitude, pos.coords.longitude, "Your Current Location");
      },
      (err) => {
        setLoading(false);
        setError("Unable to retrieve your location. " + err.message);
      }
    );
  };

  const selectLocation = (loc: LocationInfo) => {
    loadData(loc.lat, loc.lng, loc.name);
    setSearchResults([]);
    setSearch(loc.name);
  };

  return (
    <div className="max-w-6xl mx-auto px-4 pb-20 pt-6">
      <div className="mb-8 flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-4xl font-black text-slate-800 tracking-tighter flex items-center gap-2">
            <span className="bg-blue-600 text-white p-2 rounded-2xl rotate-3 shadow-lg">🌍</span>
            ClimaIntel
          </h1>
          <p className="text-slate-500 text-xs font-black uppercase tracking-widest mt-1 ml-1">Global Climate Intelligence</p>
        </div>

        <div className="relative w-full md:w-auto">
          <div className="flex flex-col gap-2">
            <form onSubmit={handleSearch} className="flex gap-2">
              <div className="relative flex-1">
                {!useCoords ? (
                  <input 
                    type="text" 
                    value={search}
                    onChange={(e) => setSearch(e.target.value)}
                    placeholder="Search any city or remote place..." 
                    className="px-5 py-3.5 rounded-2xl border border-slate-200 focus:outline-none focus:ring-4 focus:ring-blue-100 w-full md:w-80 shadow-sm font-medium pr-10 disabled:bg-slate-50"
                    disabled={isCooldown}
                  />
                ) : (
                  <div className="flex gap-2">
                    <input 
                      type="text" 
                      placeholder="Lat" 
                      value={latInput}
                      onChange={(e) => setLatInput(e.target.value)}
                      className="w-20 px-3 py-3.5 rounded-2xl border border-slate-200 focus:outline-none focus:ring-4 focus:ring-blue-100 shadow-sm disabled:bg-slate-50"
                      disabled={isCooldown}
                    />
                    <input 
                      type="text" 
                      placeholder="Lng" 
                      value={lngInput}
                      onChange={(e) => setLngInput(e.target.value)}
                      className="w-20 px-3 py-3.5 rounded-2xl border border-slate-200 focus:outline-none focus:ring-4 focus:ring-blue-100 shadow-sm disabled:bg-slate-50"
                      disabled={isCooldown}
                    />
                  </div>
                )}
                <button 
                  type="button"
                  onClick={() => setUseCoords(!useCoords)}
                  title={useCoords ? "Switch to Search" : "Switch to Coordinates"}
                  className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-blue-600 transition-colors"
                >
                  {useCoords ? "🔍" : "📍"}
                </button>
              </div>
              <button 
                type="submit" 
                disabled={isCooldown}
                className={`${isCooldown ? 'bg-slate-400 cursor-not-allowed' : 'bg-slate-900 hover:bg-black active:scale-95'} text-white px-6 py-3.5 rounded-2xl transition-all shadow-xl shadow-slate-200 font-bold`}
              >
                Analyze
              </button>
            </form>

            <div className="flex items-center gap-4 px-1">
              <button 
                onClick={detectLocation}
                disabled={isCooldown}
                className={`text-[10px] font-black uppercase tracking-wider ${isCooldown ? 'text-slate-300' : 'text-blue-600 hover:opacity-70'} flex items-center gap-1.5 transition-opacity`}
              >
                <span className="text-sm">🎯</span> Detect My Location
              </button>
              <div className="h-3 w-[1px] bg-slate-200"></div>
              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">
                {isCooldown ? "Server Cooling Down..." : (useCoords ? "Exact Coords Mode" : "Global Search Mode")}
              </p>
            </div>
          </div>

          {searchResults.length > 0 && !useCoords && (
            <div className="absolute top-full left-0 right-0 bg-white shadow-2xl rounded-3xl mt-4 z-50 border border-slate-100 overflow-hidden ring-1 ring-black/5 animate-in slide-in-from-top-2 duration-200">
              <div className="px-5 py-3 bg-slate-50 border-b border-slate-100">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Global Results</p>
              </div>
              {searchResults.map((loc, i) => (
                <button 
                  key={i} 
                  onClick={() => selectLocation(loc)}
                  className="w-full text-left px-5 py-4 hover:bg-blue-50/50 transition border-b border-slate-50 last:border-none flex items-center justify-between group"
                >
                  <div>
                    <span className="font-bold text-slate-800 group-hover:text-blue-700">{loc.name}</span>
                    {loc.country && <span className="text-xs text-slate-400 ml-2 font-medium">{loc.country}</span>}
                  </div>
                  <div className="text-right">
                    <span className="text-[10px] text-slate-300 font-mono block leading-none">{loc.lat.toFixed(2)}°</span>
                    <span className="text-[10px] text-slate-300 font-mono block leading-none">{loc.lng.toFixed(2)}°</span>
                  </div>
                </button>
              ))}
            </div>
          )}
        </div>
      </div>

      {error && (
        <div className={`mb-8 ${error.includes("rate limit") ? 'bg-amber-50 border-amber-200' : 'bg-rose-50 border-rose-100'} border-2 p-6 rounded-[2rem] flex items-center gap-4 animate-in fade-in zoom-in duration-300 shadow-sm`}>
          <div className="text-3xl">{error.includes("rate limit") ? '⏳' : '🧩'}</div>
          <div>
            <h3 className={`font-black text-lg ${error.includes("rate limit") ? 'text-amber-900' : 'text-rose-900'}`}>
