  const [error, setError] = useState<string | null>(null);
  const [data, setData] = useState<ClimateStats | null>(null);
  const [insights, setInsights] = useState<string>("");
  const [search, setSearch] = useState<string>("");
  const [searchResults, setSearchResults] = useState<LocationInfo[]>([]);
  const [useCoords, setUseCoords] = useState<boolean>(false);
  const [latInput, setLatInput] = useState<string>("");
  const [lngInput, setLngInput] = useState<string>("");
  const [isCooldown, setIsCooldown] = useState<boolean>(false);
  const [isSearching, setIsSearching] = useState<boolean>(false);

  const searchTimeoutRef = useRef<number | null>(null);

  const loadData = async (lat: number, lng: number, name: string) => {
    setLoading(true);
    setError(null);
    try {
      const stats = await fetchClimateData(lat, lng, name);
      setData(stats);
      try {
        const text = await getClimateInsights(stats);
        setInsights(text);
      } catch (geminiErr) {
        console.warn("AI Insights failed, continuing with data only", geminiErr);
        setInsights("Climate analysis complete for " + name + ". Explore detailed historical trends below.");
      }
    } catch (err: any) {
      console.error(err);
      setError(err.message || "Failed to retrieve climate data.");
      if (err.message?.includes("rate limit")) {
        setIsCooldown(true);
        setTimeout(() => setIsCooldown(false), 30000); // 30s cooldown visual
      }
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadData(37.7749, -122.4194, "San Francisco, California, United States");
  }, []);

  // Debounced search effect for real-time suggestions and fuzzy matching
  useEffect(() => {
    if (useCoords || !search.trim() || search.trim().length < 2) {
      setSearchResults([]);
      return;
    }

    if (searchTimeoutRef.current) {
      window.clearTimeout(searchTimeoutRef.current);
    }

    setIsSearching(true);
    searchTimeoutRef.current = window.setTimeout(async () => {
      try {
        const results = await geocode(search);
        setSearchResults(results);
      } catch (err: any) {
        // Silent fail for debounced search to avoid flickering errors
        console.debug("Search error:", err);
      } finally {
        setIsSearching(false);
      }
    }, 400); // 400ms debounce

    return () => {
      if (searchTimeoutRef.current) window.clearTimeout(searchTimeoutRef.current);
    };
  }, [search, useCoords]);

  const handleSearchSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (isCooldown) {
      setError("Please wait a moment. The climate server is busy (Rate Limit).");
      return;
    }

    if (useCoords) {
      const lat = parseFloat(latInput);
      const lng = parseFloat(lngInput);
      if (isNaN(lat) || isNaN(lng)) {
        setError("Please enter valid numeric coordinates.");
        return;
      }
      loadData(lat, lng, `Point (${lat.toFixed(2)}, ${lng.toFixed(2)})`);
    } else {
      // If we already have results from debounced search, pick the first one
      if (searchResults.length > 0) {
        selectLocation(searchResults[0]);
      } else {
        // Try one final manual search
        try {
          const results = await geocode(search);
          if (results.length > 0) {
            selectLocation(results[0]);
          } else {
            setError("No locations found for '" + search + "'. Check spelling or use coordinates for remote places.");
          }
        } catch (err: any) {
          setError(err.message || "Search failed.");
        }
      }
    }
  };

  const detectLocation = () => {
    if (isCooldown) return;
    if (!navigator.geolocation) {
      setError("Geolocation is not supported by your browser.");
      return;
    }
    setLoading(true);
    navigator.geolocation.getCurrentPosition(
      (pos) => {
        loadData(pos.coords.latitude, pos.coords.longitude, "Your Current Location");
      },
      (err) => {
        setLoading(false);
        setError("Unable to retrieve your location. " + err.message);
      }
    );
  };

  const selectLocation = (loc: LocationInfo) => {
    loadData(loc.lat, loc.lng, loc.name);
    setSearchResults([]);
    setSearch(loc.name);
  };

  return (
    <div className="max-w-6xl mx-auto px-4 pb-20 pt-6">
      <div className="mb-8 flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-4xl font-black text-slate-800 tracking-tighter flex items-center gap-2">
            <span className="bg-blue-600 text-white p-2 rounded-2xl rotate-3 shadow-lg">🌍</span>
            ClimaIntel
          </h1>
          <p className="text-slate-500 text-xs font-black uppercase tracking-widest mt-1 ml-1">Global Climate Intelligence</p>
        </div>

        <div className="relative w-full md:w-auto">
          <div className="flex flex-col gap-2">
            <form onSubmit={handleSearchSubmit} className="flex gap-2">
              <div className="relative flex-1">
                {!useCoords ? (
                  <div className="relative">
                    <input 
                      type="text" 
                      value={search}
                      onChange={(e) => setSearch(e.target.value)}
                      placeholder="Search any city or remote place..." 
                      className="px-5 py-3.5 rounded-2xl border border-slate-200 focus:outline-none focus:ring-4 focus:ring-blue-100 w-full md:w-96 shadow-sm font-medium pr-10 disabled:bg-slate-50"
                      disabled={isCooldown}
                    />
                    {isSearching && (
                      <div className="absolute right-10 top-1/2 -translate-y-1/2">
                        <div className="w-4 h-4 border-2 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
                      </div>
                    )}
                  </div>
                ) : (
                  <div className="flex gap-2">
                    <input 
                      type="text" 
                      placeholder="Lat" 
                      value={latInput}
                      onChange={(e) => setLatInput(e.target.value)}
                      className="w-20 px-3 py-3.5 rounded-2xl border border-slate-200 focus:outline-none focus:ring-4 focus:ring-blue-100 shadow-sm disabled:bg-slate-50 font-mono"
                      disabled={isCooldown}
                    />
                    <input 
                      type="text" 
                      placeholder="Lng" 
                      value={lngInput}
                      onChange={(e) => setLngInput(e.target.value)}
                      className="w-20 px-3 py-3.5 rounded-2xl border border-slate-200 focus:outline-none focus:ring-4 focus:ring-blue-100 shadow-sm disabled:bg-slate-50 font-mono"
                      disabled={isCooldown}
                    />
                  </div>
                )}
                <button 
                  type="button"
                  onClick={() => setUseCoords(!useCoords)}
                  title={useCoords ? "Switch to Search" : "Switch to Coordinates"}
                  className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-blue-600 transition-colors"
                >
                  {useCoords ? "🔍" : "📍"}
                </button>
              </div>
              <button 
                type="submit" 
                disabled={isCooldown}
                className={`${isCooldown ? 'bg-slate-400 cursor-not-allowed' : 'bg-slate-900 hover:bg-black active:scale-95'} text-white px-6 py-3.5 rounded-2xl transition-all shadow-xl shadow-slate-200 font-bold`}
              >
                Analyze
              </button>
            </form>

            <div className="flex items-center gap-4 px-1">
              <button 
                onClick={detectLocation}
                disabled={isCooldown}
                className={`text-[10px] font-black uppercase tracking-wider ${isCooldown ? 'text-slate-300' : 'text-blue-600 hover:opacity-70'} flex items-center gap-1.5 transition-opacity`}
              >
                <span className="text-sm">🎯</span> Detect My Location
              </button>
              <div className="h-3 w-[1px] bg-slate-200"></div>
              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">
                {isCooldown ? "Server Cooling Down..." : (useCoords ? "Exact Coords Mode" : "Fuzzy Search Active")}
              </p>
            </div>
          </div>

          {searchResults.length > 0 && !useCoords && (
            <div className="absolute top-full left-0 right-0 bg-white shadow-2xl rounded-3xl mt-4 z-50 border border-slate-100 overflow-hidden ring-1 ring-black/5 animate-in slide-in-from-top-2 duration-200 max-h-[400px] overflow-y-auto scrollbar-hide">
              <div className="px-5 py-3 bg-slate-50 border-b border-slate-100 sticky top-0 z-10 flex justify-between items-center">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Fuzzy Matches Found</p>
                <span className="text-[10px] font-bold text-blue-500 bg-blue-50 px-2 py-0.5 rounded-full">{searchResults.length} Results</span>
              </div>
              {searchResults.map((loc, i) => (
                <button 
