export default App;

import { ClimateStats, MonthlyClimateData, LocationInfo } from '../types';

const MONTH_NAMES = [
  "January", "February", "March", "April", "May", "June",
  "July", "August", "September", "October", "November", "December"
];

/**
 * Climatic Thresholds for Classification
 * Based on standard meteorological comfort and intensity scales.
 */
const CLIMATE_THRESHOLDS = {
  WINTER_MAX_TEMP: 15,      // Avg temp <= 15°C is considered a "Winter" period
  RAINY_MIN_PRECIP: 60,     // Total monthly rainfall >= 60mm is "Rainy"
  RAINY_MIN_DAYS: 10,       // Alternatively, >= 10 rainy days (>=1mm) is "Rainy"
  SUNNY_MIN_SOLAR: 22,      // Solar intensity >= 22 MJ/m² is "Sunny"
  SUNNY_MAX_PRECIP: 40,     // But only if rainfall is relatively low
  WINDY_MIN_SPEED: 14.5,    // Average wind speed >= 14.5 km/h (~4 m/s) is "Windy"
};

// Simple in-memory cache to prevent redundant API calls during a single session
const climateCache = new Map<string, ClimateStats>();

export function degToCardinal(deg: number): string {
  const directions = ['N', 'NE', 'E', 'SE', 'S', 'SW', 'W', 'NW'];
  const index = Math.round(deg / 45) % 8;
  return directions[index];
}

/**
 * Geocode search with support for fuzzy matching and misspelled queries.
 * Uses Open-Meteo's Elasticsearch-backed geocoding API.
 */
export async function geocode(query: string): Promise<LocationInfo[]> {
  if (!query || query.trim().length < 2) return [];

  try {
    const url = `https://geocoding-api.open-meteo.com/v1/search?name=${encodeURIComponent(query.trim())}&count=10&language=en&format=json`;
    const response = await fetch(url);

    if (response.status === 429) throw new Error("Search limit reached. Please wait a few seconds.");
    if (!response.ok) throw new Error("Search service temporarily unavailable.");

    const data = await response.json();
    if (!data.results) return [];

    return data.results.map((r: any) => {
      const nameParts = [r.name];
      if (r.admin2 && r.admin2 !== r.name) nameParts.push(r.admin2);
      if (r.admin1 && r.admin1 !== r.name && r.admin1 !== r.admin2) nameParts.push(r.admin1);

      return {
        name: nameParts.join(', '),
        lat: r.latitude,
        lng: r.longitude,
        country: r.country,
      };
    });
  } catch (err) {
    console.error("Geocoding failed", err);
    throw err;
  }
}

async function fetchWithRetry(lat: number, lng: number): Promise<any> {
  const end = new Date();
  const start = new Date();
  start.setFullYear(end.getFullYear() - 10);
  const fmt = (d: Date) => d.toISOString().split('T')[0];

  const url = `https://archive-api.open-meteo.com/v1/archive?latitude=${lat}&longitude=${lng}&start_date=${fmt(start)}&end_date=${fmt(end)}&daily=temperature_2m_max,temperature_2m_min,temperature_2m_mean,precipitation_sum,shortwave_radiation_sum,windspeed_10m_max,wind_direction_10m_dominant,relative_humidity_2m_mean&timezone=auto`;

  const response = await fetch(url);

  if (response.status === 429) {
    throw new Error("Climate API rate limit exceeded. Please wait a minute before searching again.");
  }

  if (!response.ok) {
    if (response.status === 400) {
       const jitterUrl = `https://archive-api.open-meteo.com/v1/archive?latitude=${lat + 0.1}&longitude=${lng + 0.1}&start_date=${fmt(start)}&end_date=${fmt(end)}&daily=temperature_2m_max,temperature_2m_min,temperature_2m_mean,precipitation_sum,shortwave_radiation_sum,windspeed_10m_max,wind_direction_10m_dominant,relative_humidity_2m_mean&timezone=auto`;
       const retry = await fetch(jitterUrl);
       if (!retry.ok) {
         if (retry.status === 429) throw new Error("Rate limit exceeded. Please wait.");
         throw new Error("This location is outside the historical climate grid (Deep Ocean or Uncharted).");
       }
       return await retry.json();
    }
    throw new Error(`Climate API error: ${response.status}`);
  }
  return await response.json();
}

export async function fetchClimateData(lat: number, lng: number, locationName?: string): Promise<ClimateStats> {
  const cacheKey = `${lat.toFixed(2)}-${lng.toFixed(2)}`;
  if (climateCache.has(cacheKey)) {
    return climateCache.get(cacheKey)!;
  }

  const raw = await fetchWithRetry(lat, lng);

  if (!raw.daily) throw new Error("No data found for these coordinates.");

  const daily = raw.daily;
  const time = daily.time;

  const monthBuckets = Array.from({ length: 12 }, () => ({
    tempMax: [] as number[],
    tempMin: [] as number[],
    tempMean: [] as number[],
    rain: [] as number[],
    solar: [] as number[],
    wind: [] as number[],
    windDirs: [] as number[],
    humidity: [] as number[],
    rainyDaysCount: 0
  }));

  for (let i = 0; i < time.length; i++) {
    const monthStr = time[i].substring(5, 7);
    const month = parseInt(monthStr, 10) - 1;
    const bucket = monthBuckets[month];

    if (daily.temperature_2m_max[i] != null) bucket.tempMax.push(daily.temperature_2m_max[i]);
    if (daily.temperature_2m_min[i] != null) bucket.tempMin.push(daily.temperature_2m_min[i]);
    if (daily.temperature_2m_mean[i] != null) bucket.tempMean.push(daily.temperature_2m_mean[i]);
    if (daily.precipitation_sum[i] != null) {
      bucket.rain.push(daily.precipitation_sum[i]);
      if (daily.precipitation_sum[i] >= 1.0) bucket.rainyDaysCount++;
    }
    if (daily.shortwave_radiation_sum[i] != null) bucket.solar.push(daily.shortwave_radiation_sum[i]);
    if (daily.windspeed_10m_max[i] != null) bucket.wind.push(daily.windspeed_10m_max[i]);
    if (daily.wind_direction_10m_dominant[i] != null) bucket.windDirs.push(daily.wind_direction_10m_dominant[i]);
    if (daily.relative_humidity_2m_mean[i] != null) bucket.humidity.push(daily.relative_humidity_2m_mean[i]);
  }

  const yearsProcessed = 10;

  const monthlyData: MonthlyClimateData[] = monthBuckets.map((b, idx) => {
    const avg = (arr: number[]) => arr.length ? arr.reduce((a, c) => a + c, 0) / arr.length : 0;
    const max = (arr: number[]) => arr.length ? Math.max(...arr) : 0;
    const min = (arr: number[]) => arr.length ? Math.min(...arr) : 0;

    const cardinalCounts: Record<string, number> = {};
    b.windDirs.forEach(d => {
      const c = degToCardinal(d);
      cardinalCounts[c] = (cardinalCounts[c] || 0) + 1;
    });
    const prevailingCardinal = Object.entries(cardinalCounts).sort((a,b) => b[1] - a[1])[0]?.[0] || 'N';
    const cardinalToDeg: Record<string, number> = { 'N': 0, 'NE': 45, 'E': 90, 'SE': 135, 'S': 180, 'SW': 225, 'W': 270, 'NW': 315 };

    const tAvg = avg(b.tempMean);
    const rh = avg(b.humidity);
    const rain = b.rain.reduce((a,c)=>a+c,0) / yearsProcessed;
    const rainyDays = Math.round(b.rainyDaysCount / yearsProcessed);
    const solar = avg(b.solar);
    const wind = avg(b.wind);

    // Apply Threshold Logic
    const isWinter = tAvg <= CLIMATE_THRESHOLDS.WINTER_MAX_TEMP;
    const isRainy = rain >= CLIMATE_THRESHOLDS.RAINY_MIN_PRECIP || rainyDays >= CLIMATE_THRESHOLDS.RAINY_MIN_DAYS;
    const isSunny = solar >= CLIMATE_THRESHOLDS.SUNNY_MIN_SOLAR && rain < CLIMATE_THRESHOLDS.SUNNY_MAX_PRECIP;
    const isWindy = wind >= CLIMATE_THRESHOLDS.WINDY_MIN_SPEED;

    return {
      month: MONTH_NAMES[idx],
      monthIdx: idx,
      tempAvg: parseFloat(tAvg.toFixed(1)),
      tempMax: parseFloat(max(b.tempMax).toFixed(1)),
      tempMin: parseFloat(min(b.tempMin).toFixed(1)),
      rainfall: parseFloat(rain.toFixed(1)),
      rainyDays: rainyDays,
      humidity: parseFloat(rh.toFixed(1)),
      humidityMax: parseFloat(max(b.humidity).toFixed(1)),
      humidityMin: parseFloat(min(b.humidity).toFixed(1)),
      windSpeed: parseFloat(wind.toFixed(1)),
      windMax: parseFloat(max(b.wind).toFixed(1)),
      windDir: cardinalToDeg[prevailingCardinal], 
      solarIntensity: parseFloat(solar.toFixed(1)),
      peakSunHours: parseFloat((solar / 3.6).toFixed(1)),
      heatIndex: parseFloat((tAvg + (rh > 60 ? 0.5 * (rh - 60) : 0)).toFixed(1)),
      isSunny,
      isRainy,
      isWinter,
      isWindy
    };
  });

  const sortedTemp = [...monthlyData].sort((a, b) => a.tempAvg - b.tempAvg);
  const sortedRain = [...monthlyData].sort((a, b) => a.rainfall - b.rainfall);
  const sortedSolar = [...monthlyData].sort((a, b) => a.solarIntensity - b.solarIntensity);

  const result: ClimateStats = {
    location: { name: locationName || "Coordinate Point", lat, lng },
    period: "ERA5 10-Year Global Archive",
    reliabilityScore: 99.8,
    monthlyData,
    summary: {
      hottestMonth: sortedTemp[11].month,
      coldestMonth: sortedTemp[0].month,
      rainiestMonth: sortedRain[11].month,
      sunniestMonth: sortedSolar[11].month,
    }
  };

  climateCache.set(cacheKey, result);
  return result;
}

