              className={`px-4 py-1.5 rounded-xl text-[11px] font-black uppercase tracking-wider transition-all ${!useCoords ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
            >
              Search Place
            </button>
            <button 
              onClick={() => setUseCoords(true)}
              className={`px-4 py-1.5 rounded-xl text-[11px] font-black uppercase tracking-wider transition-all ${useCoords ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
            >
              Coordinates
            </button>
          </div>

          <div className="relative">
            <form onSubmit={handleSearchSubmit} className="flex gap-2">
              <div className="relative flex-1">
                {!useCoords ? (
                  <div className="relative">
                    <input 
                      type="text" 
                      value={search}
                      onChange={(e) => setSearch(e.target.value)}
                      placeholder="Enter city name..." 
                      className="px-5 py-3.5 rounded-2xl border border-slate-200 focus:outline-none focus:ring-4 focus:ring-blue-100 w-full md:w-80 shadow-sm font-medium disabled:bg-slate-50"
                      disabled={isCooldown}
                    />
                    {isSearching && (
                      <div className="absolute right-4 top-1/2 -translate-y-1/2">
                        <div className="w-4 h-4 border-2 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
                      </div>
                    )}
                  </div>
                ) : (
                  <div className="flex gap-2">
                    <input 
                      type="text" 
                      placeholder="Lat" 
                      value={latInput}
                      onChange={(e) => setLatInput(e.target.value)}
                      className="w-24 px-4 py-3.5 rounded-2xl border border-slate-200 focus:outline-none focus:ring-4 focus:ring-blue-100 shadow-sm font-mono text-sm"
                    />
                    <input 
                      type="text" 
                      placeholder="Lng" 
                      value={lngInput}
                      onChange={(e) => setLngInput(e.target.value)}
                      className="w-24 px-4 py-3.5 rounded-2xl border border-slate-200 focus:outline-none focus:ring-4 focus:ring-blue-100 shadow-sm font-mono text-sm"
                    />
                  </div>
                )}
              </div>
              <button 
                type="submit" 
                disabled={isCooldown}
                className={`${isCooldown ? 'bg-slate-400 cursor-not-allowed' : 'bg-slate-900 hover:bg-black active:scale-95'} text-white px-6 py-3.5 rounded-2xl transition-all shadow-xl font-bold`}
              >
                Analyze
              </button>
            </form>

            {searchResults.length > 0 && !useCoords && (
              <div className="absolute top-full left-0 right-0 bg-white shadow-2xl rounded-3xl mt-2 z-50 border border-slate-100 overflow-hidden max-h-[300px] overflow-y-auto scrollbar-hide">
                {searchResults.map((loc, i) => (
                  <button 
                    key={i} 
                    onClick={() => selectLocation(loc)}
                    className="w-full text-left px-5 py-4 hover:bg-blue-50/50 transition border-b border-slate-50 last:border-none"
                  >
                    <span className="font-bold text-slate-800 block text-sm">{loc.name}</span>
                    <span className="text-[10px] text-slate-400 font-mono">{loc.lat.toFixed(3)}°N, {loc.lng.toFixed(3)}°E</span>
                  </button>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>

      {error && (
        <div className="mb-8 bg-rose-50 border-rose-100 border-2 p-6 rounded-[2rem] flex items-center gap-4 animate-in fade-in">
          <div className="text-3xl">🧩</div>
          <div>
            <h3 className="font-black text-rose-900">Search Insight</h3>
            <p className="text-rose-700 text-sm font-medium">{error}</p>
          </div>
          <button onClick={() => setError(null)} className="ml-auto text-rose-300 hover:text-rose-600">✕</button>
        </div>
      )}

      {loading && !data ? (
        <div className="flex flex-col items-center justify-center py-40">
           <div className="animate-spin rounded-full h-16 w-16 border-t-4 border-blue-600 mb-6"></div>
           <p className="text-slate-800 font-black text-2xl tracking-tight">Syncing Climate Records...</p>
        </div>
      ) : data && (
        <>
          <Header data={data} insights={insights} />

          <nav className="flex overflow-x-auto gap-2 mb-10 bg-white/60 p-2 rounded-[2.5rem] shadow-sm border border-slate-200/50 scrollbar-hide sticky top-4 z-40 backdrop-blur-xl">
            {[
              { id: Page.OVERVIEW, label: "Overview", icon: "🌎" },
              { id: Page.SUNNY, label: "Sunny", icon: "☀️" },
              { id: Page.RAINY, label: "Rainy", icon: "🌧️" },
              { id: Page.WINTER, label: "Winter", icon: "❄️" },
              { id: Page.STATS, label: "Data", icon: "📊" },
              { id: Page.GRAPHS, label: "Graphs", icon: "📈" },
            ].map(tab => (
              <button
                key={tab.id}
                onClick={() => setCurrentPage(tab.id as Page)}
                className={`flex items-center gap-2 px-6 py-4 rounded-[1.8rem] whitespace-nowrap transition-all ${
                  currentPage === tab.id 
                    ? 'bg-slate-900 text-white shadow-2xl -translate-y-1' 
                    : 'text-slate-600 hover:bg-white font-bold text-sm'
                }`}
              >
                <span className="text-xl">{tab.icon}</span>
                <span className="font-black tracking-tight">{tab.label}</span>
              </button>
            ))}
          </nav>

          <main className="fade-in">
            {currentPage === Page.OVERVIEW && <Overview data={data} />}
            {currentPage === Page.SUNNY && <SeasonalDetail data={data} type="sunny" />}
            {currentPage === Page.RAINY && <SeasonalDetail data={data} type="rainy" />}
            {currentPage === Page.WINTER && <SeasonalDetail data={data} type="winter" />}
            {currentPage === Page.STATS && <StatsTable data={data} />}
            {currentPage === Page.GRAPHS && <Visuals data={data} />}
          </main>
        </>
      )}
    </div>
  );
};

export default App;

