    const monthsInDir = data.monthlyData.filter(m => degToCardinal(m.windDir) === dir);
    return {
      direction: dir,
      frequency: monthsInDir.length,
      avgSpeed: monthsInDir.length > 0 
        ? monthsInDir.reduce((acc, curr) => acc + curr.windSpeed, 0) / monthsInDir.length 
        : 0
    };
