              <Bar dataKey="temp" radius={[12, 12, 0, 0]} barSize={50}>
                {seasonalData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={entry.color} />
                ))}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </ChartCard>

