          </ResponsiveContainer>
        </ChartCard>

        {/* 6. Wind Speed */}
        <ChartCard title="Wind Speed (km/h)" description="Sustained average monthly wind intensities.">
          <ResponsiveContainer width="100%" height={300}>
            <LineChart data={data.monthlyData}>
              <XAxis dataKey="month" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 600}} />
              <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 600}} unit="km/h" />
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
              <Tooltip contentStyle={{ borderRadius: '20px', border: 'none' }} />
              <Line name="Wind Speed" type="basis" dataKey="windSpeed" stroke="#10b981" strokeWidth={4} dot={{ r: 4, fill: '#10b981' }} />
