            </AreaChart>
          </ResponsiveContainer>
        </ChartCard>

        {/* 8. Wind Rose */}
        <ChartCard title="Dominant Wind Directions" description="Distribution of prevailing monthly wind directions.">
          <ResponsiveContainer width="100%" height={300}>
