              <Line name="Wind Speed" type="basis" dataKey="windSpeed" stroke="#10b981" strokeWidth={4} dot={{ r: 4, fill: '#10b981' }} />
            </LineChart>
          </ResponsiveContainer>
        </ChartCard>

        {/* 8. Solar Intensity */}
        <ChartCard title="Solar Energy (MJ/m²)" description="Total shortwave radiation reaching the surface.">
          <ResponsiveContainer width="100%" height={300}>
            <AreaChart data={data.monthlyData}>
              <XAxis dataKey="month" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 600}} />
              <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 600}} />
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
              <Tooltip contentStyle={{ borderRadius: '20px', border: 'none' }} />
              <Area name="Solar Energy" type="monotone" dataKey="solarIntensity" stroke="#d97706" fill="#f59e0b" fillOpacity={0.1} strokeWidth={3} />
            </AreaChart>
          </ResponsiveContainer>
        </ChartCard>

        {/* 9. Wind Rose */}
        <ChartCard title="Dominant Wind Directions" description="Distribution of prevailing monthly wind directions.">
          <ResponsiveContainer width="100%" height={300}>
            <RadarChart cx="50%" cy="50%" outerRadius="80%" data={windRoseData}>
              <PolarGrid stroke="#e2e8f0" />
              <PolarAngleAxis dataKey="direction" tick={{ fill: '#64748b', fontSize: 12, fontWeight: 'bold' }} />
              <Radar name="Frequency" dataKey="frequency" stroke="#6366f1" fill="#6366f1" fillOpacity={0.6} />
              <Tooltip contentStyle={{ borderRadius: '16px', border: 'none' }} />
            </RadarChart>
          </ResponsiveContainer>
        </ChartCard>
      </div>
    </div>
  );
};

