import { ClimateStats, MonthlyClimateData, LocationInfo } from '../types';

const MONTH_NAMES = [
  "January", "February", "March", "April", "May", "June",
  "July", "August", "September", "October", "November", "December"
];

/**
 * Climatic Thresholds for Classification
 * Based on standard meteorological comfort and intensity scales.
 */
const CLIMATE_THRESHOLDS = {
  WINTER_MAX_TEMP: 15,      // Avg temp <= 15°C is considered a "Winter" period
  RAINY_MIN_PRECIP: 60,     // Total monthly rainfall >= 60mm is "Rainy"
  RAINY_MIN_DAYS: 10,       // Alternatively, >= 10 rainy days (>=1mm) is "Rainy"
  SUNNY_MIN_SOLAR: 22,      // Solar intensity >= 22 MJ/m² is "Sunny"
  SUNNY_MAX_PRECIP: 40,     // But only if rainfall is relatively low
  WINDY_MIN_SPEED: 14.5,    // Average wind speed >= 14.5 km/h (~4 m/s) is "Windy"
};

// Simple in-memory cache to prevent redundant API calls during a single session
const climateCache = new Map<string, ClimateStats>();

export function degToCardinal(deg: number): string {
  const directions = ['N', 'NE', 'E', 'SE', 'S', 'SW', 'W', 'NW'];
  const index = Math.round(deg / 45) % 8;
  return directions[index];
}

/**
 * Geocode search with support for fuzzy matching and misspelled queries.
 * Uses Open-Meteo's Elasticsearch-backed geocoding API.
 */
export async function geocode(query: string): Promise<LocationInfo[]> {
  if (!query || query.trim().length < 2) return [];

  try {
    const url = `https://geocoding-api.open-meteo.com/v1/search?name=${encodeURIComponent(query.trim())}&count=10&language=en&format=json`;
    const response = await fetch(url);

    if (response.status === 429) throw new Error("Search limit reached. Please wait a few seconds.");
    if (!response.ok) throw new Error("Search service temporarily unavailable.");

    const data = await response.json();
    if (!data.results) return [];

    return data.results.map((r: any) => {
      const nameParts = [r.name];
      if (r.admin2 && r.admin2 !== r.name) nameParts.push(r.admin2);
      if (r.admin1 && r.admin1 !== r.name && r.admin1 !== r.admin2) nameParts.push(r.admin1);
      if (r.country && r.country !== r.name) nameParts.push(r.country);

      return {
        name: nameParts.join(', '),
        lat: r.latitude,
        lng: r.longitude,
        country: r.country,
      };
    });
  } catch (err) {
    console.error("Geocoding failed", err);
    throw err;
  }
}

/**
 * Reverse geocode coordinates to get a human-readable location name.
 */
export async function reverseGeocode(lat: number, lng: number): Promise<string> {
  try {
    // We use the search API with the closest match for coordinates if specific reverse geocoding is unavailable
    // However, Open-Meteo geocoding doesn't have a direct reverse endpoint, 
    // we'll fallback to a generic name if we can't find a precise match, 
    // or use a public reverse geocoding service like Nominatim (OSM).
    const url = `https://nominatim.openstreetmap.org/reverse?lat=${lat}&lon=${lng}&format=json&zoom=10`;
    const response = await fetch(url, {
      headers: { 'Accept-Language': 'en' }
    });
    if (!response.ok) return `${lat.toFixed(2)}, ${lng.toFixed(2)}`;
    const data = await response.json();
    return data.display_name || `${lat.toFixed(2)}, ${lng.toFixed(2)}`;
  } catch (err) {
    return `${lat.toFixed(2)}, ${lng.toFixed(2)}`;
  }
}

async function fetchWithRetry(lat: number, lng: number): Promise<any> {
  const end = new Date();
  const start = new Date();
  start.setFullYear(end.getFullYear() - 10);
  const fmt = (d: Date) => d.toISOString().split('T')[0];

  const params = [
    'temperature_2m_max',
    'temperature_2m_min',
    'temperature_2m_mean',
    'precipitation_sum',
    'shortwave_radiation_sum',
    'windspeed_10m_max',
    'wind_direction_10m_dominant',
    'relative_humidity_2m_mean',
    'uv_index_max'
  ].join(',');

  const url = `https://archive-api.open-meteo.com/v1/archive?latitude=${lat}&longitude=${lng}&start_date=${fmt(start)}&end_date=${fmt(end)}&daily=${params}&timezone=auto`;

  const response = await fetch(url);

  if (response.status === 429) {
    throw new Error("Climate API rate limit exceeded. Please wait a minute before searching again.");
  }

  if (!response.ok) {
    if (response.status === 400) {
       const jitterUrl = `https://archive-api.open-meteo.com/v1/archive?latitude=${lat + 0.1}&longitude=${lng + 0.1}&start_date=${fmt(start)}&end_date=${fmt(end)}&daily=${params}&timezone=auto`;
       const retry = await fetch(jitterUrl);
       if (!retry.ok) {
         if (retry.status === 429) throw new Error("Rate limit exceeded. Please wait.");
         throw new Error("This location is outside the historical climate grid (Deep Ocean or Uncharted).");
       }
       return await retry.json();
    }
    throw new Error(`Climate API error: ${response.status}`);
  }
  return await response.json();
}

export async function fetchClimateData(lat: number, lng: number, locationName?: string): Promise<ClimateStats> {
  const cacheKey = `${lat.toFixed(2)}-${lng.toFixed(2)}`;
  if (climateCache.has(cacheKey)) {
    return climateCache.get(cacheKey)!;
  }

  const raw = await fetchWithRetry(lat, lng);

  if (!raw.daily) throw new Error("No data found for these coordinates.");

  const daily = raw.daily;
  const time = daily.time;

  const monthBuckets = Array.from({ length: 12 }, () => ({
    tempMax: [] as number[],
    tempMin: [] as number[],
    tempMean: [] as number[],
    rain: [] as number[],
    solar: [] as number[],
    uv: [] as number[],
    wind: [] as number[],
    windDirs: [] as number[],
    humidity: [] as number[],
    rainyDaysCount: 0
  }));

  for (let i = 0; i < time.length; i++) {
    const monthStr = time[i].substring(5, 7);
    const month = parseInt(monthStr, 10) - 1;
    const bucket = monthBuckets[month];

    if (daily.temperature_2m_max[i] != null) bucket.tempMax.push(daily.temperature_2m_max[i]);
    if (daily.temperature_2m_min[i] != null) bucket.tempMin.push(daily.temperature_2m_min[i]);
    if (daily.temperature_2m_mean[i] != null) bucket.tempMean.push(daily.temperature_2m_mean[i]);
    if (daily.precipitation_sum[i] != null) {
      bucket.rain.push(daily.precipitation_sum[i]);
      if (daily.precipitation_sum[i] >= 1.0) bucket.rainyDaysCount++;
    }
    if (daily.shortwave_radiation_sum[i] != null) bucket.solar.push(daily.shortwave_radiation_sum[i]);
    if (daily.uv_index_max && daily.uv_index_max[i] != null) bucket.uv.push(daily.uv_index_max[i]);
    if (daily.windspeed_10m_max[i] != null) bucket.wind.push(daily.windspeed_10m_max[i]);
    if (daily.wind_direction_10m_dominant[i] != null) bucket.windDirs.push(daily.wind_direction_10m_dominant[i]);
    if (daily.relative_humidity_2m_mean[i] != null) bucket.humidity.push(daily.relative_humidity_2m_mean[i]);
  }

  const yearsProcessed = 10;

  const monthlyData: MonthlyClimateData[] = monthBuckets.map((b, idx) => {
    const avg = (arr: number[]) => arr.length ? arr.reduce((a, c) => a + c, 0) / arr.length : 0;
    const max = (arr: number[]) => arr.length ? Math.max(...arr) : 0;
    const min = (arr: number[]) => arr.length ? Math.min(...arr) : 0;

    const cardinalCounts: Record<string, number> = {};
    b.windDirs.forEach(d => {
      const c = degToCardinal(d);
      cardinalCounts[c] = (cardinalCounts[c] || 0) + 1;
    });
    const prevailingCardinal = Object.entries(cardinalCounts).sort((a,b) => b[1] - a[1])[0]?.[0] || 'N';
    const cardinalToDeg: Record<string, number> = { 'N': 0, 'NE': 45, 'E': 90, 'SE': 135, 'S': 180, 'SW': 225, 'W': 270, 'NW': 315 };

    const tAvg = avg(b.tempMean);
    const rh = avg(b.humidity);
    const rain = b.rain.reduce((a,c)=>a+c,0) / yearsProcessed;
    const rainyDays = Math.round(b.rainyDaysCount / yearsProcessed);
    const solar = avg(b.solar);
    const wind = avg(b.wind);
    const uvAvg = avg(b.uv);

    // Apply Threshold Logic
    const isWinter = tAvg <= CLIMATE_THRESHOLDS.WINTER_MAX_TEMP;
    const isRainy = rain >= CLIMATE_THRESHOLDS.RAINY_MIN_PRECIP || rainyDays >= CLIMATE_THRESHOLDS.RAINY_MIN_DAYS;
    const isSunny = solar >= CLIMATE_THRESHOLDS.SUNNY_MIN_SOLAR && rain < CLIMATE_THRESHOLDS.SUNNY_MAX_PRECIP;
    const isWindy = wind >= CLIMATE_THRESHOLDS.WINDY_MIN_SPEED;

    return {
      month: MONTH_NAMES[idx],
      monthIdx: idx,
      tempAvg: parseFloat(tAvg.toFixed(1)),
      tempMax: parseFloat(max(b.tempMax).toFixed(1)),
      tempMin: parseFloat(min(b.tempMin).toFixed(1)),
      rainfall: parseFloat(rain.toFixed(1)),
      rainyDays: rainyDays,
      humidity: parseFloat(rh.toFixed(1)),
      humidityMax: parseFloat(max(b.humidity).toFixed(1)),
      humidityMin: parseFloat(min(b.humidity).toFixed(1)),
      windSpeed: parseFloat(wind.toFixed(1)),
      windMax: parseFloat(max(b.wind).toFixed(1)),
      windDir: cardinalToDeg[prevailingCardinal], 
      solarIntensity: parseFloat(solar.toFixed(1)),
      peakSunHours: parseFloat((solar / 3.6).toFixed(1)),
      uvIndex: parseFloat(uvAvg.toFixed(1)),
      heatIndex: parseFloat((tAvg + (rh > 60 ? 0.5 * (rh - 60) : 0)).toFixed(1)),
      isSunny,
      isRainy,
      isWinter,
      isWindy
    };
  });

  const sortedTemp = [...monthlyData].sort((a, b) => a.tempAvg - b.tempAvg);
  const sortedRain = [...monthlyData].sort((a, b) => a.rainfall - b.rainfall);
  const sortedSolar = [...monthlyData].sort((a, b) => a.solarIntensity - b.solarIntensity);

  const result: ClimateStats = {
    location: { name: locationName || "Coordinate Point", lat, lng },
    period: "ERA5 10-Year Global Archive",
    reliabilityScore: 99.8,
    monthlyData,
    summary: {
      hottestMonth: sortedTemp[11].month,
      coldestMonth: sortedTemp[0].month,
      rainiestMonth: sortedRain[11].month,
      sunniestMonth: sortedSolar[11].month,
    }
  };

  climateCache.set(cacheKey, result);
  return result;
}

import React, { useState, useEffect, useRef } from 'react';
import { Page, ClimateStats, LocationInfo } from './types';
import { fetchClimateData, geocode, reverseGeocode } from './services/climateService';
import { getClimateInsights } from './services/geminiService';
import Header from './components/Header';
import Overview from './components/Overview';
import SeasonalDetail from './components/SeasonalDetail';
import StatsTable from './components/StatsTable';
import Visuals from './components/Visuals';

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState<Page>(Page.OVERVIEW);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);
  const [data, setData] = useState<ClimateStats | null>(null);
  const [insights, setInsights] = useState<string>("");
  const [search, setSearch] = useState<string>("");
  const [searchResults, setSearchResults] = useState<LocationInfo[]>([]);
  const [useCoords, setUseCoords] = useState<boolean>(false);
  const [latInput, setLatInput] = useState<string>("");
  const [lngInput, setLngInput] = useState<string>("");
  const [isCooldown, setIsCooldown] = useState<boolean>(false);
  const [isSearching, setIsSearching] = useState<boolean>(false);
  const [isLocating, setIsLocating] = useState<boolean>(false);

  const searchTimeoutRef = useRef<number | null>(null);

  const loadData = async (lat: number, lng: number, name: string) => {
    setLoading(true);
    setError(null);
    try {
      const stats = await fetchClimateData(lat, lng, name);
      setData(stats);
      try {
        const text = await getClimateInsights(stats);
        setInsights(text);
      } catch (geminiErr) {
        setInsights("Climate analysis complete for " + name + ". Explore detailed historical trends below.");
      }
    } catch (err: any) {
      setError(err.message || "Failed to retrieve climate data.");
      if (err.message?.includes("rate limit")) {
        setIsCooldown(true);
        setTimeout(() => setIsCooldown(false), 30000);
      }
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadData(37.7749, -122.4194, "San Francisco, California, United States");
  }, []);

  useEffect(() => {
    if (useCoords || !search.trim() || search.trim().length < 2) {
      setSearchResults([]);
      return;
    }
    if (searchTimeoutRef.current) window.clearTimeout(searchTimeoutRef.current);
    setIsSearching(true);
    searchTimeoutRef.current = window.setTimeout(async () => {
      try {
        const results = await geocode(search);
        setSearchResults(results);
      } catch (err) {
        console.debug("Search error", err);
      } finally {
        setIsSearching(false);
      }
    }, 400);
    return () => { if (searchTimeoutRef.current) window.clearTimeout(searchTimeoutRef.current); };
  }, [search, useCoords]);

  const handleSearchSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (isCooldown) return;
    if (useCoords) {
      const lat = parseFloat(latInput);
      const lng = parseFloat(lngInput);
      if (isNaN(lat) || isNaN(lng)) {
        setError("Please enter valid numeric coordinates.");
        return;
      }
      loadData(lat, lng, `Point (${lat.toFixed(2)}, ${lng.toFixed(2)})`);
    } else {
      if (searchResults.length > 0) {
        selectLocation(searchResults[0]);
      } else if (search.trim()) {
        try {
          const results = await geocode(search);
          if (results.length > 0) selectLocation(results[0]);
          else setError("No locations found for '" + search + "'.");
        } catch (err: any) {
          setError(err.message || "Search failed.");
        }
      }
    }
  };

  const handleGetCurrentLocation = () => {
    if (!navigator.geolocation) {
      setError("Geolocation is not supported by your browser.");
      return;
    }

    setIsLocating(true);
    navigator.geolocation.getCurrentPosition(
      async (position) => {
        const { latitude, longitude } = position.coords;

        // Auto-detect the human-readable name of the coordinates
        const locationName = await reverseGeocode(latitude, longitude);

        loadData(latitude, longitude, locationName);

        // Sync inputs
        setLatInput(latitude.toFixed(4));
        setLngInput(longitude.toFixed(4));
        setSearch(locationName);
        setUseCoords(false); // Switch to search view so user sees the name
        setIsLocating(false);
      },
      (error) => {
        setIsLocating(false);
        switch(error.code) {
          case error.PERMISSION_DENIED:
            setError("Location access denied. Please enable location permissions in your browser.");
            break;
          case error.POSITION_UNAVAILABLE:
            setError("Location information is unavailable.");
            break;
          case error.TIMEOUT:
            setError("The request to get user location timed out.");
            break;
          default:
            setError("An unknown error occurred while fetching location.");
            break;
        }
      },
      { enableHighAccuracy: true, timeout: 5000, maximumAge: 0 }
    );
  };

  const selectLocation = (loc: LocationInfo) => {
    loadData(loc.lat, loc.lng, loc.name);
    setSearchResults([]);
    setSearch(loc.name);
  };

  return (
    <div className="max-w-6xl mx-auto px-4 pb-20 pt-6">
      <div className="mb-8 flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div>
          <h1 className="text-4xl font-black text-slate-800 tracking-tighter flex items-center gap-2">
            <span className="bg-blue-600 text-white p-2 rounded-2xl rotate-3 shadow-lg">🌍</span>
            ClimaIntel
          </h1>
          <p className="text-slate-500 text-xs font-black uppercase tracking-widest mt-1 ml-1">Global Climate Intelligence</p>
        </div>

        <div className="w-full md:w-auto">
          {/* Mode Switcher */}
          <div className="flex bg-slate-100 p-1 rounded-2xl mb-3 w-fit ml-auto md:ml-0">
            <button 
              onClick={() => setUseCoords(false)}
              className={`px-4 py-1.5 rounded-xl text-[11px] font-black uppercase tracking-wider transition-all ${!useCoords ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
            >
              Search Place
            </button>
            <button 
              onClick={() => setUseCoords(true)}
              className={`px-4 py-1.5 rounded-xl text-[11px] font-black uppercase tracking-wider transition-all ${useCoords ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
            >
              Coordinates
            </button>
          </div>

          <div className="relative">
            <div className="flex gap-2">
              <div className="flex-1 flex gap-2">
                <div className="relative flex-1">
                  {!useCoords ? (
                    <div className="relative">
                      <input 
                        type="text" 
                        value={search}
                        onChange={(e) => setSearch(e.target.value)}
                        placeholder="Enter city name..." 
                        className="px-5 py-3.5 rounded-2xl border border-slate-200 focus:outline-none focus:ring-4 focus:ring-blue-100 w-full md:w-80 shadow-sm font-medium disabled:bg-slate-50"
                        disabled={isCooldown}
                      />
                      {isSearching && (
                        <div className="absolute right-4 top-1/2 -translate-y-1/2">
                          <div className="w-4 h-4 border-2 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
                        </div>
                      )}
                    </div>
                  ) : (
                    <div className="flex gap-2">
                      <input 
                        type="text" 
                        placeholder="Lat" 
                        value={latInput}
                        onChange={(e) => setLatInput(e.target.value)}
                        className="w-24 px-4 py-3.5 rounded-2xl border border-slate-200 focus:outline-none focus:ring-4 focus:ring-blue-100 shadow-sm font-mono text-sm"
                      />
                      <input 
                        type="text" 
                        placeholder="Lng" 
                        value={lngInput}
                        onChange={(e) => setLngInput(e.target.value)}
                        className="w-24 px-4 py-3.5 rounded-2xl border border-slate-200 focus:outline-none focus:ring-4 focus:ring-blue-100 shadow-sm font-mono text-sm"
                      />
                    </div>
                  )}
                </div>
                <button 
                  onClick={handleSearchSubmit}
                  disabled={isCooldown}
                  className={`${isCooldown ? 'bg-slate-400 cursor-not-allowed' : 'bg-slate-900 hover:bg-black active:scale-95'} text-white px-6 py-3.5 rounded-2xl transition-all shadow-xl font-bold flex items-center justify-center min-w-[100px]`}
                >
                  Analyze
                </button>
              </div>
              <button
                type="button"
                onClick={handleGetCurrentLocation}
                disabled={isLocating || isCooldown}
                className={`px-4 py-3.5 rounded-2xl border transition-all shadow-md flex items-center justify-center ${
                  isLocating 
                    ? 'bg-blue-50 border-blue-200 text-blue-600' 
                    : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50 active:scale-95'
                }`}
                title="Detect My Location & Analyze"
              >
                {isLocating ? (
                  <div className="w-5 h-5 border-2 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
                ) : (
                  <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"></path><circle cx="12" cy="10" r="3"></circle></svg>
                )}
              </button>
            </div>

            {searchResults.length > 0 && !useCoords && (
              <div className="absolute top-full left-0 right-0 bg-white shadow-2xl rounded-3xl mt-2 z-50 border border-slate-100 overflow-hidden max-h-[300px] overflow-y-auto scrollbar-hide">
                {searchResults.map((loc, i) => (
                  <button 
                    key={i} 
                    onClick={() => selectLocation(loc)}
                    className="w-full text-left px-5 py-4 hover:bg-blue-50/50 transition border-b border-slate-50 last:border-none"
                  >
                    <span className="font-bold text-slate-800 block text-sm">{loc.name}</span>
                    <span className="text-[10px] text-slate-400 font-mono">{loc.lat.toFixed(3)}°N, {loc.lng.toFixed(3)}°E</span>
                  </button>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>

      {error && (
        <div className="mb-8 bg-rose-50 border-rose-100 border-2 p-6 rounded-[2rem] flex items-center gap-4 animate-in fade-in">
          <div className="text-3xl">🧩</div>
          <div>
            <h3 className="font-black text-rose-900">System Notification</h3>
            <p className="text-rose-700 text-sm font-medium">{error}</p>
          </div>
          <button onClick={() => setError(null)} className="ml-auto text-rose-300 hover:text-rose-600">✕</button>
        </div>
      )}

      {loading && !data ? (
        <div className="flex flex-col items-center justify-center py-40">
           <div className="animate-spin rounded-full h-16 w-16 border-t-4 border-blue-600 mb-6"></div>
           <p className="text-slate-800 font-black text-2xl tracking-tight">Syncing Climate Records...</p>
        </div>
      ) : data && (
        <>
          <Header data={data} insights={insights} />

          <nav className="flex overflow-x-auto gap-2 mb-10 bg-white/60 p-2 rounded-[2.5rem] shadow-sm border border-slate-200/50 scrollbar-hide sticky top-4 z-40 backdrop-blur-xl">
            {[
              { id: Page.OVERVIEW, label: "Overview", icon: "🌎" },
              { id: Page.SUNNY, label: "Sunny", icon: "☀️" },
              { id: Page.RAINY, label: "Rainy", icon: "🌧️" },
              { id: Page.WINTER, label: "Winter", icon: "❄️" },
              { id: Page.STATS, label: "Data", icon: "📊" },
              { id: Page.GRAPHS, label: "Graphs", icon: "📈" },
            ].map(tab => (
              <button
                key={tab.id}
                onClick={() => setCurrentPage(tab.id as Page)}
                className={`flex items-center gap-2 px-6 py-4 rounded-[1.8rem] whitespace-nowrap transition-all ${
                  currentPage === tab.id 
                    ? 'bg-slate-900 text-white shadow-2xl -translate-y-1' 
                    : 'text-slate-600 hover:bg-white font-bold text-sm'
                }`}
              >
                <span className="text-xl">{tab.icon}</span>
                <span className="font-black tracking-tight">{tab.label}</span>
              </button>
            ))}
          </nav>

          <main className="fade-in">
            {currentPage === Page.OVERVIEW && <Overview data={data} />}
            {currentPage === Page.SUNNY && <SeasonalDetail data={data} type="sunny" />}
            {currentPage === Page.RAINY && <SeasonalDetail data={data} type="rainy" />}
            {currentPage === Page.WINTER && <SeasonalDetail data={data} type="winter" />}
            {currentPage === Page.STATS && <StatsTable data={data} />}
            {currentPage === Page.GRAPHS && <Visuals data={data} />}
          </main>
        </>
      )}
    </div>
  );
};

export default App;

import React from 'react';
import { ClimateStats, MonthlyClimateData } from '../types';
import { degToCardinal } from '../services/climateService';
import {
  AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
  BarChart, Bar, LineChart, Line, Cell
} from 'recharts';

interface Props {
  data: ClimateStats;
  type: 'sunny' | 'rainy' | 'winter';
}

const SeasonalDetail: React.FC<Props> = ({ data, type }) => {
  const months = data.monthlyData.filter(m => {
    if (type === 'sunny') return m.isSunny;
    if (type === 'rainy') return m.isRainy;
    return m.isWinter;
  });

  if (months.length === 0) {
    return (
      <div className="bg-slate-100 p-12 rounded-[2.5rem] text-center border-2 border-dashed border-slate-200">
        <p className="text-slate-400 font-bold text-lg">No distinct {type} patterns detected for this location.</p>
        <p className="text-slate-400 text-sm mt-1">This location may have a very stable year-round climate.</p>
      </div>
    );
  }

  const getSeasonTheme = () => {
    switch (type) {
      case 'sunny': return { color: '#f59e0b', label: 'Sunlight & UV Intensity', icon: '☀️' };
      case 'rainy': return { color: '#3b82f6', label: 'Rainfall & Moisture', icon: '🌧️' };
      case 'winter': return { color: '#6366f1', label: 'Thermal Profile & Wind', icon: '❄️' };
    }
  };

  const theme = getSeasonTheme();

  return (
    <div className="space-y-10">
      {/* Seasonal Analytics Header */}
      <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
        <div className="flex items-center gap-3 mb-8">
          <span className="text-2xl">{theme.icon}</span>
          <h3 className="text-2xl font-black text-slate-800 tracking-tight">{theme.label}</h3>
        </div>

        <div className="h-[300px] w-full">
          <ResponsiveContainer width="100%" height="100%">
            {type === 'sunny' ? (
              <AreaChart data={months}>
                <defs>
                  <linearGradient id="colorSun" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#f59e0b" stopOpacity={0.2}/>
                    <stop offset="95%" stopColor="#f59e0b" stopOpacity={0}/>
                  </linearGradient>
                </defs>
                <XAxis dataKey="month" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12, fontWeight: 700}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12}} />
                <Tooltip contentStyle={{borderRadius: '20px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)'}} />
                <Area name="Solar Energy" type="monotone" dataKey="solarIntensity" stroke="#f59e0b" strokeWidth={4} fill="url(#colorSun)" />
                <Area name="UV Index" type="monotone" dataKey="uvIndex" stroke="#ef4444" strokeWidth={2} fill="transparent" strokeDasharray="5 5" />
              </AreaChart>
            ) : type === 'rainy' ? (
              <BarChart data={months}>
                <XAxis dataKey="month" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12, fontWeight: 700}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12}} unit="mm" />
                <Tooltip cursor={{fill: '#f1f5f9'}} contentStyle={{borderRadius: '20px', border: 'none'}} />
                <Bar name="Rainfall" dataKey="rainfall" fill="#3b82f6" radius={[10, 10, 0, 0]} barSize={40} />
              </BarChart>
            ) : (
              <LineChart data={months}>
                <XAxis dataKey="month" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12, fontWeight: 700}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12}} unit="°" />
                <Tooltip contentStyle={{borderRadius: '20px', border: 'none'}} />
                <Line name="Avg Temp" type="monotone" dataKey="tempAvg" stroke="#6366f1" strokeWidth={4} dot={{ r: 6, fill: '#6366f1' }} />
                <Line name="Min Temp" type="monotone" dataKey="tempMin" stroke="#94a3b8" strokeWidth={2} strokeDasharray="3 3" dot={false} />
              </LineChart>
            )}
          </ResponsiveContainer>
        </div>
      </div>

      {/* Monthly Detail Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {months.map(m => (
          <MonthCard key={m.month} data={m} type={type} />
        ))}
      </div>
    </div>
  );
};

const MonthCard: React.FC<{data: MonthlyClimateData, type: string}> = ({ data, type }) => {
  const getTheme = () => {
    if (type === 'sunny') return { bg: 'bg-orange-50', text: 'text-orange-900', border: 'border-orange-100', icon: '☀️' };
    if (type === 'rainy') return { bg: 'bg-blue-50', text: 'text-blue-900', border: 'border-blue-100', icon: '🌧️' };
    return { bg: 'bg-indigo-50', text: 'text-indigo-900', border: 'border-indigo-100', icon: '❄️' };
  };

  const theme = getTheme();
  const cardinal = degToCardinal(data.windDir);

  const getUvSeverity = (uv: number) => {
    if (uv >= 11) return 'text-purple-600';
    if (uv >= 8) return 'text-red-600';
    if (uv >= 6) return 'text-orange-600';
    if (uv >= 3) return 'text-yellow-600';
    return 'text-green-600';
  };

  return (
    <div className={`${theme.bg} ${theme.border} border-2 p-7 rounded-[2.5rem] shadow-sm hover:shadow-md transition-all group`}>
      <div className="flex justify-between items-center mb-8">
        <div>
           <h3 className={`text-3xl font-black ${theme.text}`}>{data.month}</h3>
           <p className="text-slate-500 text-xs font-bold uppercase tracking-widest mt-1">Seasonal Profile</p>
        </div>
        <span className="text-4xl filter drop-shadow-sm group-hover:scale-110 transition-transform">{theme.icon}</span>
      </div>

      <div className="space-y-4">
        <DetailRow label="Avg Temperature" value={`${data.tempAvg}°C`} />
        <DetailRow label="Range" value={`${data.tempMin}° - ${data.tempMax}°C`} />

        {type === 'rainy' && (
          <>
            <DetailRow label="Precipitation" value={`${data.rainfall} mm`} />
            <DetailRow label="Wet Days" value={`${data.rainyDays} days`} />
          </>
        )}

        {type === 'sunny' && (
          <>
            <DetailRow label="Sun Intensity" value={`${data.solarIntensity} MJ/m²`} />
            <DetailRow label="Peak Hours" value={`${data.peakSunHours} hrs`} />
            <div className="flex justify-between items-center py-2 border-b border-black/5">
              <span className="text-slate-500 text-sm font-medium">UV Index (Max Avg)</span>
              <span className={`font-black ${getUvSeverity(data.uvIndex)}`}>{data.uvIndex}</span>
            </div>
          </>
        )}

        <DetailRow label="Humidity" value={`${data.humidity}%`} />

        <div className="flex justify-between items-center pt-2 mt-2 border-t border-black/5">
          <span className="text-slate-500 text-sm font-semibold">Prevailing Wind</span>
          <div className="flex items-center gap-2">
            <span className="text-slate-800 font-black">{data.windSpeed} km/h {cardinal}</span>
            <div 
              className="w-6 h-6 rounded-full bg-white border border-slate-200 flex items-center justify-center text-blue-500"
              style={{ transform: `rotate(${data.windDir}deg)` }}
            >
              <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round">
                <line x1="12" y1="19" x2="12" y2="5"></line>
                <polyline points="5 12 12 5 19 12"></polyline>
              </svg>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

const DetailRow: React.FC<{label: string, value: string}> = ({ label, value }) => (
  <div className="flex justify-between items-center py-2 border-b border-black/5 last:border-0">
    <span className="text-slate-500 text-sm font-medium">{label}</span>
    <span className="text-slate-800 font-bold">{value}</span>
  </div>
);

export default SeasonalDetail;

import React from 'react';
import { ClimateStats } from '../types';
import {
  ComposedChart, Line, Bar, XAxis, YAxis, CartesianGrid, Tooltip, 
  ResponsiveContainer, Legend, Area
} from 'recharts';

interface Props {
  data: ClimateStats;
}

const Overview: React.FC<Props> = ({ data }) => {
  const sunnyMonths = data.monthlyData.filter(m => m.isSunny).map(m => m.month);
  const rainyMonths = data.monthlyData.filter(m => m.isRainy).map(m => m.month);
  const winterMonths = data.monthlyData.filter(m => m.isWinter).map(m => m.month);
  const windyMonths = data.monthlyData.filter(m => m.isWindy).map(m => m.month);

  return (
    <div className="space-y-8">
      {/* Yearly Summary Pulse Chart */}
      <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
