import React from 'react';
import { ClimateStats, MonthlyClimateData } from '../types';
import { degToCardinal } from '../services/climateService';
import {
  AreaChart, Area, XAxis, YAxis, Tooltip, ResponsiveContainer,
  BarChart, Bar, LineChart, Line
} from 'recharts';

interface Props {
  data: ClimateStats;
  type: 'sunny' | 'rainy' | 'winter';
}

const SeasonalDetail: React.FC<Props> = ({ data, type }) => {
  const months = data.monthlyData.filter(m => {
    if (type === 'sunny') return m.isSunny;
    if (type === 'rainy') return m.isRainy;
    return m.isWinter;
  });

  if (months.length === 0) {
    return (
      <div className="bg-slate-100 p-12 rounded-[2.5rem] text-center border-2 border-dashed border-slate-200">
        <p className="text-slate-400 font-bold text-lg">No distinct {type} patterns detected for this location.</p>
        <p className="text-slate-400 text-sm mt-1">This location may have a very stable year-round climate.</p>
      </div>
    );
  }

  const getSeasonTheme = () => {
    switch (type) {
      case 'sunny': return { color: '#f59e0b', label: 'Sunlight & UV Intensity', icon: '☀️' };
      case 'rainy': return { color: '#3b82f6', label: 'Rainfall & Moisture', icon: '🌧️' };
      case 'winter': return { color: '#6366f1', label: 'Thermal Profile & Wind', icon: '❄️' };
    }
  };

  const theme = getSeasonTheme();

  return (
    <div className="space-y-10">
      {/* Seasonal Analytics Header */}
      <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
        <div className="flex items-center gap-3 mb-8">
          <span className="text-2xl">{theme.icon}</span>
          <h3 className="text-2xl font-black text-slate-800 tracking-tight">{theme.label}</h3>
        </div>

        <div className="h-[300px] w-full">
          <ResponsiveContainer width="100%" height="100%">
            {type === 'sunny' ? (
              <AreaChart data={months}>
                <defs>
                  <linearGradient id="colorSun" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#f59e0b" stopOpacity={0.2}/>
                    <stop offset="95%" stopColor="#f59e0b" stopOpacity={0}/>
                  </linearGradient>
                </defs>
                <XAxis dataKey="month" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12, fontWeight: 700}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12}} />
                <Tooltip contentStyle={{borderRadius: '20px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)'}} />
                <Area name="Solar Energy" type="monotone" dataKey="solarIntensity" stroke="#f59e0b" strokeWidth={4} fill="url(#colorSun)" />
                <Area name="UV Index" type="monotone" dataKey="uvIndex" stroke="#ef4444" strokeWidth={2} fill="transparent" strokeDasharray="5 5" />
              </AreaChart>
            ) : type === 'rainy' ? (
              <BarChart data={months}>
                <XAxis dataKey="month" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12, fontWeight: 700}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12}} unit="mm" />
                <Tooltip cursor={{fill: '#f1f5f9'}} contentStyle={{borderRadius: '20px', border: 'none'}} />
                <Bar name="Rainfall" dataKey="rainfall" fill="#3b82f6" radius={[10, 10, 0, 0]} barSize={40} />
              </BarChart>
            ) : (
              <LineChart data={months}>
                <XAxis dataKey="month" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12, fontWeight: 700}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12}} unit="°" />
                <Tooltip contentStyle={{borderRadius: '20px', border: 'none'}} />
                <Line name="Avg Temp" type="monotone" dataKey="tempAvg" stroke="#6366f1" strokeWidth={4} dot={{ r: 6, fill: '#6366f1' }} />
                <Line name="Min Temp" type="monotone" dataKey="tempMin" stroke="#94a3b8" strokeWidth={2} strokeDasharray="3 3" dot={false} />
              </LineChart>
            )}
          </ResponsiveContainer>
        </div>
      </div>

      {/* Monthly Detail Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {months.map(m => (
          <MonthCard key={m.month} data={m} type={type} />
        ))}
      </div>
    </div>
  );
};

const MonthCard: React.FC<{data: MonthlyClimateData, type: string}> = ({ data, type }) => {
  const getTheme = () => {
    if (type === 'sunny') return { bg: 'bg-orange-50', text: 'text-orange-900', border: 'border-orange-100', icon: '☀️', chart: '#f59e0b' };
    if (type === 'rainy') return { bg: 'bg-blue-50', text: 'text-blue-900', border: 'border-blue-100', icon: '🌧️', chart: '#3b82f6' };
    return { bg: 'bg-indigo-50', text: 'text-indigo-900', border: 'border-indigo-100', icon: '❄️', chart: '#6366f1' };
  };

  const theme = getTheme();
  const cardinal = degToCardinal(data.windDir);

  const getUvSeverity = (uv: number) => {
    if (uv >= 11) return 'text-purple-600';
    if (uv >= 8) return 'text-red-600';
    if (uv >= 6) return 'text-orange-600';
    if (uv >= 3) return 'text-yellow-600';
    return 'text-green-600';
  };

  return (
    <div className={`${theme.bg} ${theme.border} border-2 p-7 rounded-[2.5rem] shadow-sm hover:shadow-md transition-all group`}>
      <div className="flex justify-between items-center mb-6">
        <div>
           <h3 className={`text-3xl font-black ${theme.text}`}>{data.month}</h3>
           <p className="text-slate-500 text-xs font-bold uppercase tracking-widest mt-1">Seasonal Profile</p>
        </div>
        <span className="text-4xl filter drop-shadow-sm group-hover:scale-110 transition-transform">{theme.icon}</span>
      </div>

      {/* Mini Bar Visual */}
      <div className="mb-6 bg-black/5 rounded-2xl p-4">
        <div className="flex justify-between text-[10px] font-black uppercase text-slate-400 mb-2">
          <span>Heat</span>
          <span>Comfort Range</span>
        </div>
        <div className="h-2 w-full bg-black/5 rounded-full relative overflow-hidden">
          <div 
            className="absolute h-full rounded-full transition-all duration-1000"
            style={{ 
              backgroundColor: theme.chart,
              left: `${Math.max(0, (data.tempMin + 10) * 2)}%`,
              width: `${Math.max(10, (data.tempMax - data.tempMin) * 2)}%`
            }}
          />
        </div>
      </div>

      <div className="space-y-4">
        <DetailRow label="Avg Temperature" value={`${data.tempAvg}°C`} />

        {type === 'rainy' && (
          <>
            <DetailRow label="Precipitation" value={`${data.rainfall} mm`} />
            <DetailRow label="Wet Days" value={`${data.rainyDays} days`} />
          </>
        )}

        {type === 'sunny' && (
          <>
            <DetailRow label="Peak Hours" value={`${data.peakSunHours} hrs`} />
            <div className="flex justify-between items-center py-2 border-b border-black/5">
              <span className="text-slate-500 text-sm font-medium">UV Index</span>
              <span className={`font-black ${getUvSeverity(data.uvIndex)}`}>{data.uvIndex}</span>
            </div>
          </>
        )}

        <DetailRow label="Humidity" value={`${data.humidity}%`} />

        <div className="flex justify-between items-center pt-2 mt-2 border-t border-black/5">
          <span className="text-slate-500 text-sm font-semibold">Wind Speed</span>
          <div className="flex items-center gap-2">
            <span className="text-slate-800 font-black">{data.windSpeed} km/h {cardinal}</span>
          </div>
        </div>
      </div>
    </div>
  );
};

const DetailRow: React.FC<{label: string, value: string}> = ({ label, value }) => (
  <div className="flex justify-between items-center py-2 border-b border-black/5 last:border-0">
    <span className="text-slate-500 text-sm font-medium">{label}</span>
    <span className="text-slate-800 font-bold">{value}</span>
  </div>
);

export default SeasonalDetail;

import React from 'react';
import {
  AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
  BarChart, Bar, LineChart, Line, Legend, Cell,
  Radar, RadarChart, PolarGrid, PolarAngleAxis
} from 'recharts';
import { ClimateStats } from '../types';
import { degToCardinal } from '../services/climateService';

interface Props {
  data: ClimateStats;
}

const Visuals: React.FC<Props> = ({ data }) => {
  // Prepare Wind Rose Data (Radar Chart)
  const directions = ['N', 'NE', 'E', 'SE', 'S', 'SW', 'W', 'NW'];
  const windRoseData = directions.map(dir => {
    const monthsInDir = data.monthlyData.filter(m => degToCardinal(m.windDir) === dir);
    return {
      direction: dir,
      frequency: monthsInDir.length,
      avgSpeed: monthsInDir.length > 0 
        ? monthsInDir.reduce((acc, curr) => acc + curr.windSpeed, 0) / monthsInDir.length 
        : 0
    };
  });

  const getUvColor = (uv: number) => {
    if (uv >= 11) return '#a855f7'; // Extreme (Purple)
    if (uv >= 8) return '#ef4444';  // Very High (Red)
    if (uv >= 6) return '#f97316';  // High (Orange)
    if (uv >= 3) return '#f59e0b';  // Moderate (Amber/Yellow)
    return '#10b981';              // Low (Green)
  };

  return (
    <div className="space-y-12 pb-20">
      {/* 1. UV Index - Primary Feature Request */}
      <section className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
        <div className="mb-8">
          <div className="flex items-center gap-3">
            <span className="text-3xl">☀️</span>
            <h2 className="text-2xl font-black text-slate-800 tracking-tight">Average Monthly UV Index</h2>
          </div>
          <p className="text-slate-400 text-sm font-medium mt-2">Historical solar radiation intensity for skin safety planning.</p>
        </div>

        <div className="h-[350px] w-full">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={data.monthlyData}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
              <XAxis 
                dataKey="month" 
                axisLine={false} 
                tickLine={false} 
                tick={{fill: '#94a3b8', fontSize: 12, fontWeight: 700}} 
              />
              <YAxis 
                axisLine={false} 
                tickLine={false} 
                tick={{fill: '#94a3b8', fontSize: 12}} 
                domain={[0, 12]}
              />
              <Tooltip 
                cursor={{fill: '#f8fafc'}}
                contentStyle={{ borderRadius: '20px', border: 'none', boxShadow: '0 20px 25px -5px rgb(0 0 0 / 0.1)' }}
              />
              <Bar dataKey="uvIndex" name="UV Index" radius={[12, 12, 0, 0]} barSize={40}>
                {data.monthlyData.map((entry, index) => (
                  <Cell key={`cell-uv-${index}`} fill={getUvColor(entry.uvIndex)} />
                ))}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>

        <div className="flex flex-wrap gap-4 mt-8 pt-6 border-t border-slate-50 justify-center">
          {[
            { label: 'Low', color: 'bg-emerald-500' },
            { label: 'Moderate', color: 'bg-amber-500' },
            { label: 'High', color: 'bg-orange-500' },
            { label: 'Very High', color: 'bg-red-500' },
            { label: 'Extreme', color: 'bg-purple-500' }
          ].map(lvl => (
            <div key={lvl.label} className="flex items-center gap-2">
              <span className={`w-3 h-3 rounded-full ${lvl.color}`}></span>
              <span className="text-[10px] font-black uppercase text-slate-400 tracking-wider">{lvl.label}</span>
            </div>
          ))}
        </div>
      </section>

      {/* 2. Temperature Range Chart */}
      <section className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
        <div className="mb-8">
          <h2 className="text-2xl font-black text-slate-800 tracking-tight">Thermal Profile (°C)</h2>
          <p className="text-slate-400 text-sm font-medium mt-1">Average monthly highs and lows.</p>
        </div>

        <div className="h-[350px] w-full">
          <ResponsiveContainer width="100%" height="100%">
            <AreaChart data={data.monthlyData}>
              <defs>
                <linearGradient id="tempGradient" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="#f43f5e" stopOpacity={0.1}/>
                  <stop offset="95%" stopColor="#3b82f6" stopOpacity={0.05}/>
                </linearGradient>
              </defs>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
              <XAxis dataKey="month" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11, fontWeight: 700}} />
              <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} unit="°" />
              <Tooltip contentStyle={{ borderRadius: '24px', border: 'none', boxShadow: '0 20px 25px -5px rgb(0 0 0 / 0.1)' }} />
              <Legend verticalAlign="top" height={36} />
              <Area name="Max Temp" type="monotone" dataKey="tempMax" stroke="#f43f5e" strokeWidth={3} fill="url(#tempGradient)" />
              <Area name="Min Temp" type="monotone" dataKey="tempMin" stroke="#3b82f6" strokeWidth={3} fill="transparent" />
              <Line name="Average" type="monotone" dataKey="tempAvg" stroke="#1e293b" strokeWidth={2} strokeDasharray="4 4" dot={false} />
            </AreaChart>
          </ResponsiveContainer>
        </div>
      </section>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* 3. Rainfall Bar Chart */}
        <section className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
          <h3 className="text-xl font-black text-slate-800 mb-6">Rainfall Intensity (mm)</h3>
          <div className="h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={data.monthlyData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="month" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 700}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10}} unit="mm" />
                <Tooltip cursor={{fill: '#f1f5f9'}} contentStyle={{ borderRadius: '20px', border: 'none' }} />
                <Bar dataKey="rainfall" name="Rain" fill="#3b82f6" radius={[8, 8, 0, 0]} barSize={25} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </section>

        {/* 4. Wind Radar Chart */}
        <section className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
          <h3 className="text-xl font-black text-slate-800 mb-6">Prevailing Wind Directions</h3>
          <div className="h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <RadarChart cx="50%" cy="50%" outerRadius="80%" data={windRoseData}>
                <PolarGrid stroke="#e2e8f0" />
                <PolarAngleAxis dataKey="direction" tick={{ fill: '#64748b', fontSize: 12, fontWeight: 'bold' }} />
                <Radar name="Frequency" dataKey="frequency" stroke="#6366f1" fill="#6366f1" fillOpacity={0.6} />
                <Tooltip contentStyle={{ borderRadius: '16px', border: 'none' }} />
              </RadarChart>
            </ResponsiveContainer>
          </div>
        </section>
      </div>

      {/* 5. Humidity & Sunlight */}
      <section className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
        <h3 className="text-xl font-black text-slate-800 mb-6">Atmospheric Comfort & Sunlight</h3>
        <div className="h-[300px] w-full">
          <ResponsiveContainer width="100%" height="100%">
            <LineChart data={data.monthlyData}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
              <XAxis dataKey="month" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11, fontWeight: 700}} />
              <YAxis yAxisId="left" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} unit="%" />
              <YAxis yAxisId="right" orientation="right" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} unit="hr" />
              <Tooltip contentStyle={{ borderRadius: '20px', border: 'none' }} />
              <Legend />
              <Line yAxisId="left" type="monotone" name="Humidity %" dataKey="humidity" stroke="#0ea5e9" strokeWidth={3} dot={{r: 4, fill: '#0ea5e9'}} />
              <Line yAxisId="right" type="monotone" name="Peak Sun Hours" dataKey="peakSunHours" stroke="#f59e0b" strokeWidth={3} dot={{r: 4, fill: '#f59e0b'}} />
            </LineChart>
          </ResponsiveContainer>
        </div>
      </section>
    </div>
  );
};

export default Visuals;

