        <div className="h-[350px] w-full" style={{ minHeight: '350px' }}>
          <ResponsiveContainer width="100%" height="100%" debounce={1}>
            <BarChart data={data.monthlyData} margin={{ top: 10, right: 30, left: 0, bottom: 0 }}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
              <XAxis 
                dataKey="month" 
                axisLine={false} 
                tickLine={false} 
                tick={{fill: '#94a3b8', fontSize: 12, fontWeight: 700}} 
              />
              <YAxis 
                axisLine={false} 
                tickLine={false} 
                tick={{fill: '#94a3b8', fontSize: 12}} 
                domain={[0, 12]}
              />
              <Tooltip 
                cursor={{fill: '#f8fafc'}}
                contentStyle={{ borderRadius: '20px', border: 'none', boxShadow: '0 20px 25px -5px rgb(0 0 0 / 0.1)' }}
              />
              <Bar dataKey="uvIndex" name="UV Index" radius={[12, 12, 0, 0]} barSize={40}>
                {data.monthlyData.map((entry, index) => (
                  <Cell key={`cell-uv-${index}`} fill={getUvColor(entry.uvIndex)} />
                ))}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>

        <div className="flex flex-wrap gap-4 mt-8 pt-6 border-t border-slate-50 justify-center">
          {[
