      {/* 2. Temperature Range Section */}
      <section className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm min-h-[500px]">
        <div className="mb-8">
          <h2 className="text-2xl font-black text-slate-800 tracking-tight">Thermal Profile (°C)</h2>
