import { ClimateStats, MonthlyClimateData, LocationInfo } from '../types';

const MONTH_NAMES = [
  "January", "February", "March", "April", "May", "June",
  "July", "August", "September", "October", "November", "December"
];

/**
 * Climatic Thresholds for Classification
 * Based on standard meteorological comfort and intensity scales.
 */
const CLIMATE_THRESHOLDS = {
  WINTER_MAX_TEMP: 15,      // Avg temp <= 15°C is considered a "Winter" period
  RAINY_MIN_PRECIP: 60,     // Total monthly rainfall >= 60mm is "Rainy"
  RAINY_MIN_DAYS: 10,       // Alternatively, >= 10 rainy days (>=1mm) is "Rainy"
  SUNNY_MIN_SOLAR: 22,      // Solar intensity >= 22 MJ/m² is "Sunny"
  SUNNY_MAX_PRECIP: 40,     // But only if rainfall is relatively low
  WINDY_MIN_SPEED: 14.5,    // Average wind speed >= 14.5 km/h (~4 m/s) is "Windy"
};

// Simple in-memory cache to prevent redundant API calls during a single session
const climateCache = new Map<string, ClimateStats>();

export function degToCardinal(deg: number): string {
  const directions = ['N', 'NE', 'E', 'SE', 'S', 'SW', 'W', 'NW'];
  const index = Math.round(deg / 45) % 8;
  return directions[index];
}

/**
 * Geocode search with support for fuzzy matching and misspelled queries.
 * Uses Open-Meteo's Elasticsearch-backed geocoding API.
 */
export async function geocode(query: string): Promise<LocationInfo[]> {
  if (!query || query.trim().length < 2) return [];

  try {
    const url = `https://geocoding-api.open-meteo.com/v1/search?name=${encodeURIComponent(query.trim())}&count=10&language=en&format=json`;
    const response = await fetch(url);

    if (response.status === 429) throw new Error("SEARCH_LIMIT: Search limit reached. Please wait a few seconds.");
    if (!response.ok) throw new Error("SERVICE_UNAVAILABLE: Search service temporarily unavailable.");

    const data = await response.json();
    if (!data.results) return [];

    return data.results.map((r: any) => {
      const nameParts = [r.name];
      if (r.admin2 && r.admin2 !== r.name) nameParts.push(r.admin2);
      if (r.admin1 && r.admin1 !== r.name && r.admin1 !== r.admin2) nameParts.push(r.admin1);
      if (r.country && r.country !== r.name) nameParts.push(r.country);

      return {
        name: nameParts.join(', '),
        lat: r.latitude,
        lng: r.longitude,
        country: r.country,
      };
    });
  } catch (err: any) {
    console.error("Geocoding failed", err);
    throw err;
  }
}

/**
 * Reverse geocode coordinates to get a human-readable location name.
 */
export async function reverseGeocode(lat: number, lng: number): Promise<string> {
  try {
    const url = `https://nominatim.openstreetmap.org/reverse?lat=${lat}&lon=${lng}&format=json&zoom=10`;
    const response = await fetch(url, {
      headers: { 'Accept-Language': 'en' }
    });
    if (!response.ok) return `${lat.toFixed(2)}, ${lng.toFixed(2)}`;
    const data = await response.json();
    return data.display_name || `${lat.toFixed(2)}, ${lng.toFixed(2)}`;
  } catch (err) {
    return `${lat.toFixed(2)}, ${lng.toFixed(2)}`;
  }
}

async function fetchWithRetry(lat: number, lng: number): Promise<any> {
  const end = new Date();
  const start = new Date();
  start.setFullYear(end.getFullYear() - 10);
  const fmt = (d: Date) => d.toISOString().split('T')[0];

  const params = [
    'temperature_2m_max',
    'temperature_2m_min',
    'temperature_2m_mean',
    'precipitation_sum',
    'shortwave_radiation_sum',
    'windspeed_10m_max',
    'wind_direction_10m_dominant',
    'relative_humidity_2m_mean',
    'uv_index_max'
  ].join(',');

  const url = `https://archive-api.open-meteo.com/v1/archive?latitude=${lat}&longitude=${lng}&start_date=${fmt(start)}&end_date=${fmt(end)}&daily=${params}&timezone=auto`;

  const response = await fetch(url);

  if (response.status === 429) {
    throw new Error("RATE_LIMIT: Climate API rate limit exceeded. Please wait a minute before searching again.");
  }

  if (!response.ok) {
    if (response.status === 400) {
       throw new Error("OUTSIDE_GRID: This coordinate point is outside our historical climate grid. This usually happens for locations deep in the ocean or uninhabited remote zones.");
    }
    throw new Error(`API_ERROR: Climate API error: ${response.status}`);
  }
  return await response.json();
}

export async function fetchClimateData(lat: number, lng: number, locationName?: string): Promise<ClimateStats> {
  const cacheKey = `${lat.toFixed(2)}-${lng.toFixed(2)}`;
  if (climateCache.has(cacheKey)) {
    return climateCache.get(cacheKey)!;
  }

  const raw = await fetchWithRetry(lat, lng);

  if (!raw.daily) throw new Error("NO_DATA: No historical records found for these exact coordinates.");

  const daily = raw.daily;
  const time = daily.time;

  const monthBuckets = Array.from({ length: 12 }, () => ({
    tempMax: [] as number[],
    tempMin: [] as number[],
    tempMean: [] as number[],
    rain: [] as number[],
    solar: [] as number[],
    uv: [] as number[],
    wind: [] as number[],
    windDirs: [] as number[],
    humidity: [] as number[],
    rainyDaysCount: 0
  }));

  for (let i = 0; i < time.length; i++) {
    const monthStr = time[i].substring(5, 7);
    const month = parseInt(monthStr, 10) - 1;
    const bucket = monthBuckets[month];

    if (daily.temperature_2m_max[i] != null) bucket.tempMax.push(daily.temperature_2m_max[i]);
    if (daily.temperature_2m_min[i] != null) bucket.tempMin.push(daily.temperature_2m_min[i]);
    if (daily.temperature_2m_mean[i] != null) bucket.tempMean.push(daily.temperature_2m_mean[i]);
    if (daily.precipitation_sum[i] != null) {
      bucket.rain.push(daily.precipitation_sum[i]);
      if (daily.precipitation_sum[i] >= 1.0) bucket.rainyDaysCount++;
    }
    if (daily.shortwave_radiation_sum[i] != null) bucket.solar.push(daily.shortwave_radiation_sum[i]);
    if (daily.uv_index_max && daily.uv_index_max[i] != null) bucket.uv.push(daily.uv_index_max[i]);
    if (daily.windspeed_10m_max[i] != null) bucket.wind.push(daily.windspeed_10m_max[i]);
    if (daily.wind_direction_10m_dominant[i] != null) bucket.windDirs.push(daily.wind_direction_10m_dominant[i]);
    if (daily.relative_humidity_2m_mean[i] != null) bucket.humidity.push(daily.relative_humidity_2m_mean[i]);
  }

  const yearsProcessed = 10;

  const initialMonthlyData: MonthlyClimateData[] = monthBuckets.map((b, idx) => {
    const avg = (arr: number[]) => arr.length ? arr.reduce((a, c) => a + c, 0) / arr.length : 0;
    const max = (arr: number[]) => arr.length ? Math.max(...arr) : 0;
    const min = (arr: number[]) => arr.length ? Math.min(...arr) : 0;

    const cardinalCounts: Record<string, number> = {};
    b.windDirs.forEach(d => {
      const c = degToCardinal(d);
      cardinalCounts[c] = (cardinalCounts[c] || 0) + 1;
    });
    const prevailingCardinal = Object.entries(cardinalCounts).sort((a,b) => b[1] - a[1])[0]?.[0] || 'N';
    const cardinalToDeg: Record<string, number> = { 'N': 0, 'NE': 45, 'E': 90, 'SE': 135, 'S': 180, 'SW': 225, 'W': 270, 'NW': 315 };

    const tAvg = avg(b.tempMean);
    const rh = avg(b.humidity);
    const rain = b.rain.reduce((a,c)=>a+c,0) / yearsProcessed;
    const rainyDays = Math.round(b.rainyDaysCount / yearsProcessed);
    const solar = avg(b.solar);
    const wind = avg(b.wind);
    const uvAvg = avg(b.uv);

    return {
      month: MONTH_NAMES[idx],
      monthIdx: idx,
      tempAvg: parseFloat(tAvg.toFixed(1)),
      tempMax: parseFloat(max(b.tempMax).toFixed(1)),
      tempMin: parseFloat(min(b.tempMin).toFixed(1)),
      rainfall: parseFloat(rain.toFixed(1)),
      rainyDays: rainyDays,
      humidity: parseFloat(rh.toFixed(1)),
      humidityMax: parseFloat(max(b.humidity).toFixed(1)),
      humidityMin: parseFloat(min(b.humidity).toFixed(1)),
      windSpeed: parseFloat(wind.toFixed(1)),
      windMax: parseFloat(max(b.wind).toFixed(1)),
      windDir: cardinalToDeg[prevailingCardinal], 
      solarIntensity: parseFloat(solar.toFixed(1)),
      peakSunHours: parseFloat((solar / 3.6).toFixed(1)),
      uvIndex: parseFloat(uvAvg.toFixed(1)),
      heatIndex: parseFloat((tAvg + (rh > 60 ? 0.5 * (rh - 60) : 0)).toFixed(1)),
      isSunny: solar >= CLIMATE_THRESHOLDS.SUNNY_MIN_SOLAR && rain < CLIMATE_THRESHOLDS.SUNNY_MAX_PRECIP,
      isRainy: rain >= CLIMATE_THRESHOLDS.RAINY_MIN_PRECIP || rainyDays >= CLIMATE_THRESHOLDS.RAINY_MIN_DAYS,
      isWinter: tAvg <= CLIMATE_THRESHOLDS.WINTER_MAX_TEMP,
      isWindy: wind >= CLIMATE_THRESHOLDS.WINDY_MIN_SPEED
    };
  });

  const hasWinter = initialMonthlyData.some(m => m.isWinter);
  const hasRainy = initialMonthlyData.some(m => m.isRainy);
  const hasSunny = initialMonthlyData.some(m => m.isSunny);
  const hasWindy = initialMonthlyData.some(m => m.isWindy);

  const sortedByTemp = [...initialMonthlyData].sort((a, b) => a.tempAvg - b.tempAvg);
  const sortedByRain = [...initialMonthlyData].sort((a, b) => b.rainfall - a.rainfall);
  const sortedBySolar = [...initialMonthlyData].sort((a, b) => b.solarIntensity - a.solarIntensity);
  const sortedByWind = [...initialMonthlyData].sort((a, b) => b.windSpeed - a.windSpeed);

  const coldest3Months = sortedByTemp.slice(0, 3).map(m => m.monthIdx);
  const rainiest3Months = sortedByRain.slice(0, 3).map(m => m.monthIdx);
  const sunniest3Months = sortedBySolar.slice(0, 3).map(m => m.monthIdx);
  const windiest3Months = sortedByWind.slice(0, 3).map(m => m.monthIdx);

  const finalMonthlyData = initialMonthlyData.map(m => ({
    ...m,
    isWinter: hasWinter ? m.isWinter : coldest3Months.includes(m.monthIdx),
    isRainy: hasRainy ? m.isRainy : rainiest3Months.includes(m.monthIdx),
    isSunny: hasSunny ? m.isSunny : sunniest3Months.includes(m.monthIdx),
    isWindy: hasWindy ? m.isWindy : windiest3Months.includes(m.monthIdx),
  }));

  const result: ClimateStats = {
    location: { name: locationName || "Coordinate Point", lat, lng },
    period: "ERA5 10-Year Global Archive",
    reliabilityScore: 99.8,
    monthlyData: finalMonthlyData,
    summary: {
      hottestMonth: sortedByTemp[11].month,
      coldestMonth: sortedByTemp[0].month,
      rainiestMonth: sortedByRain[0].month,
      sunniestMonth: sortedBySolar[0].month,
    }
  };

  climateCache.set(cacheKey, result);
  return result;
}

import React, { useState, useEffect, useRef } from 'react';
import { Page, ClimateStats, LocationInfo } from './types';
import { fetchClimateData, geocode, reverseGeocode } from './services/climateService';
import { getClimateInsights } from './services/geminiService';
import Header from './components/Header';
import Overview from './components/Overview';
import SeasonalDetail from './components/SeasonalDetail';
import StatsTable from './components/StatsTable';
import Visuals from './components/Visuals';

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState<Page>(Page.OVERVIEW);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<{ message: string; type: string } | null>(null);
  const [data, setData] = useState<ClimateStats | null>(null);
  const [insights, setInsights] = useState<string>("");
  const [search, setSearch] = useState<string>("");
  const [searchResults, setSearchResults] = useState<LocationInfo[]>([]);
  const [useCoords, setUseCoords] = useState<boolean>(false);
  const [latInput, setLatInput] = useState<string>("");
  const [lngInput, setLngInput] = useState<string>("");
  const [isCooldown, setIsCooldown] = useState<boolean>(false);
  const [isSearching, setIsSearching] = useState<boolean>(false);
  const [isLocating, setIsLocating] = useState<boolean>(false);

  const searchTimeoutRef = useRef<number | null>(null);

  const loadData = async (lat: number, lng: number, name: string) => {
    setLoading(true);
    setError(null);
    try {
      const stats = await fetchClimateData(lat, lng, name);
      setData(stats);
      try {
        const text = await getClimateInsights(stats);
        setInsights(text);
      } catch (geminiErr) {
        setInsights("Climate analysis complete for " + name + ". Explore detailed historical trends below.");
      }
    } catch (err: any) {
      const msg = err.message || "Failed to retrieve climate data.";
      const type = msg.includes(":") ? msg.split(":")[0] : "GENERAL_ERROR";
      const cleanMsg = msg.includes(":") ? msg.split(":")[1].trim() : msg;

      setError({ message: cleanMsg, type });

      if (type === "RATE_LIMIT") {
        setIsCooldown(true);
        setTimeout(() => setIsCooldown(false), 30000);
      }
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadData(37.7749, -122.4194, "San Francisco, California, United States");
  }, []);

  useEffect(() => {
    if (useCoords || !search.trim() || search.trim().length < 2) {
      setSearchResults([]);
      return;
    }
    if (searchTimeoutRef.current) window.clearTimeout(searchTimeoutRef.current);
    setIsSearching(true);
    searchTimeoutRef.current = window.setTimeout(async () => {
      try {
        const results = await geocode(search);
        setSearchResults(results);
      } catch (err) {
        console.debug("Search error", err);
      } finally {
        setIsSearching(false);
      }
    }, 400);
    return () => { if (searchTimeoutRef.current) window.clearTimeout(searchTimeoutRef.current); };
  }, [search, useCoords]);

  const handleSearchSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (isCooldown) return;
    if (useCoords) {
      const lat = parseFloat(latInput);
      const lng = parseFloat(lngInput);
      if (isNaN(lat) || isNaN(lng)) {
        setError({ message: "Please enter valid numeric coordinates for Latitude and Longitude.", type: "INPUT_ERROR" });
        return;
      }
      loadData(lat, lng, `Point (${lat.toFixed(2)}, ${lng.toFixed(2)})`);
    } else {
      if (searchResults.length > 0) {
        selectLocation(searchResults[0]);
      } else if (search.trim()) {
        try {
          const results = await geocode(search);
          if (results.length > 0) selectLocation(results[0]);
          else setError({ message: `No locations found for '${search}'.`, type: "NOT_FOUND" });
        } catch (err: any) {
          setError({ message: err.message || "Search failed.", type: "SEARCH_ERROR" });
        }
      }
    }
  };

  const handleGetCurrentLocation = () => {
    if (!navigator.geolocation) {
      setError({ message: "Geolocation is not supported by your browser.", type: "PERMISSION_ERROR" });
      return;
    }

    setIsLocating(true);
    navigator.geolocation.getCurrentPosition(
      async (position) => {
        const { latitude, longitude } = position.coords;
        const locationName = await reverseGeocode(latitude, longitude);
        loadData(latitude, longitude, locationName);
        setLatInput(latitude.toFixed(4));
        setLngInput(longitude.toFixed(4));
        setSearch(locationName);
        setUseCoords(false);
        setIsLocating(false);
      },
      (err) => {
        setIsLocating(false);
        let msg = "An unknown error occurred while fetching location.";
        if (err.code === err.PERMISSION_DENIED) msg = "Location access denied. Please enable location permissions in your browser.";
        if (err.code === err.POSITION_UNAVAILABLE) msg = "Location information is unavailable.";
        if (err.code === err.TIMEOUT) msg = "Location request timed out.";
        setError({ message: msg, type: "PERMISSION_ERROR" });
      },
      { enableHighAccuracy: true, timeout: 5000, maximumAge: 0 }
    );
  };

  const selectLocation = (loc: LocationInfo) => {
    loadData(loc.lat, loc.lng, loc.name);
    setSearchResults([]);
    setSearch(loc.name);
  };

  const ErrorCard = ({ error }: { error: { message: string, type: string } }) => {
    const getSuggestions = () => {
      switch (error.type) {
        case 'OUTSIDE_GRID':
          return [
            "Search for the nearest populated city or town.",
            "Verify your coordinates (did you swap Lat and Lng?)",
            "Try a location that is definitely on land."
          ];
        case 'RATE_LIMIT':
          return [
            "Wait 30 seconds for the system to refresh.",
            "Avoid making rapid consecutive searches."
          ];
        case 'NOT_FOUND':
          return [
            "Check for spelling errors.",
            "Try adding the country name (e.g., 'Paris, France').",
            "Try searching by coordinates instead."
          ];
        default:
          return ["Try refreshing the page.", "Check your internet connection."];
      }
    };

    return (
      <div className="mb-8 bg-rose-50 border-rose-100 border-2 p-8 rounded-[2.5rem] animate-in fade-in slide-in-from-top-4 duration-500">
        <div className="flex items-start gap-5">
          <div className="bg-white p-3 rounded-2xl shadow-sm text-3xl">🧩</div>
          <div className="flex-1">
            <h3 className="font-black text-rose-900 text-lg mb-1">System Intelligence Report</h3>
            <p className="text-rose-700 text-sm font-semibold leading-relaxed mb-4">{error.message}</p>

            <div className="bg-white/50 p-5 rounded-3xl border border-rose-100/50">
              <h4 className="text-[10px] font-black uppercase tracking-widest text-rose-400 mb-3">Recommended Actions:</h4>
              <ul className="space-y-2">
                {getSuggestions().map((s, i) => (
                  <li key={i} className="flex items-start gap-2 text-xs font-bold text-rose-600">
                    <span className="text-rose-300">•</span>
                    {s}
                  </li>
                ))}
              </ul>
            </div>
          </div>
          <button onClick={() => setError(null)} className="text-rose-300 hover:text-rose-600 transition-colors p-2">✕</button>
        </div>
      </div>
    );
  };

  return (
    <div className="max-w-6xl mx-auto px-4 pb-20 pt-6">
      <div className="mb-8 flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div>
          <h1 className="text-4xl font-black text-slate-800 tracking-tighter flex items-center gap-2">
            <span className="bg-blue-600 text-white p-2 rounded-2xl rotate-3 shadow-lg">🌍</span>
            ClimaIntel
          </h1>
          <p className="text-slate-500 text-xs font-black uppercase tracking-widest mt-1 ml-1">Global Climate Intelligence</p>
        </div>

        <div className="w-full md:w-auto">
          <div className="flex bg-slate-100 p-1 rounded-2xl mb-3 w-fit ml-auto md:ml-0">
            <button 
              onClick={() => setUseCoords(false)}
              className={`px-4 py-1.5 rounded-xl text-[11px] font-black uppercase tracking-wider transition-all ${!useCoords ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
            >
              Search Place
            </button>
            <button 
              onClick={() => setUseCoords(true)}
              className={`px-4 py-1.5 rounded-xl text-[11px] font-black uppercase tracking-wider transition-all ${useCoords ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
            >
              Coordinates
            </button>
          </div>

          <div className="relative">
            <div className="flex gap-2">
              <div className="flex-1 flex gap-2">
                <div className="relative flex-1">
                  {!useCoords ? (
                    <div className="relative">
                      <input 
                        type="text" 
                        value={search}
                        onChange={(e) => setSearch(e.target.value)}
                        placeholder="Enter city name..." 
                        className="px-5 py-3.5 rounded-2xl border border-slate-200 focus:outline-none focus:ring-4 focus:ring-blue-100 w-full md:w-80 shadow-sm font-medium disabled:bg-slate-50"
                        disabled={isCooldown}
                      />
                      {isSearching && (
                        <div className="absolute right-4 top-1/2 -translate-y-1/2">
                          <div className="w-4 h-4 border-2 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
                        </div>
                      )}
                    </div>
                  ) : (
                    <div className="flex gap-2">
                      <input 
                        type="text" 
                        placeholder="Lat" 
                        value={latInput}
                        onChange={(e) => setLatInput(e.target.value)}
                        className="w-24 px-4 py-3.5 rounded-2xl border border-slate-200 focus:outline-none focus:ring-4 focus:ring-blue-100 shadow-sm font-mono text-sm"
                      />
                      <input 
                        type="text" 
                        placeholder="Lng" 
                        value={lngInput}
                        onChange={(e) => setLngInput(e.target.value)}
                        className="w-24 px-4 py-3.5 rounded-2xl border border-slate-200 focus:outline-none focus:ring-4 focus:ring-blue-100 shadow-sm font-mono text-sm"
                      />
                    </div>
                  )}
                </div>
                <button 
                  onClick={handleSearchSubmit}
                  disabled={isCooldown}
                  className={`${isCooldown ? 'bg-slate-400 cursor-not-allowed' : 'bg-slate-900 hover:bg-black active:scale-95'} text-white px-6 py-3.5 rounded-2xl transition-all shadow-xl font-bold flex items-center justify-center min-w-[100px]`}
                >
                  Analyze
                </button>
              </div>
              <button
                type="button"
                onClick={handleGetCurrentLocation}
                disabled={isLocating || isCooldown}
                className={`px-4 py-3.5 rounded-2xl border transition-all shadow-md flex items-center justify-center ${
                  isLocating 
                    ? 'bg-blue-50 border-blue-200 text-blue-600' 
                    : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50 active:scale-95'
                }`}
                title="Detect My Location & Analyze"
              >
                {isLocating ? (
                  <div className="w-5 h-5 border-2 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
                ) : (
                  <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"></path><circle cx="12" cy="10" r="3"></circle></svg>
                )}
              </button>
            </div>

            {searchResults.length > 0 && !useCoords && (
              <div className="absolute top-full left-0 right-0 bg-white shadow-2xl rounded-3xl mt-2 z-50 border border-slate-100 overflow-hidden max-h-[300px] overflow-y-auto scrollbar-hide">
                {searchResults.map((loc, i) => (
                  <button 
                    key={i} 
                    onClick={() => selectLocation(loc)}
                    className="w-full text-left px-5 py-4 hover:bg-blue-50/50 transition border-b border-slate-50 last:border-none"
                  >
                    <span className="font-bold text-slate-800 block text-sm">{loc.name}</span>
                    <span className="text-[10px] text-slate-400 font-mono">{loc.lat.toFixed(3)}°N, {loc.lng.toFixed(3)}°E</span>
                  </button>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>

      {isCooldown && (
        <div className="mb-6 bg-amber-50 border-amber-100 border p-4 rounded-2xl flex items-center gap-3">
          <span className="animate-pulse">⏳</span>
          <p className="text-amber-800 text-xs font-black uppercase tracking-wider">Cooling down to prevent rate limits... Please wait.</p>
        </div>
      )}

      {error && <ErrorCard error={error} />}

      {loading && !data ? (
        <div className="flex flex-col items-center justify-center py-40">
           <div className="relative">
             <div className="animate-spin rounded-full h-20 w-20 border-t-4 border-blue-600 mb-6"></div>
             <div className="absolute inset-0 flex items-center justify-center text-xl">📡</div>
           </div>
           <p className="text-slate-800 font-black text-2xl tracking-tight">Syncing Climate Records...</p>
           <p className="text-slate-400 text-sm font-medium mt-2">Accessing historical reanalysis grids for this location.</p>
        </div>
      ) : data && (
        <>
          <Header data={data} insights={insights} />

          <nav className="flex overflow-x-auto gap-2 mb-10 bg-white/60 p-2 rounded-[2.5rem] shadow-sm border border-slate-200/50 scrollbar-hide sticky top-4 z-40 backdrop-blur-xl">
            {[
              { id: Page.OVERVIEW, label: "Overview", icon: "🌎" },
              { id: Page.SUNNY, label: "Sunny", icon: "☀️" },
              { id: Page.RAINY, label: "Rainy", icon: "🌧️" },
              { id: Page.WINTER, label: "Winter", icon: "❄️" },
              { id: Page.STATS, label: "Data", icon: "📊" },
              { id: Page.GRAPHS, label: "Graphs", icon: "📈" },
            ].map(tab => (
              <button
                key={tab.id}
                onClick={() => setCurrentPage(tab.id as Page)}
                className={`flex items-center gap-2 px-6 py-4 rounded-[1.8rem] whitespace-nowrap transition-all ${
                  currentPage === tab.id 
                    ? 'bg-slate-900 text-white shadow-2xl -translate-y-1' 
                    : 'text-slate-600 hover:bg-white font-bold text-sm'
                }`}
              >
                <span className="text-xl">{tab.icon}</span>
                <span className="font-black tracking-tight">{tab.label}</span>
              </button>
            ))}
          </nav>

          <main className="fade-in">
            {currentPage === Page.OVERVIEW && <Overview data={data} />}
            {currentPage === Page.SUNNY && <SeasonalDetail data={data} type="sunny" />}
            {currentPage === Page.RAINY && <SeasonalDetail data={data} type="rainy" />}
            {currentPage === Page.WINTER && <SeasonalDetail data={data} type="winter" />}
            {currentPage === Page.STATS && <StatsTable data={data} />}
            {currentPage === Page.GRAPHS && <Visuals data={data} />}
          </main>
        </>
      )}
    </div>
  );
};

export default App;

import { ClimateStats, MonthlyClimateData, LocationInfo } from '../types';

const MONTH_NAMES = [
  "January", "February", "March", "April", "May", "June",
  "July", "August", "September", "October", "November", "December"
];

const CLIMATE_THRESHOLDS = {
  WINTER_MAX_TEMP: 15,
  RAINY_MIN_PRECIP: 60,
  RAINY_MIN_DAYS: 10,
  SUNNY_MIN_SOLAR: 22,
  SUNNY_MAX_PRECIP: 40,
  WINDY_MIN_SPEED: 14.5,
};

const CACHE_PREFIX = 'climatintel_cache_';

/**
 * Normalizes coordinates to a 2-decimal precision string for consistent caching.
 */
const getCacheKey = (lat: number, lng: number) => `${lat.toFixed(2)}_${lng.toFixed(2)}`;

/**
 * Retrieves cached climate data from localStorage if available and not expired (24h).
 */
function getCachedData(lat: number, lng: number): ClimateStats | null {
  const key = CACHE_PREFIX + getCacheKey(lat, lng);
  const cached = localStorage.getItem(key);
  if (!cached) return null;

  try {
    const entry = JSON.parse(cached);
    const now = new Date().getTime();
    // 24 hour cache expiration
    if (now - entry.timestamp > 24 * 60 * 60 * 1000) {
      localStorage.removeItem(key);
      return null;
    }
    return entry.data;
  } catch (e) {
    return null;
  }
}

/**
 * Saves processed climate data to localStorage.
 */
function setCachedData(lat: number, lng: number, data: ClimateStats) {
  const key = CACHE_PREFIX + getCacheKey(lat, lng);
  const entry = {
    timestamp: new Date().getTime(),
    data
  };
  try {
    localStorage.setItem(key, JSON.stringify(entry));
  } catch (e) {
    // If storage is full, clear old cache entries
    console.warn("LocalStorage full, clearing climate cache");
    Object.keys(localStorage).forEach(k => {
      if (k.startsWith(CACHE_PREFIX)) localStorage.removeItem(k);
    });
  }
}

export function degToCardinal(deg: number): string {
  const directions = ['N', 'NE', 'E', 'SE', 'S', 'SW', 'W', 'NW'];
  const index = Math.round(deg / 45) % 8;
  return directions[index];
}

export async function geocode(query: string): Promise<LocationInfo[]> {
  if (!query || query.trim().length < 2) return [];

  try {
    const url = `https://geocoding-api.open-meteo.com/v1/search?name=${encodeURIComponent(query.trim())}&count=10&language=en&format=json`;
    const response = await fetch(url);

    if (response.status === 429) throw new Error("RATE_LIMIT: Search limit reached. Please wait.");
    if (!response.ok) throw new Error("SERVICE_UNAVAILABLE: Search service unavailable.");

    const data = await response.json();
    if (!data.results) return [];

    return data.results.map((r: any) => ({
      name: `${r.name}${r.admin1 ? ', ' + r.admin1 : ''}, ${r.country}`,
      lat: r.latitude,
      lng: r.longitude,
      country: r.country,
    }));
  } catch (err: any) {
    throw err;
  }
}

export async function reverseGeocode(lat: number, lng: number): Promise<string> {
  try {
    const url = `https://nominatim.openstreetmap.org/reverse?lat=${lat}&lon=${lng}&format=json&zoom=10`;
    const response = await fetch(url, { headers: { 'Accept-Language': 'en' } });
    if (!response.ok) return `${lat.toFixed(2)}, ${lng.toFixed(2)}`;
    const data = await response.json();
    return data.display_name || `${lat.toFixed(2)}, ${lng.toFixed(2)}`;
  } catch (err) {
    return `${lat.toFixed(2)}, ${lng.toFixed(2)}`;
  }
}

async function fetchWithRetry(lat: number, lng: number): Promise<any> {
  const end = new Date();
  const start = new Date();
  // Reducing from 10 years to 7 years to reduce payload size and API pressure
  start.setFullYear(end.getFullYear() - 7);
  const fmt = (d: Date) => d.toISOString().split('T')[0];

  const params = [
    'temperature_2m_max',
    'temperature_2m_min',
    'temperature_2m_mean',
    'precipitation_sum',
    'shortwave_radiation_sum',
    'windspeed_10m_max',
    'wind_direction_10m_dominant',
    'relative_humidity_2m_mean',
    'uv_index_max'
  ].join(',');

  const url = `https://archive-api.open-meteo.com/v1/archive?latitude=${lat}&longitude=${lng}&start_date=${fmt(start)}&end_date=${fmt(end)}&daily=${params}&timezone=auto`;

  const response = await fetch(url);

  if (response.status === 429) {
    throw new Error("RATE_LIMIT: The Climate API is under heavy load. We've retrieved data from cache where possible, but new locations need a 60-second break.");
  }

  if (!response.ok) {
    if (response.status === 400) throw new Error("OUTSIDE_GRID: Location not in historical records (e.g. Deep Ocean).");
    throw new Error(`API_ERROR: HTTP ${response.status}`);
  }
  return await response.json();
}

export async function fetchClimateData(lat: number, lng: number, locationName?: string): Promise<ClimateStats> {
  const cached = getCachedData(lat, lng);
  if (cached) {
    console.log("Serving from local cache for:", locationName);
    return { ...cached, location: { ...cached.location, name: locationName || cached.location.name } };
  }

  const raw = await fetchWithRetry(lat, lng);
  if (!raw.daily) throw new Error("NO_DATA: No historical records found.");

  const daily = raw.daily;
  const time = daily.time;
  const monthBuckets = Array.from({ length: 12 }, () => ({
    tempMax: [] as number[],
    tempMin: [] as number[],
    tempMean: [] as number[],
    rain: [] as number[],
    solar: [] as number[],
    uv: [] as number[],
    wind: [] as number[],
    windDirs: [] as number[],
    humidity: [] as number[],
    rainyDaysCount: 0
  }));

  for (let i = 0; i < time.length; i++) {
    const month = parseInt(time[i].substring(5, 7), 10) - 1;
    const bucket = monthBuckets[month];
    if (daily.temperature_2m_max[i] != null) bucket.tempMax.push(daily.temperature_2m_max[i]);
    if (daily.temperature_2m_min[i] != null) bucket.tempMin.push(daily.temperature_2m_min[i]);
    if (daily.temperature_2m_mean[i] != null) bucket.tempMean.push(daily.temperature_2m_mean[i]);
    if (daily.precipitation_sum[i] != null) {
      bucket.rain.push(daily.precipitation_sum[i]);
      if (daily.precipitation_sum[i] >= 1.0) bucket.rainyDaysCount++;
    }
    if (daily.shortwave_radiation_sum[i] != null) bucket.solar.push(daily.shortwave_radiation_sum[i]);
    if (daily.uv_index_max && daily.uv_index_max[i] != null) bucket.uv.push(daily.uv_index_max[i]);
    if (daily.windspeed_10m_max[i] != null) bucket.wind.push(daily.windspeed_10m_max[i]);
    if (daily.wind_direction_10m_dominant[i] != null) bucket.windDirs.push(daily.wind_direction_10m_dominant[i]);
    if (daily.relative_humidity_2m_mean[i] != null) bucket.humidity.push(daily.relative_humidity_2m_mean[i]);
  }

  const yearsProcessed = 7;
  const initialMonthlyData: MonthlyClimateData[] = monthBuckets.map((b, idx) => {
    const avg = (arr: number[]) => arr.length ? arr.reduce((a, c) => a + c, 0) / arr.length : 0;
    const max = (arr: number[]) => arr.length ? Math.max(...arr) : 0;
    const min = (arr: number[]) => arr.length ? Math.min(...arr) : 0;

    const cardinalCounts: Record<string, number> = {};
    b.windDirs.forEach(d => {
      const c = degToCardinal(d);
      cardinalCounts[c] = (cardinalCounts[c] || 0) + 1;
    });
    const prevailingCardinal = Object.entries(cardinalCounts).sort((a,b) => b[1] - a[1])[0]?.[0] || 'N';
    const cardinalToDeg: Record<string, number> = { 'N': 0, 'NE': 45, 'E': 90, 'SE': 135, 'S': 180, 'SW': 225, 'W': 270, 'NW': 315 };

    const tAvg = avg(b.tempMean);
    const rh = avg(b.humidity);
    const rain = b.rain.reduce((a,c)=>a+c,0) / yearsProcessed;
    const solar = avg(b.solar);
    const wind = avg(b.wind);

    return {
      month: MONTH_NAMES[idx],
      monthIdx: idx,
      tempAvg: parseFloat(tAvg.toFixed(1)),
      tempMax: parseFloat(max(b.tempMax).toFixed(1)),
      tempMin: parseFloat(min(b.tempMin).toFixed(1)),
      rainfall: parseFloat(rain.toFixed(1)),
      rainyDays: Math.round(b.rainyDaysCount / yearsProcessed),
      humidity: parseFloat(rh.toFixed(1)),
      humidityMax: parseFloat(max(b.humidity).toFixed(1)),
      humidityMin: parseFloat(min(b.humidity).toFixed(1)),
      windSpeed: parseFloat(wind.toFixed(1)),
      windMax: parseFloat(max(b.wind).toFixed(1)),
      windDir: cardinalToDeg[prevailingCardinal], 
      solarIntensity: parseFloat(solar.toFixed(1)),
      peakSunHours: parseFloat((solar / 3.6).toFixed(1)),
      uvIndex: parseFloat(avg(b.uv).toFixed(1)),
      heatIndex: parseFloat((tAvg + (rh > 60 ? 0.5 * (rh - 60) : 0)).toFixed(1)),
      isSunny: solar >= CLIMATE_THRESHOLDS.SUNNY_MIN_SOLAR && rain < CLIMATE_THRESHOLDS.SUNNY_MAX_PRECIP,
      isRainy: rain >= CLIMATE_THRESHOLDS.RAINY_MIN_PRECIP || (b.rainyDaysCount / yearsProcessed) >= CLIMATE_THRESHOLDS.RAINY_MIN_DAYS,
      isWinter: tAvg <= CLIMATE_THRESHOLDS.WINTER_MAX_TEMP,
      isWindy: wind >= CLIMATE_THRESHOLDS.WINDY_MIN_SPEED
    };
  });

  // Relative seasonal fallbacks
  const hasWinter = initialMonthlyData.some(m => m.isWinter);
  const hasRainy = initialMonthlyData.some(m => m.isRainy);
  const hasSunny = initialMonthlyData.some(m => m.isSunny);
  const hasWindy = initialMonthlyData.some(m => m.isWindy);

  const sortedByTemp = [...initialMonthlyData].sort((a, b) => a.tempAvg - b.tempAvg);
  const sortedByRain = [...initialMonthlyData].sort((a, b) => b.rainfall - a.rainfall);
  const sortedBySolar = [...initialMonthlyData].sort((a, b) => b.solarIntensity - a.solarIntensity);
  const sortedByWind = [...initialMonthlyData].sort((a, b) => b.windSpeed - a.windSpeed);

  const finalMonthlyData = initialMonthlyData.map(m => ({
    ...m,
    isWinter: hasWinter ? m.isWinter : sortedByTemp.slice(0, 3).some(sm => sm.monthIdx === m.monthIdx),
    isRainy: hasRainy ? m.isRainy : sortedByRain.slice(0, 3).some(sm => sm.monthIdx === m.monthIdx),
    isSunny: hasSunny ? m.isSunny : sortedBySolar.slice(0, 3).some(sm => sm.monthIdx === m.monthIdx),
    isWindy: hasWindy ? m.isWindy : sortedByWind.slice(0, 3).some(sm => sm.monthIdx === m.monthIdx),
  }));

  const result: ClimateStats = {
    location: { name: locationName || "Location", lat, lng },
    period: "7-Year ERA5 Baseline",
    reliabilityScore: 99.8,
    monthlyData: finalMonthlyData,
    summary: {
      hottestMonth: sortedByTemp[11].month,
      coldestMonth: sortedByTemp[0].month,
      rainiestMonth: sortedByRain[0].month,
      sunniestMonth: sortedBySolar[0].month,
    }
  };

  setCachedData(lat, lng, result);
  return result;
}

import React, { useState, useEffect, useRef } from 'react';
import { Page, ClimateStats, LocationInfo } from './types';
import { fetchClimateData, geocode, reverseGeocode } from './services/climateService';
import { getClimateInsights } from './services/geminiService';
import Header from './components/Header';
import Overview from './components/Overview';
import SeasonalDetail from './components/SeasonalDetail';
import StatsTable from './components/StatsTable';
import Visuals from './components/Visuals';

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState<Page>(Page.OVERVIEW);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<{ message: string; type: string } | null>(null);
  const [data, setData] = useState<ClimateStats | null>(null);
  const [insights, setInsights] = useState<string>("");
  const [search, setSearch] = useState<string>("");
  const [searchResults, setSearchResults] = useState<LocationInfo[]>([]);
  const [useCoords, setUseCoords] = useState<boolean>(false);
  const [latInput, setLatInput] = useState<string>("");
  const [lngInput, setLngInput] = useState<string>("");
  const [cooldownTime, setCooldownTime] = useState<number>(0);
  const [isSearching, setIsSearching] = useState<boolean>(false);
  const [isLocating, setIsLocating] = useState<boolean>(false);

  const searchTimeoutRef = useRef<number | null>(null);
  const cooldownTimerRef = useRef<number | null>(null);

  const loadData = async (lat: number, lng: number, name: string) => {
    setLoading(true);
    setError(null);
    try {
      const stats = await fetchClimateData(lat, lng, name);
      setData(stats);
      try {
        const text = await getClimateInsights(stats);
        setInsights(text);
      } catch (geminiErr) {
        setInsights(`Historical overview for ${name} based on long-term climate grids.`);
      }
    } catch (err: any) {
      const msg = err.message || "Failed to retrieve climate data.";
      const type = msg.includes(":") ? msg.split(":")[0] : "GENERAL_ERROR";
      const cleanMsg = msg.includes(":") ? msg.split(":")[1].trim() : msg;

      setError({ message: cleanMsg, type });

      if (type === "RATE_LIMIT") {
        setCooldownTime(30);
      }
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    // Initial load: San Francisco
    loadData(37.7749, -122.4194, "San Francisco, CA, United States");
  }, []);

  useEffect(() => {
    if (cooldownTime > 0) {
      cooldownTimerRef.current = window.setInterval(() => {
        setCooldownTime(prev => prev - 1);
      }, 1000);
    } else {
      if (cooldownTimerRef.current) clearInterval(cooldownTimerRef.current);
    }
    return () => { if (cooldownTimerRef.current) clearInterval(cooldownTimerRef.current); };
  }, [cooldownTime]);

  useEffect(() => {
    if (useCoords || !search.trim() || search.trim().length < 2) {
      setSearchResults([]);
      return;
    }
    if (searchTimeoutRef.current) window.clearTimeout(searchTimeoutRef.current);
    setIsSearching(true);
    searchTimeoutRef.current = window.setTimeout(async () => {
      try {
        const results = await geocode(search);
        setSearchResults(results);
      } catch (err) {
        console.debug("Search error", err);
      } finally {
        setIsSearching(false);
      }
    }, 400);
    return () => { if (searchTimeoutRef.current) window.clearTimeout(searchTimeoutRef.current); };
  }, [search, useCoords]);

  const handleSearchSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (cooldownTime > 0) return;
    if (useCoords) {
      const lat = parseFloat(latInput);
      const lng = parseFloat(lngInput);
      if (isNaN(lat) || isNaN(lng)) {
        setError({ message: "Enter valid coordinates.", type: "INPUT_ERROR" });
        return;
      }
      loadData(lat, lng, `Coordinates (${lat.toFixed(2)}, ${lng.toFixed(2)})`);
    } else {
      if (searchResults.length > 0) {
        selectLocation(searchResults[0]);
      } else if (search.trim()) {
        try {
          const results = await geocode(search);
          if (results.length > 0) selectLocation(results[0]);
          else setError({ message: `No locations found for '${search}'.`, type: "NOT_FOUND" });
        } catch (err: any) {
          setError({ message: err.message || "Search failed.", type: "SEARCH_ERROR" });
        }
      }
    }
  };

  const handleGetCurrentLocation = () => {
    if (!navigator.geolocation) {
      setError({ message: "Geolocation not supported.", type: "PERMISSION_ERROR" });
      return;
    }
    setIsLocating(true);
    navigator.geolocation.getCurrentPosition(
      async (position) => {
        const { latitude, longitude } = position.coords;
        const locationName = await reverseGeocode(latitude, longitude);
        loadData(latitude, longitude, locationName);
        setLatInput(latitude.toFixed(4));
        setLngInput(longitude.toFixed(4));
        setSearch(locationName);
        setUseCoords(false);
        setIsLocating(false);
      },
      () => {
        setIsLocating(false);
        setError({ message: "Location access denied or unavailable.", type: "PERMISSION_ERROR" });
      }
    );
  };

  const selectLocation = (loc: LocationInfo) => {
    loadData(loc.lat, loc.lng, loc.name);
    setSearchResults([]);
    setSearch(loc.name);
  };

  const ErrorCard = ({ error }: { error: { message: string, type: string } }) => {
    return (
      <div className="mb-8 bg-rose-50 border-rose-100 border-2 p-8 rounded-[2.5rem] fade-in">
        <div className="flex items-start gap-5">
          <div className="bg-white p-3 rounded-2xl shadow-sm text-3xl">📡</div>
          <div className="flex-1">
            <h3 className="font-black text-rose-900 text-lg mb-1">Status Report</h3>
            <p className="text-rose-700 text-sm font-semibold leading-relaxed mb-4">{error.message}</p>
            {error.type === 'RATE_LIMIT' && (
              <div className="bg-rose-500 text-white px-4 py-2 rounded-xl text-xs font-black inline-block animate-pulse">
                Retry in {cooldownTime}s
              </div>
            )}
          </div>
          <button onClick={() => setError(null)} className="text-rose-300 hover:text-rose-600 p-2">✕</button>
        </div>
      </div>
    );
  };

  return (
    <div className="max-w-6xl mx-auto px-4 pb-20 pt-6">
      <div className="mb-8 flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div>
          <h1 className="text-4xl font-black text-slate-800 tracking-tighter flex items-center gap-2">
            <span className="bg-blue-600 text-white p-2 rounded-2xl rotate-3 shadow-lg">🌍</span>
            ClimaIntel
          </h1>
          <p className="text-slate-500 text-xs font-black uppercase tracking-widest mt-1 ml-1">Global Climate Intelligence</p>
        </div>

        <div className="w-full md:w-auto">
          <div className="flex bg-slate-100 p-1 rounded-2xl mb-3 w-fit ml-auto md:ml-0">
            <button onClick={() => setUseCoords(false)} className={`px-4 py-1.5 rounded-xl text-[11px] font-black uppercase tracking-wider transition-all ${!useCoords ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-400'}`}>Search</button>
            <button onClick={() => setUseCoords(true)} className={`px-4 py-1.5 rounded-xl text-[11px] font-black uppercase tracking-wider transition-all ${useCoords ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-400'}`}>Coords</button>
          </div>

          <div className="relative">
            <div className="flex gap-2">
              <div className="flex-1 flex gap-2">
                {!useCoords ? (
                  <div className="relative flex-1">
                    <input 
                      type="text" 
                      value={search}
                      onChange={(e) => setSearch(e.target.value)}
                      placeholder="Enter city..." 
                      className="px-5 py-3.5 rounded-2xl border border-slate-200 w-full md:w-80 shadow-sm font-medium"
                    />
                    {isSearching && <div className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 border-2 border-blue-600 border-t-transparent rounded-full animate-spin"></div>}
                  </div>
                ) : (
                  <div className="flex gap-2">
                    <input type="text" placeholder="Lat" value={latInput} onChange={(e) => setLatInput(e.target.value)} className="w-24 px-4 py-3.5 rounded-2xl border border-slate-200 shadow-sm font-mono text-sm" />
                    <input type="text" placeholder="Lng" value={lngInput} onChange={(e) => setLngInput(e.target.value)} className="w-24 px-4 py-3.5 rounded-2xl border border-slate-200 shadow-sm font-mono text-sm" />
                  </div>
                )}
                <button 
                  onClick={handleSearchSubmit}
                  disabled={cooldownTime > 0}
                  className={`${cooldownTime > 0 ? 'bg-slate-300' : 'bg-slate-900 hover:bg-black active:scale-95'} text-white px-6 py-3.5 rounded-2xl transition-all shadow-xl font-bold min-w-[100px]`}
                >
                  {cooldownTime > 0 ? `${cooldownTime}s` : 'Analyze'}
                </button>
              </div>
              <button onClick={handleGetCurrentLocation} disabled={isLocating || cooldownTime > 0} className="px-4 py-3.5 rounded-2xl border bg-white border-slate-200 text-slate-600 hover:bg-slate-50 active:scale-95 shadow-md">
                {isLocating ? <div className="w-5 h-5 border-2 border-blue-600 border-t-transparent rounded-full animate-spin"></div> : "📍"}
              </button>
            </div>
            {searchResults.length > 0 && !useCoords && (
              <div className="absolute top-full left-0 right-0 bg-white shadow-2xl rounded-3xl mt-2 z-50 border border-slate-100 overflow-hidden max-h-[300px] overflow-y-auto">
                {searchResults.map((loc, i) => (
                  <button key={i} onClick={() => selectLocation(loc)} className="w-full text-left px-5 py-4 hover:bg-blue-50 transition border-b border-slate-50 last:border-none">
                    <span className="font-bold text-slate-800 block text-sm">{loc.name}</span>
                    <span className="text-[10px] text-slate-400 font-mono">{loc.lat.toFixed(2)}, {loc.lng.toFixed(2)}</span>
                  </button>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>

      {error && <ErrorCard error={error} />}

      {loading && !data ? (
        <div className="flex flex-col items-center justify-center py-40">
           <div className="animate-spin rounded-full h-16 w-16 border-t-4 border-blue-600 mb-6"></div>
           <p className="text-slate-800 font-black text-2xl">Retrieving Climate Grids...</p>
        </div>
      ) : data && (
        <>
          <Header data={data} insights={insights} />
          <nav className="flex overflow-x-auto gap-2 mb-10 bg-white/60 p-2 rounded-[2.5rem] shadow-sm border border-slate-200/50 scrollbar-hide sticky top-4 z-40 backdrop-blur-xl">
            {[
              { id: Page.OVERVIEW, label: "Overview", icon: "🌎" },
              { id: Page.SUNNY, label: "Sunny", icon: "☀️" },
              { id: Page.RAINY, label: "Rainy", icon: "🌧️" },
              { id: Page.WINTER, label: "Winter", icon: "❄️" },
              { id: Page.STATS, label: "Data", icon: "📊" },
              { id: Page.GRAPHS, label: "Graphs", icon: "📈" },
            ].map(tab => (
              <button key={tab.id} onClick={() => setCurrentPage(tab.id as Page)} className={`flex items-center gap-2 px-6 py-4 rounded-[1.8rem] transition-all ${currentPage === tab.id ? 'bg-slate-900 text-white shadow-2xl -translate-y-1' : 'text-slate-600 hover:bg-white font-bold text-sm'}`}>
                <span className="text-xl">{tab.icon}</span>
                <span className="font-black tracking-tight">{tab.label}</span>
              </button>
            ))}
          </nav>
          <main className="fade-in">
            {currentPage === Page.OVERVIEW && <Overview data={data} />}
            {currentPage === Page.SUNNY && <SeasonalDetail data={data} type="sunny" />}
            {currentPage === Page.RAINY && <SeasonalDetail data={data} type="rainy" />}
            {currentPage === Page.WINTER && <SeasonalDetail data={data} type="winter" />}
            {currentPage === Page.STATS && <StatsTable data={data} />}
            {currentPage === Page.GRAPHS && <Visuals data={data} />}
          </main>
        </>
      )}
    </div>
  );
};

export default App;

import { ClimateStats, MonthlyClimateData, LocationInfo } from '../types';

const MONTH_NAMES = [
  "January", "February", "March", "April", "May", "June",
  "July", "August", "September", "October", "November", "December"
];

const CLIMATE_THRESHOLDS = {
  WINTER_MAX_TEMP: 15,
  RAINY_MIN_PRECIP: 60,
  RAINY_MIN_DAYS: 10,
  SUNNY_MIN_SOLAR: 22,
  SUNNY_MAX_PRECIP: 40,
  WINDY_MIN_SPEED: 14.5,
};

const CACHE_PREFIX = 'climatintel_cache_';

/**
 * Normalizes coordinates to a 2-decimal precision string for consistent caching.
 */
const getCacheKey = (lat: number, lng: number) => `${lat.toFixed(2)}_${lng.toFixed(2)}`;

/**
 * Retrieves cached climate data from localStorage if available and not expired (24h).
 */
function getCachedData(lat: number, lng: number): ClimateStats | null {
  const key = CACHE_PREFIX + getCacheKey(lat, lng);
  const cached = localStorage.getItem(key);
  if (!cached) return null;

  try {
    const entry = JSON.parse(cached);
    const now = new Date().getTime();
    // 24 hour cache expiration
    if (now - entry.timestamp > 24 * 60 * 60 * 1000) {
      localStorage.removeItem(key);
      return null;
    }
    return entry.data;
  } catch (e) {
    return null;
  }
}

/**
 * Saves processed climate data to localStorage.
 */
function setCachedData(lat: number, lng: number, data: ClimateStats) {
  const key = CACHE_PREFIX + getCacheKey(lat, lng);
  const entry = {
    timestamp: new Date().getTime(),
    data
  };
  try {
    localStorage.setItem(key, JSON.stringify(entry));
  } catch (e) {
    // If storage is full, clear old cache entries
    console.warn("LocalStorage full, clearing climate cache");
    Object.keys(localStorage).forEach(k => {
      if (k.startsWith(CACHE_PREFIX)) localStorage.removeItem(k);
    });
  }
}

export function degToCardinal(deg: number): string {
  const directions = ['N', 'NE', 'E', 'SE', 'S', 'SW', 'W', 'NW'];
  const index = Math.round(deg / 45) % 8;
  return directions[index];
}

/**
 * Enhanced Geocode search with smart fallbacks.
 */
export async function geocode(query: string): Promise<LocationInfo[]> {
  const sanitized = query.trim();
  if (!sanitized || sanitized.length < 2) return [];

  const performSearch = async (term: string): Promise<LocationInfo[]> => {
    const url = `https://geocoding-api.open-meteo.com/v1/search?name=${encodeURIComponent(term)}&count=10&language=en&format=json`;
    const response = await fetch(url);

    if (response.status === 429) throw new Error("RATE_LIMIT: Search limit reached. Please wait.");
    if (!response.ok) throw new Error("SERVICE_UNAVAILABLE: Search service unavailable.");

    const data = await response.json();
    if (!data.results) return [];

    return data.results.map((r: any) => ({
      name: `${r.name}${r.admin1 ? ', ' + r.admin1 : ''}${r.country ? ', ' + r.country : ''}`,
      lat: r.latitude,
      lng: r.longitude,
      country: r.country,
    }));
  };

  try {
    // Try primary search
    let results = await performSearch(sanitized);

    // If no results and query contains commas, try searching for just the first part (the city)
    if (results.length === 0 && sanitized.includes(',')) {
      const parts = sanitized.split(',').map(p => p.trim()).filter(p => p.length > 0);
      if (parts.length > 0) {
        results = await performSearch(parts[0]);
      }
    }

    return results;
  } catch (err: any) {
    throw err;
  }
}

export async function reverseGeocode(lat: number, lng: number): Promise<string> {
  try {
    const url = `https://nominatim.openstreetmap.org/reverse?lat=${lat}&lon=${lng}&format=json&zoom=10`;
    const response = await fetch(url, { headers: { 'Accept-Language': 'en' } });
    if (!response.ok) return `${lat.toFixed(2)}, ${lng.toFixed(2)}`;
    const data = await response.json();
    return data.display_name || `${lat.toFixed(2)}, ${lng.toFixed(2)}`;
  } catch (err) {
    return `${lat.toFixed(2)}, ${lng.toFixed(2)}`;
  }
}

async function fetchWithRetry(lat: number, lng: number): Promise<any> {
  const end = new Date();
  const start = new Date();
  // Reducing from 10 years to 7 years to reduce payload size and API pressure
  start.setFullYear(end.getFullYear() - 7);
  const fmt = (d: Date) => d.toISOString().split('T')[0];

  const params = [
    'temperature_2m_max',
    'temperature_2m_min',
    'temperature_2m_mean',
    'precipitation_sum',
    'shortwave_radiation_sum',
    'windspeed_10m_max',
    'wind_direction_10m_dominant',
    'relative_humidity_2m_mean',
    'uv_index_max'
  ].join(',');

  const url = `https://archive-api.open-meteo.com/v1/archive?latitude=${lat}&longitude=${lng}&start_date=${fmt(start)}&end_date=${fmt(end)}&daily=${params}&timezone=auto`;

  const response = await fetch(url);

  if (response.status === 429) {
    throw new Error("RATE_LIMIT: The Climate API is under heavy load. We've retrieved data from cache where possible, but new locations need a 60-second break.");
  }

  if (!response.ok) {
    if (response.status === 400) throw new Error("OUTSIDE_GRID: Location not in historical records (e.g. Deep Ocean).");
    throw new Error(`API_ERROR: HTTP ${response.status}`);
  }
  return await response.json();
}

export async function fetchClimateData(lat: number, lng: number, locationName?: string): Promise<ClimateStats> {
  const cached = getCachedData(lat, lng);
  if (cached) {
    console.log("Serving from local cache for:", locationName);
    return { ...cached, location: { ...cached.location, name: locationName || cached.location.name } };
  }

  const raw = await fetchWithRetry(lat, lng);
  if (!raw.daily) throw new Error("NO_DATA: No historical records found.");

  const daily = raw.daily;
  const time = daily.time;
  const monthBuckets = Array.from({ length: 12 }, () => ({
    tempMax: [] as number[],
    tempMin: [] as number[],
    tempMean: [] as number[],
    rain: [] as number[],
    solar: [] as number[],
    uv: [] as number[],
    wind: [] as number[],
    windDirs: [] as number[],
    humidity: [] as number[],
    rainyDaysCount: 0
  }));

  for (let i = 0; i < time.length; i++) {
    const month = parseInt(time[i].substring(5, 7), 10) - 1;
    const bucket = monthBuckets[month];
    if (daily.temperature_2m_max[i] != null) bucket.tempMax.push(daily.temperature_2m_max[i]);
    if (daily.temperature_2m_min[i] != null) bucket.tempMin.push(daily.temperature_2m_min[i]);
    if (daily.temperature_2m_mean[i] != null) bucket.tempMean.push(daily.temperature_2m_mean[i]);
    if (daily.precipitation_sum[i] != null) {
      bucket.rain.push(daily.precipitation_sum[i]);
      if (daily.precipitation_sum[i] >= 1.0) bucket.rainyDaysCount++;
    }
    if (daily.shortwave_radiation_sum[i] != null) bucket.solar.push(daily.shortwave_radiation_sum[i]);
    if (daily.uv_index_max && daily.uv_index_max[i] != null) bucket.uv.push(daily.uv_index_max[i]);
    if (daily.windspeed_10m_max[i] != null) bucket.wind.push(daily.windspeed_10m_max[i]);
    if (daily.wind_direction_10m_dominant[i] != null) bucket.windDirs.push(daily.wind_direction_10m_dominant[i]);
    if (daily.relative_humidity_2m_mean[i] != null) bucket.humidity.push(daily.relative_humidity_2m_mean[i]);
  }

  const yearsProcessed = 7;
  const initialMonthlyData: MonthlyClimateData[] = monthBuckets.map((b, idx) => {
    const avg = (arr: number[]) => arr.length ? arr.reduce((a, c) => a + c, 0) / arr.length : 0;
    const max = (arr: number[]) => arr.length ? Math.max(...arr) : 0;
    const min = (arr: number[]) => arr.length ? Math.min(...arr) : 0;

    const cardinalCounts: Record<string, number> = {};
    b.windDirs.forEach(d => {
      const c = degToCardinal(d);
      cardinalCounts[c] = (cardinalCounts[c] || 0) + 1;
    });
    const prevailingCardinal = Object.entries(cardinalCounts).sort((a,b) => b[1] - a[1])[0]?.[0] || 'N';
    const cardinalToDeg: Record<string, number> = { 'N': 0, 'NE': 45, 'E': 90, 'SE': 135, 'S': 180, 'SW': 225, 'W': 270, 'NW': 315 };

    const tAvg = avg(b.tempMean);
    const rh = avg(b.humidity);
    const rain = b.rain.reduce((a,c)=>a+c,0) / yearsProcessed;
    const solar = avg(b.solar);
    const wind = avg(b.wind);

    return {
      month: MONTH_NAMES[idx],
      monthIdx: idx,
      tempAvg: parseFloat(tAvg.toFixed(1)),
      tempMax: parseFloat(max(b.tempMax).toFixed(1)),
      tempMin: parseFloat(min(b.tempMin).toFixed(1)),
      rainfall: parseFloat(rain.toFixed(1)),
      rainyDays: Math.round(b.rainyDaysCount / yearsProcessed),
      humidity: parseFloat(rh.toFixed(1)),
      humidityMax: parseFloat(max(b.humidity).toFixed(1)),
      humidityMin: parseFloat(min(b.humidity).toFixed(1)),
      windSpeed: parseFloat(wind.toFixed(1)),
      windMax: parseFloat(max(b.wind).toFixed(1)),
      windDir: cardinalToDeg[prevailingCardinal], 
      solarIntensity: parseFloat(solar.toFixed(1)),
      peakSunHours: parseFloat((solar / 3.6).toFixed(1)),
      uvIndex: parseFloat(avg(b.uv).toFixed(1)),
      heatIndex: parseFloat((tAvg + (rh > 60 ? 0.5 * (rh - 60) : 0)).toFixed(1)),
      isSunny: solar >= CLIMATE_THRESHOLDS.SUNNY_MIN_SOLAR && rain < CLIMATE_THRESHOLDS.SUNNY_MAX_PRECIP,
      isRainy: rain >= CLIMATE_THRESHOLDS.RAINY_MIN_PRECIP || (b.rainyDaysCount / yearsProcessed) >= CLIMATE_THRESHOLDS.RAINY_MIN_DAYS,
      isWinter: tAvg <= CLIMATE_THRESHOLDS.WINTER_MAX_TEMP,
      isWindy: wind >= CLIMATE_THRESHOLDS.WINDY_MIN_SPEED
    };
  });

  // Relative seasonal fallbacks
  const hasWinter = initialMonthlyData.some(m => m.isWinter);
  const hasRainy = initialMonthlyData.some(m => m.isRainy);
  const hasSunny = initialMonthlyData.some(m => m.isSunny);
  const hasWindy = initialMonthlyData.some(m => m.isWindy);

  const sortedByTemp = [...initialMonthlyData].sort((a, b) => a.tempAvg - b.tempAvg);
  const sortedByRain = [...initialMonthlyData].sort((a, b) => b.rainfall - a.rainfall);
  const sortedBySolar = [...initialMonthlyData].sort((a, b) => b.solarIntensity - a.solarIntensity);
  const sortedByWind = [...initialMonthlyData].sort((a, b) => b.windSpeed - a.windSpeed);

  const finalMonthlyData = initialMonthlyData.map(m => ({
    ...m,
    isWinter: hasWinter ? m.isWinter : sortedByTemp.slice(0, 3).some(sm => sm.monthIdx === m.monthIdx),
    isRainy: hasRainy ? m.isRainy : sortedByRain.slice(0, 3).some(sm => sm.monthIdx === m.monthIdx),
    isSunny: hasSunny ? m.isSunny : sortedBySolar.slice(0, 3).some(sm => sm.monthIdx === m.monthIdx),
    isWindy: hasWindy ? m.isWindy : sortedByWind.slice(0, 3).some(sm => sm.monthIdx === m.monthIdx),
  }));

  const result: ClimateStats = {
    location: { name: locationName || "Location", lat, lng },
    period: "7-Year ERA5 Baseline",
    reliabilityScore: 99.8,
    monthlyData: finalMonthlyData,
    summary: {
      hottestMonth: sortedByTemp[11].month,
      coldestMonth: sortedByTemp[0].month,
      rainiestMonth: sortedByRain[0].month,
      sunniestMonth: sortedBySolar[0].month,
    }
  };

  setCachedData(lat, lng, result);
  return result;
}

import React, { useState, useEffect, useRef } from 'react';
import { Page, ClimateStats, LocationInfo } from './types';
import { fetchClimateData, geocode, reverseGeocode } from './services/climateService';
import { getClimateInsights } from './services/geminiService';
import Header from './components/Header';
import Overview from './components/Overview';
import SeasonalDetail from './components/SeasonalDetail';
import StatsTable from './components/StatsTable';
import Visuals from './components/Visuals';

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState<Page>(Page.OVERVIEW);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<{ message: string; type: string } | null>(null);
  const [data, setData] = useState<ClimateStats | null>(null);
  const [insights, setInsights] = useState<string>("");
  const [search, setSearch] = useState<string>("");
  const [searchResults, setSearchResults] = useState<LocationInfo[]>([]);
  const [useCoords, setUseCoords] = useState<boolean>(false);
  const [latInput, setLatInput] = useState<string>("");
  const [lngInput, setLngInput] = useState<string>("");
  const [cooldownTime, setCooldownTime] = useState<number>(0);
  const [isSearching, setIsSearching] = useState<boolean>(false);
  const [isLocating, setIsLocating] = useState<boolean>(false);

  const searchTimeoutRef = useRef<number | null>(null);
  const cooldownTimerRef = useRef<number | null>(null);

  const loadData = async (lat: number, lng: number, name: string) => {
    setLoading(true);
    setError(null);
    try {
      const stats = await fetchClimateData(lat, lng, name);
      setData(stats);
      try {
        const text = await getClimateInsights(stats);
        setInsights(text);
      } catch (geminiErr) {
        setInsights(`Historical overview for ${name} based on long-term climate grids.`);
      }
    } catch (err: any) {
      const msg = err.message || "Failed to retrieve climate data.";
      const type = msg.includes(":") ? msg.split(":")[0] : "GENERAL_ERROR";
      const cleanMsg = msg.includes(":") ? msg.split(":")[1].trim() : msg;

      setError({ message: cleanMsg, type });

      if (type === "RATE_LIMIT") {
        setCooldownTime(30);
      }
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    // Initial load: San Francisco
    loadData(37.7749, -122.4194, "San Francisco, CA, United States");
  }, []);

  useEffect(() => {
    if (cooldownTime > 0) {
      cooldownTimerRef.current = window.setInterval(() => {
        setCooldownTime(prev => prev - 1);
      }, 1000);
    } else {
      if (cooldownTimerRef.current) clearInterval(cooldownTimerRef.current);
    }
    return () => { if (cooldownTimerRef.current) clearInterval(cooldownTimerRef.current); };
  }, [cooldownTime]);

  useEffect(() => {
    if (useCoords || !search.trim() || search.trim().length < 2) {
      setSearchResults([]);
      return;
    }
    if (searchTimeoutRef.current) window.clearTimeout(searchTimeoutRef.current);
    setIsSearching(true);
    searchTimeoutRef.current = window.setTimeout(async () => {
      try {
        const results = await geocode(search);
        setSearchResults(results);
      } catch (err) {
        console.debug("Search error", err);
      } finally {
        setIsSearching(false);
      }
    }, 400);
    return () => { if (searchTimeoutRef.current) window.clearTimeout(searchTimeoutRef.current); };
  }, [search, useCoords]);

  const handleSearchSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (cooldownTime > 0) return;

    setError(null);

    if (useCoords) {
      const lat = parseFloat(latInput);
      const lng = parseFloat(lngInput);
      if (isNaN(lat) || isNaN(lng)) {
        setError({ message: "Enter valid coordinates.", type: "INPUT_ERROR" });
        return;
      }
      loadData(lat, lng, `Coordinates (${lat.toFixed(2)}, ${lng.toFixed(2)})`);
    } else {
      if (searchResults.length > 0) {
        selectLocation(searchResults[0]);
      } else if (search.trim()) {
        setLoading(true);
        try {
          const results = await geocode(search);
          if (results.length > 0) {
            selectLocation(results[0]);
          } else {
            setError({ 
              message: `No exact match for '${search}'. Try searching for just the city name (e.g. 'Delhi') instead of specific addresses.`, 
              type: "NOT_FOUND" 
            });
            setLoading(false);
          }
        } catch (err: any) {
          const msg = err.message || "Search failed.";
          const type = msg.includes(":") ? msg.split(":")[0] : "SEARCH_ERROR";
          const cleanMsg = msg.includes(":") ? msg.split(":")[1].trim() : msg;
          setError({ message: cleanMsg, type });
          setLoading(false);
        }
      }
    }
  };

  const handleGetCurrentLocation = () => {
    if (!navigator.geolocation) {
      setError({ message: "Geolocation not supported.", type: "PERMISSION_ERROR" });
      return;
    }
    setIsLocating(true);
    navigator.geolocation.getCurrentPosition(
      async (position) => {
        const { latitude, longitude } = position.coords;
        const locationName = await reverseGeocode(latitude, longitude);
        loadData(latitude, longitude, locationName);
        setLatInput(latitude.toFixed(4));
        setLngInput(longitude.toFixed(4));
        setSearch(locationName);
        setUseCoords(false);
        setIsLocating(false);
      },
      () => {
        setIsLocating(false);
        setError({ message: "Location access denied or unavailable.", type: "PERMISSION_ERROR" });
      }
    );
  };

  const selectLocation = (loc: LocationInfo) => {
    loadData(loc.lat, loc.lng, loc.name);
    setSearchResults([]);
    setSearch(loc.name);
  };

  const ErrorCard = ({ error }: { error: { message: string, type: string } }) => {
    return (
      <div className="mb-8 bg-rose-50 border-rose-100 border-2 p-8 rounded-[2.5rem] fade-in">
        <div className="flex items-start gap-5">
          <div className="bg-white p-3 rounded-2xl shadow-sm text-3xl">📡</div>
          <div className="flex-1">
            <h3 className="font-black text-rose-900 text-lg mb-1">Status Report</h3>
            <p className="text-rose-700 text-sm font-semibold leading-relaxed mb-4">{error.message}</p>
            {error.type === 'RATE_LIMIT' && (
              <div className="bg-rose-500 text-white px-4 py-2 rounded-xl text-xs font-black inline-block animate-pulse">
                Retry in {cooldownTime}s
              </div>
            )}
            {error.type === 'NOT_FOUND' && (
              <p className="text-rose-400 text-xs font-bold uppercase tracking-wide">Tip: Check spelling or try using broader location names.</p>
            )}
          </div>
          <button onClick={() => setError(null)} className="text-rose-300 hover:text-rose-600 p-2">✕</button>
        </div>
      </div>
    );
  };

  return (
    <div className="max-w-6xl mx-auto px-4 pb-20 pt-6">
      <div className="mb-8 flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div>
          <h1 className="text-4xl font-black text-slate-800 tracking-tighter flex items-center gap-2">
            <span className="bg-blue-600 text-white p-2 rounded-2xl rotate-3 shadow-lg">🌍</span>
            ClimaIntel
          </h1>
          <p className="text-slate-500 text-xs font-black uppercase tracking-widest mt-1 ml-1">Global Climate Intelligence</p>
        </div>

        <div className="w-full md:w-auto">
          <div className="flex bg-slate-100 p-1 rounded-2xl mb-3 w-fit ml-auto md:ml-0">
            <button onClick={() => setUseCoords(false)} className={`px-4 py-1.5 rounded-xl text-[11px] font-black uppercase tracking-wider transition-all ${!useCoords ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-400'}`}>Search</button>
            <button onClick={() => setUseCoords(true)} className={`px-4 py-1.5 rounded-xl text-[11px] font-black uppercase tracking-wider transition-all ${useCoords ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-400'}`}>Coords</button>
          </div>

          <div className="relative">
            <form onSubmit={handleSearchSubmit} className="flex gap-2">
              <div className="flex-1 flex gap-2">
                {!useCoords ? (
                  <div className="relative flex-1">
                    <input 
                      type="text" 
                      value={search}
                      onChange={(e) => setSearch(e.target.value)}
                      placeholder="Enter city..." 
                      className="px-5 py-3.5 rounded-2xl border border-slate-200 w-full md:w-80 shadow-sm font-medium focus:ring-4 focus:ring-blue-100 focus:outline-none transition-all"
                    />
                    {isSearching && <div className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 border-2 border-blue-600 border-t-transparent rounded-full animate-spin"></div>}
                  </div>
                ) : (
                  <div className="flex gap-2">
                    <input type="text" placeholder="Lat" value={latInput} onChange={(e) => setLatInput(e.target.value)} className="w-24 px-4 py-3.5 rounded-2xl border border-slate-200 shadow-sm font-mono text-sm focus:ring-4 focus:ring-blue-100 focus:outline-none transition-all" />
                    <input type="text" placeholder="Lng" value={lngInput} onChange={(e) => setLngInput(e.target.value)} className="w-24 px-4 py-3.5 rounded-2xl border border-slate-200 shadow-sm font-mono text-sm focus:ring-4 focus:ring-blue-100 focus:outline-none transition-all" />
                  </div>
                )}
                <button 
                  type="submit"
                  disabled={cooldownTime > 0 || loading}
                  className={`${cooldownTime > 0 ? 'bg-slate-300' : 'bg-slate-900 hover:bg-black active:scale-95'} text-white px-6 py-3.5 rounded-2xl transition-all shadow-xl font-bold min-w-[100px] disabled:opacity-50`}
                >
                  {cooldownTime > 0 ? `${cooldownTime}s` : loading ? '...' : 'Analyze'}
                </button>
              </div>
              <button type="button" onClick={handleGetCurrentLocation} disabled={isLocating || cooldownTime > 0} className="px-4 py-3.5 rounded-2xl border bg-white border-slate-200 text-slate-600 hover:bg-slate-50 active:scale-95 shadow-md">
                {isLocating ? <div className="w-5 h-5 border-2 border-blue-600 border-t-transparent rounded-full animate-spin"></div> : "📍"}
              </button>
            </form>
            {searchResults.length > 0 && !useCoords && (
              <div className="absolute top-full left-0 right-0 bg-white shadow-2xl rounded-3xl mt-2 z-50 border border-slate-100 overflow-hidden max-h-[300px] overflow-y-auto">
                {searchResults.map((loc, i) => (
                  <button key={i} onClick={() => selectLocation(loc)} className="w-full text-left px-5 py-4 hover:bg-blue-50 transition border-b border-slate-50 last:border-none">
                    <span className="font-bold text-slate-800 block text-sm">{loc.name}</span>
                    <span className="text-[10px] text-slate-400 font-mono">{loc.lat.toFixed(2)}, {loc.lng.toFixed(2)}</span>
                  </button>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>

      {error && <ErrorCard error={error} />}

      {loading && !data ? (
        <div className="flex flex-col items-center justify-center py-40">
           <div className="animate-spin rounded-full h-16 w-16 border-t-4 border-blue-600 mb-6"></div>
           <p className="text-slate-800 font-black text-2xl">Retrieving Climate Grids...</p>
        </div>
      ) : data && (
        <>
          <Header data={data} insights={insights} />
          <nav className="flex overflow-x-auto gap-2 mb-10 bg-white/60 p-2 rounded-[2.5rem] shadow-sm border border-slate-200/50 scrollbar-hide sticky top-4 z-40 backdrop-blur-xl">
            {[
              { id: Page.OVERVIEW, label: "Overview", icon: "🌎" },
              { id: Page.SUNNY, label: "Sunny", icon: "☀️" },
              { id: Page.RAINY, label: "Rainy", icon: "🌧️" },
              { id: Page.WINTER, label: "Winter", icon: "❄️" },
              { id: Page.STATS, label: "Data", icon: "📊" },
              { id: Page.GRAPHS, label: "Graphs", icon: "📈" },
            ].map(tab => (
              <button key={tab.id} onClick={() => setCurrentPage(tab.id as Page)} className={`flex items-center gap-2 px-6 py-4 rounded-[1.8rem] transition-all ${currentPage === tab.id ? 'bg-slate-900 text-white shadow-2xl -translate-y-1' : 'text-slate-600 hover:bg-white font-bold text-sm'}`}>
                <span className="text-xl">{tab.icon}</span>
                <span className="font-black tracking-tight">{tab.label}</span>
              </button>
            ))}
          </nav>
          <main className="fade-in">
            {currentPage === Page.OVERVIEW && <Overview data={data} />}
            {currentPage === Page.SUNNY && <SeasonalDetail data={data} type="sunny" />}
            {currentPage === Page.RAINY && <SeasonalDetail data={data} type="rainy" />}
            {currentPage === Page.WINTER && <SeasonalDetail data={data} type="winter" />}
            {currentPage === Page.STATS && <StatsTable data={data} />}
            {currentPage === Page.GRAPHS && <Visuals data={data} />}
          </main>
        </>
      )}
    </div>
  );
};

export default App;

import React from 'react';
import {
  AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
  BarChart, Bar, LineChart, Line, Legend, Cell,
  Radar, RadarChart, PolarGrid, PolarAngleAxis
} from 'recharts';
import { ClimateStats } from '../types';
import { degToCardinal } from '../services/climateService';

interface Props {
  data: ClimateStats;
}

const Visuals: React.FC<Props> = ({ data }) => {
  // Hemisphere aware seasonal aggregation
  const isSouthern = data.location.lat < 0;

  const getSeason = (monthIdx: number) => {
    if (isSouthern) {
      if ([11, 0, 1].includes(monthIdx)) return 'Summer';
      if ([2, 3, 4].includes(monthIdx)) return 'Autumn';
      if ([5, 6, 7].includes(monthIdx)) return 'Winter';
      return 'Spring';
    } else {
      if ([11, 0, 1].includes(monthIdx)) return 'Winter';
      if ([2, 3, 4].includes(monthIdx)) return 'Spring';
      if ([5, 6, 7].includes(monthIdx)) return 'Summer';
      return 'Autumn';
    }
  };

  const seasonalStats = [
    { name: 'Winter', temp: 0, rain: 0, humidity: 0, count: 0, color: '#3b82f6' },
    { name: 'Spring', temp: 0, rain: 0, humidity: 0, count: 0, color: '#10b981' },
    { name: 'Summer', temp: 0, rain: 0, humidity: 0, count: 0, color: '#f59e0b' },
    { name: 'Autumn', temp: 0, rain: 0, humidity: 0, count: 0, color: '#ef4444' },
  ];

  data.monthlyData.forEach(m => {
    const season = seasonalStats.find(s => s.name === getSeason(m.monthIdx));
    if (season) {
      season.temp += m.tempAvg;
      season.rain += m.rainfall;
      season.humidity += m.humidity;
      season.count += 1;
    }
  });

  const seasonalData = seasonalStats.map(s => ({
    ...s,
    temp: parseFloat((s.temp / s.count).toFixed(1)),
    rain: parseFloat((s.rain).toFixed(1)), // Seasonal total rainfall
    humidity: parseFloat((s.humidity / s.count).toFixed(1)),
  }));

  const directions = ['N', 'NE', 'E', 'SE', 'S', 'SW', 'W', 'NW'];
  const windRoseData = directions.map(dir => {
    const monthsInDir = data.monthlyData.filter(m => degToCardinal(m.windDir) === dir);
    return {
      direction: dir,
      frequency: monthsInDir.length,
      avgSpeed: monthsInDir.length > 0 
        ? monthsInDir.reduce((acc, curr) => acc + curr.windSpeed, 0) / monthsInDir.length 
        : 0
    };
  });

  const getUvColor = (uv: number) => {
    if (uv >= 11) return '#a855f7';
    if (uv >= 8) return '#ef4444';
    if (uv >= 6) return '#f97316';
    if (uv >= 3) return '#f59e0b';
    return '#10b981';
  };

  return (
    <div className="space-y-12 pb-20 fade-in">
      {/* 1. Seasonal Intelligence Section */}
      <section className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm min-h-[500px]">
        <div className="mb-8">
          <div className="flex items-center gap-3">
            <span className="text-3xl">🗓️</span>
            <h2 className="text-2xl font-black text-slate-800 tracking-tight">Seasonal Intelligence</h2>
          </div>
          <p className="text-slate-400 text-sm font-medium mt-2">Aggregated metrics identifying broader environmental trends for {isSouthern ? 'Southern' : 'Northern'} Hemisphere seasons.</p>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 mb-10">
          <div className="lg:col-span-2 h-[350px]">
            <ResponsiveContainer width="100%" height="100%" debounce={1}>
              <BarChart data={seasonalData} margin={{ top: 20, right: 30, left: 0, bottom: 0 }}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 13, fontWeight: 800}} />
                <YAxis yAxisId="left" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} />
                <YAxis yAxisId="right" orientation="right" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} unit="mm" />
                <Tooltip 
                  cursor={{fill: '#f8fafc'}}
                  contentStyle={{ borderRadius: '24px', border: 'none', boxShadow: '0 25px 50px -12px rgb(0 0 0 / 0.15)' }}
                />
                <Legend iconType="circle" />
                <Bar yAxisId="left" dataKey="temp" name="Avg Temp (°C)" radius={[10, 10, 0, 0]} barSize={40}>
                   {seasonalData.map((entry, index) => (
                    <Cell key={`cell-season-${index}`} fill={entry.color} />
                  ))}
                </Bar>
                <Bar yAxisId="right" dataKey="rain" name="Total Rain (mm)" fill="#cbd5e1" radius={[10, 10, 0, 0]} barSize={20} />
              </BarChart>
            </ResponsiveContainer>
          </div>
          <div className="space-y-4">
             {seasonalData.map(s => (
               <div key={s.name} className="bg-slate-50 p-5 rounded-3xl border border-slate-100">
                 <div className="flex items-center justify-between mb-2">
                   <h4 className="font-black text-slate-800">{s.name}</h4>
