            </ResponsiveContainer>
          </div>
        </section>

        <section className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm min-h-[400px]">
          <h3 className="text-xl font-black text-slate-800 mb-6">Atmospheric Comfort & Sunlight</h3>
          <div className="h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%" debounce={1}>
              <LineChart data={data.monthlyData} margin={{ top: 10, right: 30, left: 0, bottom: 0 }}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="month" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11, fontWeight: 700}} />
                <YAxis yAxisId="left" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} unit="%" />
                <YAxis yAxisId="right" orientation="right" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} unit="hr" />
                <Tooltip contentStyle={{ borderRadius: '20px', border: 'none' }} />
                <Legend />
                <Line yAxisId="left" type="monotone" name="Humidity %" dataKey="humidity" stroke="#0ea5e9" strokeWidth={3} dot={{r: 4, fill: '#0ea5e9'}} />
                <Line yAxisId="right" type="monotone" name="Peak Sun Hours" dataKey="peakSunHours" stroke="#f59e0b" strokeWidth={3} dot={{r: 4, fill: '#f59e0b'}} />
              </LineChart>
            </ResponsiveContainer>
          </div>
        </section>
      </div>
    </div>
  );
};

export default Visuals;

import React, { useState, useEffect, useRef } from 'react';
import { Page, ClimateStats, LocationInfo } from './types';
import { fetchClimateData, geocode, reverseGeocode } from './services/climateService';
import { getClimateInsights } from './services/geminiService';
import Header from './components/Header';
import Overview from './components/Overview';
import SeasonalDetail from './components/SeasonalDetail';
import StatsTable from './components/StatsTable';
import Visuals from './components/Visuals';

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState<Page>(Page.OVERVIEW);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<{ message: string; type: string } | null>(null);
  const [data, setData] = useState<ClimateStats | null>(null);
  const [insights, setInsights] = useState<string>("");
  const [search, setSearch] = useState<string>("");
  const [searchResults, setSearchResults] = useState<LocationInfo[]>([]);
  const [useCoords, setUseCoords] = useState<boolean>(false);
  const [latInput, setLatInput] = useState<string>("");
  const [lngInput, setLngInput] = useState<string>("");
  const [cooldownTime, setCooldownTime] = useState<number>(0);
  const [isSearching, setIsSearching] = useState<boolean>(false);
  const [isLocating, setIsLocating] = useState<boolean>(false);

  const searchTimeoutRef = useRef<number | null>(null);
  const cooldownTimerRef = useRef<number | null>(null);

  const handleOpenKeySelection = async () => {
    try {
      if (window.aistudio && typeof window.aistudio.openSelectKey === 'function') {
        await window.aistudio.openSelectKey();
        // After selection, we attempt to reload data to verify the new key
        if (data) loadData(data.location.lat, data.location.lng, data.location.name);
      }
    } catch (e) {
      console.error("Failed to open key selection", e);
    }
  };

  const loadData = async (lat: number, lng: number, name: string) => {
    setLoading(true);
    setError(null);
    try {
      const stats = await fetchClimateData(lat, lng, name);
      setData(stats);
      try {
        const text = await getClimateInsights(stats);
        setInsights(text);
      } catch (geminiErr: any) {
        if (geminiErr.message?.includes("429") || geminiErr.message?.includes("quota")) {
           setInsights("The intelligence engine is currently at capacity. Select your own API key to bypass system limits.");
           setError({ message: "Gemini API Rate Limit exceeded. Please select your own API key to continue analysis.", type: "GEMINI_LIMIT" });
        } else {
           setInsights(`Historical overview for ${name} based on long-term climate grids.`);
        }
      }
    } catch (err: any) {
      const msg = err.message || "Failed to retrieve climate data.";
      const type = msg.includes(":") ? msg.split(":")[0] : "GENERAL_ERROR";
      const cleanMsg = msg.includes(":") ? msg.split(":")[1].trim() : msg;

      setError({ message: cleanMsg, type });
      if (type === "RATE_LIMIT") setCooldownTime(30);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadData(37.7749, -122.4194, "San Francisco, CA, United States");
  }, []);

  useEffect(() => {
    if (cooldownTime > 0) {
      cooldownTimerRef.current = window.setInterval(() => {
        setCooldownTime(prev => prev - 1);
      }, 1000);
    } else {
      if (cooldownTimerRef.current) clearInterval(cooldownTimerRef.current);
    }
    return () => { if (cooldownTimerRef.current) clearInterval(cooldownTimerRef.current); };
  }, [cooldownTime]);

  useEffect(() => {
    if (useCoords || !search.trim() || search.trim().length < 2) {
      setSearchResults([]);
      return;
    }
    if (searchTimeoutRef.current) window.clearTimeout(searchTimeoutRef.current);
    setIsSearching(true);
    searchTimeoutRef.current = window.setTimeout(async () => {
      try {
        const results = await geocode(search);
        setSearchResults(results);
      } catch (err) {
        console.debug("Search error", err);
      } finally {
        setIsSearching(false);
      }
    }, 400);
    return () => { if (searchTimeoutRef.current) window.clearTimeout(searchTimeoutRef.current); };
  }, [search, useCoords]);

  const handleSearchSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (cooldownTime > 0) return;
    setError(null);

    if (useCoords) {
      const lat = parseFloat(latInput);
      const lng = parseFloat(lngInput);
      if (isNaN(lat) || isNaN(lng)) {
        setError({ message: "Enter valid coordinates.", type: "INPUT_ERROR" });
        return;
      }
      loadData(lat, lng, `Coordinates (${lat.toFixed(2)}, ${lng.toFixed(2)})`);
    } else {
      if (searchResults.length > 0) {
        selectLocation(searchResults[0]);
      } else if (search.trim()) {
        setLoading(true);
        try {
          const results = await geocode(search);
          if (results.length > 0) selectLocation(results[0]);
          else {
            setError({ message: `No exact match for '${search}'. Try city names only.`, type: "NOT_FOUND" });
            setLoading(false);
          }
        } catch (err: any) {
          setError({ message: err.message || "Search failed.", type: "SEARCH_ERROR" });
          setLoading(false);
        }
      }
    }
  };

  const handleGetCurrentLocation = () => {
    if (!navigator.geolocation) {
      setError({ message: "Geolocation not supported.", type: "PERMISSION_ERROR" });
      return;
    }
    setIsLocating(true);
    navigator.geolocation.getCurrentPosition(
      async (position) => {
        const { latitude, longitude } = position.coords;
        const locationName = await reverseGeocode(latitude, longitude);
        loadData(latitude, longitude, locationName);
        setLatInput(latitude.toFixed(4));
        setLngInput(longitude.toFixed(4));
        setSearch(locationName);
        setIsLocating(false);
      },
      () => {
        setIsLocating(false);
        setError({ message: "Location access denied.", type: "PERMISSION_ERROR" });
      }
    );
  };

  const selectLocation = (loc: LocationInfo) => {
    loadData(loc.lat, loc.lng, loc.name);
    setSearchResults([]);
    setSearch(loc.name);
  };

  const ErrorCard = ({ error }: { error: { message: string, type: string } }) => {
    return (
      <div className="mb-8 bg-rose-50 border-rose-100 border-2 p-8 rounded-[2.5rem] fade-in">
        <div className="flex items-start gap-5">
          <div className="bg-white p-3 rounded-2xl shadow-sm text-3xl">📡</div>
          <div className="flex-1">
            <h3 className="font-black text-rose-900 text-lg mb-1">Status Report</h3>
            <p className="text-rose-700 text-sm font-semibold leading-relaxed mb-4">{error.message}</p>
            {error.type === 'GEMINI_LIMIT' && (
              <div className="flex flex-col gap-3">
                <button 
                  onClick={handleOpenKeySelection}
                  className="bg-rose-600 text-white px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-wider hover:bg-rose-700 transition shadow-lg w-fit"
                >
                  Select My Own API Key
                </button>
                <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" className="text-[10px] text-rose-400 font-bold hover:underline">Requires a paid GCP project →</a>
              </div>
            )}
            {error.type === 'RATE_LIMIT' && (
              <div className="bg-rose-500 text-white px-4 py-2 rounded-xl text-xs font-black inline-block animate-pulse">
                Retry available in {cooldownTime}s
              </div>
            )}
          </div>
          <button onClick={() => setError(null)} className="text-rose-300 hover:text-rose-600 p-2">✕</button>
        </div>
      </div>
    );
  };

  return (
    <div className="max-w-6xl mx-auto px-4 pb-20 pt-6">
      <div className="mb-8 flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div>
          <h1 className="text-4xl font-black text-slate-800 tracking-tighter flex items-center gap-2">
            <span className="bg-blue-600 text-white p-2 rounded-2xl rotate-3 shadow-lg">🌍</span>
            ClimaIntel
          </h1>
          <p className="text-slate-500 text-xs font-black uppercase tracking-widest mt-1 ml-1">Global Climate Intelligence</p>
        </div>

        <div className="w-full md:w-auto flex flex-col items-end gap-3">
          <div className="flex bg-slate-100 p-1 rounded-2xl w-fit">
            <button onClick={() => setUseCoords(false)} className={`px-4 py-1.5 rounded-xl text-[11px] font-black uppercase tracking-wider transition-all ${!useCoords ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-400'}`}>Search</button>
            <button onClick={() => setUseCoords(true)} className={`px-4 py-1.5 rounded-xl text-[11px] font-black uppercase tracking-wider transition-all ${useCoords ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-400'}`}>Coords</button>
            <div className="w-px h-4 bg-slate-200 self-center mx-1"></div>
            <button onClick={handleOpenKeySelection} className="px-4 py-1.5 rounded-xl text-[11px] font-black uppercase tracking-wider text-slate-400 hover:text-slate-600 transition-colors">Key ⚙️</button>
          </div>

          <div className="relative w-full">
            <form onSubmit={handleSearchSubmit} className="flex gap-2">
              <div className="flex-1 flex gap-2">
                {!useCoords ? (
                  <div className="relative flex-1">
                    <input 
                      type="text" 
                      value={search}
                      onChange={(e) => setSearch(e.target.value)}
                      placeholder="Enter city..." 
                      className="px-5 py-3.5 rounded-2xl border border-slate-200 w-full md:w-80 shadow-sm font-medium focus:ring-4 focus:ring-blue-100 focus:outline-none"
                    />
                    {isSearching && <div className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 border-2 border-blue-600 border-t-transparent rounded-full animate-spin"></div>}
                  </div>
                ) : (
                  <div className="flex gap-2">
                    <input type="text" placeholder="Lat" value={latInput} onChange={(e) => setLatInput(e.target.value)} className="w-24 px-4 py-3.5 rounded-2xl border border-slate-200 shadow-sm font-mono text-sm" />
                    <input type="text" placeholder="Lng" value={lngInput} onChange={(e) => setLngInput(e.target.value)} className="w-24 px-4 py-3.5 rounded-2xl border border-slate-200 shadow-sm font-mono text-sm" />
                  </div>
                )}
                <button 
                  type="submit"
                  disabled={cooldownTime > 0 || loading}
                  className={`${cooldownTime > 0 ? 'bg-slate-300' : 'bg-slate-900 hover:bg-black active:scale-95'} text-white px-6 py-3.5 rounded-2xl transition-all shadow-xl font-bold min-w-[100px]`}
                >
                  {cooldownTime > 0 ? `${cooldownTime}s` : loading ? '...' : 'Analyze'}
                </button>
              </div>
              <button type="button" onClick={handleGetCurrentLocation} disabled={isLocating || cooldownTime > 0} className="px-4 py-3.5 rounded-2xl border bg-white border-slate-200 text-slate-600 hover:bg-slate-50 active:scale-95 shadow-md">
                {isLocating ? <div className="w-5 h-5 border-2 border-blue-600 border-t-transparent rounded-full animate-spin"></div> : "📍"}
              </button>
            </form>
            {searchResults.length > 0 && !useCoords && (
              <div className="absolute top-full left-0 right-0 bg-white shadow-2xl rounded-3xl mt-2 z-50 border border-slate-100 overflow-hidden max-h-[300px] overflow-y-auto">
                {searchResults.map((loc, i) => (
                  <button key={i} onClick={() => selectLocation(loc)} className="w-full text-left px-5 py-4 hover:bg-blue-50 transition border-b border-slate-50 last:border-none">
                    <span className="font-bold text-slate-800 block text-sm">{loc.name}</span>
                    <span className="text-[10px] text-slate-400 font-mono">{loc.lat.toFixed(2)}, {loc.lng.toFixed(2)}</span>
                  </button>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>

      {error && <ErrorCard error={error} />}

      {loading && !data ? (
        <div className="flex flex-col items-center justify-center py-40">
           <div className="animate-spin rounded-full h-16 w-16 border-t-4 border-blue-600 mb-6"></div>
           <p className="text-slate-800 font-black text-2xl">Retrieving Climate Grids...</p>
        </div>
      ) : data && (
        <>
          <Header data={data} insights={insights} />
          <nav className="flex overflow-x-auto gap-2 mb-10 bg-white/60 p-2 rounded-[2.5rem] shadow-sm border border-slate-200/50 scrollbar-hide sticky top-4 z-40 backdrop-blur-xl">
            {[
              { id: Page.OVERVIEW, label: "Overview", icon: "🌎" },
              { id: Page.SUNNY, label: "Sunny", icon: "☀️" },
              { id: Page.RAINY, label: "Rainy", icon: "🌧️" },
              { id: Page.WINTER, label: "Winter", icon: "❄️" },
              { id: Page.STATS, label: "Data", icon: "📊" },
              { id: Page.GRAPHS, label: "Graphs", icon: "📈" },
            ].map(tab => (
              <button key={tab.id} onClick={() => setCurrentPage(tab.id as Page)} className={`flex items-center gap-2 px-6 py-4 rounded-[1.8rem] transition-all ${currentPage === tab.id ? 'bg-slate-900 text-white shadow-2xl -translate-y-1' : 'text-slate-600 hover:bg-white font-bold text-sm'}`}>
                <span className="text-xl">{tab.icon}</span>
                <span className="font-black tracking-tight">{tab.label}</span>
              </button>
            ))}
          </nav>
          <main className="fade-in">
            {currentPage === Page.OVERVIEW && <Overview data={data} />}
            {currentPage === Page.SUNNY && <SeasonalDetail data={data} type="sunny" />}
            {currentPage === Page.RAINY && <SeasonalDetail data={data} type="rainy" />}
            {currentPage === Page.WINTER && <SeasonalDetail data={data} type="winter" />}
            {currentPage === Page.STATS && <StatsTable data={data} />}
            {currentPage === Page.GRAPHS && <Visuals data={data} />}
          </main>
        </>
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import {
  AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
  BarChart, Bar, LineChart, Line, Legend, Cell
} from 'recharts';
import { ClimateStats } from '../types';
import { degToCardinal } from '../services/climateService';

interface Props {
  data: ClimateStats;
}

const Visuals: React.FC<Props> = ({ data }) => {
  const [viewMode, setViewMode] = useState<'monthly' | 'seasonal'>('seasonal');
  const isSouthern = data.location.lat < 0;

  const getSeasonName = (monthIdx: number) => {
    if (isSouthern) {
      if ([11, 0, 1].includes(monthIdx)) return 'Summer';
      if ([2, 3, 4].includes(monthIdx)) return 'Autumn';
      if ([5, 6, 7].includes(monthIdx)) return 'Winter';
      return 'Spring';
    } else {
      if ([11, 0, 1].includes(monthIdx)) return 'Winter';
      if ([2, 3, 4].includes(monthIdx)) return 'Spring';
      if ([5, 6, 7].includes(monthIdx)) return 'Summer';
      return 'Autumn';
    }
  };

  const seasons = ['Winter', 'Spring', 'Summer', 'Autumn'];
  const seasonalStats = seasons.map(name => {
    const months = data.monthlyData.filter(m => getSeasonName(m.monthIdx) === name);
    const count = months.length;
    return {
      name,
      temp: parseFloat((months.reduce((acc, m) => acc + m.tempAvg, 0) / count).toFixed(1)),
      rain: parseFloat((months.reduce((acc, m) => acc + m.rainfall, 0)).toFixed(1)), // Total seasonal rain
      humidity: parseFloat((months.reduce((acc, m) => acc + m.humidity, 0) / count).toFixed(1)),
      color: name === 'Winter' ? '#3b82f6' : name === 'Spring' ? '#10b981' : name === 'Summer' ? '#f59e0b' : '#ef4444'
    };
  });

  const getUvColor = (uv: number) => {
    if (uv >= 11) return '#a855f7';
    if (uv >= 8) return '#ef4444';
    if (uv >= 6) return '#f97316';
    if (uv >= 3) return '#f59e0b';
    return '#10b981';
  };

  return (
    <div className="space-y-12 pb-20 fade-in">
      {/* View Mode Toggle */}
      <div className="flex justify-center mb-8">
        <div className="bg-slate-100 p-1 rounded-2xl flex shadow-inner">
          <button 
            onClick={() => setViewMode('seasonal')}
            className={`px-8 py-3 rounded-xl text-xs font-black uppercase tracking-wider transition-all ${viewMode === 'seasonal' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-400'}`}
          >
            Seasonal Intelligence
          </button>
          <button 
            onClick={() => setViewMode('monthly')}
            className={`px-8 py-3 rounded-xl text-xs font-black uppercase tracking-wider transition-all ${viewMode === 'monthly' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-400'}`}
          >
            Monthly Detail
          </button>
        </div>
      </div>

      {viewMode === 'seasonal' ? (
        <section className="bg-white p-8 rounded-[3rem] border border-slate-100 shadow-xl overflow-hidden relative">
          <div className="absolute top-0 right-0 p-8 opacity-5 select-none text-[120px] font-black -rotate-12 pointer-events-none">
            {isSouthern ? 'SOUTHERN' : 'NORTHERN'}
          </div>
          <div className="mb-12 relative z-10">
            <div className="flex items-center gap-4 mb-4">
              <span className="bg-blue-600 text-white p-3 rounded-2xl text-2xl shadow-lg">📈</span>
              <div>
                <h2 className="text-3xl font-black text-slate-800 tracking-tight">Seasonal Profile</h2>
                <p className="text-slate-400 text-sm font-semibold">Aggregated environmental trends across {isSouthern ? 'Southern' : 'Northern'} seasons.</p>
              </div>
            </div>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-3 gap-12">
            <div className="lg:col-span-2 h-[450px]">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={seasonalStats} margin={{ top: 20, right: 30, left: 0, bottom: 20 }}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                  <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 14, fontWeight: 800}} />
                  <YAxis yAxisId="left" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} unit="°C" />
                  <YAxis yAxisId="right" orientation="right" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} unit="mm" />
                  <Tooltip 
                    cursor={{fill: '#f8fafc'}}
                    contentStyle={{ borderRadius: '24px', border: 'none', boxShadow: '0 25px 50px -12px rgb(0 0 0 / 0.15)' }}
                  />
                  <Legend iconType="circle" wrapperStyle={{paddingTop: '20px'}} />
                  <Bar yAxisId="left" dataKey="temp" name="Quarterly Temp (°C)" radius={[12, 12, 0, 0]} barSize={50}>
                    {seasonalStats.map((entry, index) => (
                      <Cell key={`cell-s-${index}`} fill={entry.color} />
                    ))}
                  </Bar>
                  <Bar yAxisId="right" dataKey="rain" name="Total Rainfall (mm)" fill="#cbd5e1" radius={[8, 8, 0, 0]} barSize={25} />
                </BarChart>
              </ResponsiveContainer>
            </div>

            <div className="space-y-4">
               {seasonalStats.map(s => (
                 <div key={s.name} className="bg-slate-50 p-6 rounded-[2rem] border border-slate-100 hover:scale-[1.02] transition-transform">
                   <div className="flex items-center justify-between mb-4">
                     <span className="px-3 py-1 rounded-full text-[10px] font-black uppercase text-white shadow-sm" style={{backgroundColor: s.color}}>{s.name}</span>
                     <span className="text-[10px] font-bold text-slate-300 uppercase tracking-widest">3-Month Cluster</span>
                   </div>
                   <div className="grid grid-cols-2 gap-4">
                      <div>
                        <div className="text-3xl font-black text-slate-800">{s.temp}°</div>
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-tight mt-1">Avg Temperature</p>
                      </div>
                      <div className="text-right">
                        <div className="text-2xl font-black text-slate-600">{s.humidity}%</div>
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-tight mt-1">Rel. Humidity</p>
                      </div>
                      <div className="col-span-2 pt-2 mt-2 border-t border-slate-200/50">
                        <div className="flex justify-between items-end">
                           <div>
                             <span className="text-lg font-bold text-blue-600">{s.rain}mm</span>
                             <p className="text-[9px] text-slate-400 font-bold uppercase tracking-tight">Period Rainfall</p>
                           </div>
                           <div className="flex gap-1 h-3 items-end">
                              {[1,2,3,4,5].map(i => (
                                <div key={i} className={`w-1.5 rounded-full ${s.rain > i*20 ? 'bg-blue-400' : 'bg-slate-200'}`} style={{height: `${i*20}%`}}></div>
                              ))}
                           </div>
                        </div>
                      </div>
                   </div>
                 </div>
               ))}
            </div>
          </div>
        </section>
      ) : (
        <div className="space-y-12">
          {/* UV Index Chart */}
          <section className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
            <div className="mb-8">
              <h2 className="text-2xl font-black text-slate-800 tracking-tight">Monthly UV Risk Index</h2>
              <p className="text-slate-400 text-sm font-medium mt-1">Average historical solar radiation intensity.</p>
            </div>
            <div className="h-[350px] w-full">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={data.monthlyData} margin={{ top: 10, right: 30, left: 0, bottom: 0 }}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                  <XAxis dataKey="month" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12, fontWeight: 700}} />
                  <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12}} domain={[0, 12]} />
                  <Tooltip cursor={{fill: '#f8fafc'}} contentStyle={{ borderRadius: '20px', border: 'none' }} />
                  <Bar dataKey="uvIndex" name="UV Index" radius={[10, 10, 0, 0]} barSize={35}>
                    {data.monthlyData.map((entry, index) => (
                      <Cell key={`cell-uv-${index}`} fill={getUvColor(entry.uvIndex)} />
                    ))}
                  </Bar>
                </BarChart>
              </ResponsiveContainer>
            </div>
          </section>

