import { GoogleGenAI } from "@google/genai";
import { ClimateStats } from "../types";

export async function getClimateInsights(stats: ClimateStats): Promise<string> {
  const apiKey = process.env.API_KEY;

  // Return fallback if no key is provided yet
  if (!apiKey || apiKey === "") {
    return "Select your own Gemini API key to enable AI-powered climate insights for this location.";
  }

  const prompt = `
    Act as a senior climate engineer. Analyze the following climate stats for ${stats.location.name} (${stats.location.lat}, ${stats.location.lng}).
    Provide a concise, user-friendly 2-3 sentence summary explaining what a visitor or resident should expect regarding climate comfort and seasonal patterns. 
    Use a friendly tone.

    Data Summary:
    - Hottest month: ${stats.summary.hottestMonth}
    - Coldest month: ${stats.summary.coldestMonth}
    - Rainiest month: ${stats.summary.rainiestMonth}
    - Typical Humidity: ${stats.monthlyData[6].humidity}%
    - Period: ${stats.period}
  `;

  try {
    const ai = new GoogleGenAI({ apiKey });
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "Climate analysis complete. Explore the historical data below.";
  } catch (error: any) {
    console.error("Gemini Error:", error);
    if (error.message?.includes("429") || error.message?.includes("quota")) {
      throw new Error("GEMINI_LIMIT: AI Quota reached.");
    }
    return "Detailed climate metrics are available below for your review.";
  }
}

import React, { useState, useEffect, useRef } from 'react';
import { Page, ClimateStats, LocationInfo } from './types';
import { fetchClimateData, geocode, reverseGeocode } from './services/climateService';
import { getClimateInsights } from './services/geminiService';
import Header from './components/Header';
import Overview from './components/Overview';
import SeasonalDetail from './components/SeasonalDetail';
import StatsTable from './components/StatsTable';
import Visuals from './components/Visuals';

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState<Page>(Page.OVERVIEW);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<{ message: string; type: string; lat?: number; lng?: number; name?: string } | null>(null);
  const [data, setData] = useState<ClimateStats | null>(null);
  const [insights, setInsights] = useState<string>("");
  const [search, setSearch] = useState<string>("");
  const [searchResults, setSearchResults] = useState<LocationInfo[]>([]);
  const [useCoords, setUseCoords] = useState<boolean>(false);
  const [latInput, setLatInput] = useState<string>("");
  const [lngInput, setLngInput] = useState<string>("");
  const [cooldownTime, setCooldownTime] = useState<number>(0);
  const [isSearching, setIsSearching] = useState<boolean>(false);
  const [isLocating, setIsLocating] = useState<boolean>(false);

  const searchTimeoutRef = useRef<number | null>(null);
  const cooldownTimerRef = useRef<number | null>(null);

  const handleOpenKeySelection = async () => {
    try {
      if (window.aistudio && typeof window.aistudio.openSelectKey === 'function') {
        await window.aistudio.openSelectKey();
        if (data) loadData(data.location.lat, data.location.lng, data.location.name);
      }
    } catch (e) {
      console.error("Failed to open key selection", e);
    }
  };

  const loadData = async (lat: number, lng: number, name: string) => {
    setLoading(true);
    setError(null);
    try {
      const stats = await fetchClimateData(lat, lng, name);
      setData(stats);
      try {
        const text = await getClimateInsights(stats);
        setInsights(text);
      } catch (geminiErr: any) {
        if (geminiErr.message?.includes("GEMINI_LIMIT") || geminiErr.message?.includes("429")) {
           setInsights("The AI engine has reached its limit. Data below is still accurate.");
           setError({ message: "Gemini AI limit reached. You can still view climate data, or select your own API key for AI analysis.", type: "GEMINI_LIMIT" });
        } else {
           setInsights(`Historical climate overview for ${name}.`);
        }
      }
    } catch (err: any) {
      const msg = err.message || "Failed to retrieve climate data.";
      const type = msg.includes(":") ? msg.split(":")[0] : "GENERAL_ERROR";
      const cleanMsg = msg.includes(":") ? msg.split(":")[1].trim() : msg;

      setError({ message: cleanMsg, type, lat, lng, name });
      if (type === "RATE_LIMIT") setCooldownTime(30);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadData(37.7749, -122.4194, "San Francisco, CA, United States");
  }, []);

  useEffect(() => {
    if (cooldownTime > 0) {
      cooldownTimerRef.current = window.setInterval(() => {
        setCooldownTime(prev => prev - 1);
      }, 1000);
    } else {
      if (cooldownTimerRef.current) clearInterval(cooldownTimerRef.current);
    }
    return () => { if (cooldownTimerRef.current) clearInterval(cooldownTimerRef.current); };
  }, [cooldownTime]);

  useEffect(() => {
    if (useCoords || !search.trim() || search.trim().length < 2) {
      setSearchResults([]);
      return;
    }
    if (searchTimeoutRef.current) window.clearTimeout(searchTimeoutRef.current);
    setIsSearching(true);
    searchTimeoutRef.current = window.setTimeout(async () => {
      try {
        const results = await geocode(search);
        setSearchResults(results);
      } catch (err) {
        console.debug("Search error", err);
      } finally {
        setIsSearching(false);
      }
    }, 400);
    return () => { if (searchTimeoutRef.current) window.clearTimeout(searchTimeoutRef.current); };
  }, [search, useCoords]);

  const handleSearchSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (cooldownTime > 0) return;
    setError(null);

    if (useCoords) {
      const lat = parseFloat(latInput);
      const lng = parseFloat(lngInput);
      if (isNaN(lat) || isNaN(lng)) {
        setError({ message: "Enter valid coordinates.", type: "INPUT_ERROR" });
        return;
      }
      loadData(lat, lng, `Coordinates (${lat.toFixed(2)}, ${lng.toFixed(2)})`);
    } else {
      if (searchResults.length > 0) {
        selectLocation(searchResults[0]);
      } else if (search.trim()) {
        setLoading(true);
        try {
          const results = await geocode(search);
          if (results.length > 0) selectLocation(results[0]);
          else {
            setError({ message: `No exact match for '${search}'. Try searching for just the city name.`, type: "NOT_FOUND" });
            setLoading(false);
          }
        } catch (err: any) {
          setError({ message: err.message || "Search failed.", type: "SEARCH_ERROR" });
          setLoading(false);
        }
      }
    }
  };

  const handleGetCurrentLocation = () => {
    if (!navigator.geolocation) {
      setError({ message: "Geolocation not supported.", type: "PERMISSION_ERROR" });
      return;
    }
    setIsLocating(true);
    navigator.geolocation.getCurrentPosition(
      async (position) => {
        const { latitude, longitude } = position.coords;
        const locationName = await reverseGeocode(latitude, longitude);
        loadData(latitude, longitude, locationName);
        setLatInput(latitude.toFixed(4));
        setLngInput(longitude.toFixed(4));
        setSearch(locationName);
        setIsLocating(false);
      },
      () => {
        setIsLocating(false);
        setError({ message: "Location access denied.", type: "PERMISSION_ERROR" });
      }
    );
  };

  const selectLocation = (loc: LocationInfo) => {
    loadData(loc.lat, loc.lng, loc.name);
    setSearchResults([]);
    setSearch(loc.name);
  };

  const ErrorCard = ({ error }: { error: { message: string, type: string, lat?: number, lng?: number, name?: string } }) => {
    return (
      <div className="mb-8 bg-rose-50 border-rose-100 border-2 p-8 rounded-[2.5rem] fade-in shadow-lg">
        <div className="flex items-start gap-5">
          <div className="bg-white p-4 rounded-2xl shadow-sm text-3xl">📡</div>
          <div className="flex-1">
            <h3 className="font-black text-rose-900 text-lg mb-1">Status Alert</h3>
            <p className="text-rose-700 text-sm font-semibold leading-relaxed mb-5">{error.message}</p>
            <div className="flex flex-wrap gap-3">
              {(error.type === 'GEMINI_LIMIT' || error.type === 'RATE_LIMIT') && (
                <button 
                  onClick={handleOpenKeySelection}
                  className="bg-slate-900 text-white px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-wider hover:bg-black transition shadow-md"
                >
                  Configure API Key
                </button>
              )}
              {error.lat !== undefined && error.lng !== undefined && (
                <button 
                  onClick={() => loadData(error.lat!, error.lng!, error.name || "Retry")}
                  className="bg-rose-600 text-white px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-wider hover:bg-rose-700 transition shadow-md"
                >
                  Retry Analysis
                </button>
              )}
              {error.type === 'RATE_LIMIT' && (
                <span className="bg-rose-100 text-rose-700 px-4 py-2.5 rounded-xl text-[10px] font-black uppercase flex items-center gap-2">
                  <span className="w-2 h-2 rounded-full bg-rose-500 animate-pulse"></span>
                  Ready in {cooldownTime}s
                </span>
              )}
            </div>
          </div>
          <button onClick={() => setError(null)} className="text-rose-300 hover:text-rose-600 p-2">✕</button>
        </div>
      </div>
    );
  };

  return (
    <div className="max-w-6xl mx-auto px-4 pb-20 pt-6">
      <div className="mb-12 flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div>
          <h1 className="text-4xl font-black text-slate-800 tracking-tighter flex items-center gap-2">
            <span className="bg-blue-600 text-white p-2.5 rounded-2xl rotate-3 shadow-xl">🌍</span>
            ClimaIntel
          </h1>
          <p className="text-slate-500 text-[10px] font-black uppercase tracking-[0.3em] mt-2 ml-1 opacity-80">Global Climate Intelligence System</p>
        </div>

        <div className="w-full md:w-auto flex flex-col items-end gap-3">
          <div className="flex bg-white/80 backdrop-blur-md p-1.5 rounded-2xl w-fit shadow-sm border border-slate-200">
            <button onClick={() => setUseCoords(false)} className={`px-5 py-2 rounded-xl text-[10px] font-black uppercase tracking-wider transition-all ${!useCoords ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-400 hover:text-slate-600'}`}>City Search</button>
            <button onClick={() => setUseCoords(true)} className={`px-5 py-2 rounded-xl text-[10px] font-black uppercase tracking-wider transition-all ${useCoords ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-400 hover:text-slate-600'}`}>Coordinates</button>
            <div className="w-px h-4 bg-slate-200 self-center mx-2"></div>
            <button onClick={handleOpenKeySelection} className="px-5 py-2 rounded-xl text-[10px] font-black uppercase tracking-wider text-blue-600 hover:bg-blue-50 transition-colors">Setup Key ⚙️</button>
          </div>

          <div className="relative w-full">
            <form onSubmit={handleSearchSubmit} className="flex gap-2">
              <div className="flex-1 flex gap-2">
                {!useCoords ? (
                  <div className="relative flex-1">
                    <input 
                      type="text" 
                      value={search}
                      onChange={(e) => setSearch(e.target.value)}
                      placeholder="Enter city (e.g. Delhi)..." 
                      className="px-6 py-4 rounded-[1.5rem] border border-slate-200 w-full md:w-80 shadow-xl font-medium focus:ring-4 focus:ring-blue-100 focus:outline-none transition-all placeholder:text-slate-300"
                    />
                    {isSearching && <div className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 border-2 border-blue-600 border-t-transparent rounded-full animate-spin"></div>}
                  </div>
                ) : (
                  <div className="flex gap-2">
                    <input type="text" placeholder="Lat" value={latInput} onChange={(e) => setLatInput(e.target.value)} className="w-24 px-5 py-4 rounded-[1.5rem] border border-slate-200 shadow-xl font-mono text-sm focus:ring-4 focus:ring-blue-100 focus:outline-none" />
                    <input type="text" placeholder="Lng" value={lngInput} onChange={(e) => setLngInput(e.target.value)} className="w-24 px-5 py-4 rounded-[1.5rem] border border-slate-200 shadow-xl font-mono text-sm focus:ring-4 focus:ring-blue-100 focus:outline-none" />
                  </div>
                )}
                <button 
                  type="submit"
                  disabled={cooldownTime > 0 || loading}
                  className={`${cooldownTime > 0 ? 'bg-slate-300' : 'bg-slate-900 hover:bg-black active:scale-95'} text-white px-8 py-4 rounded-[1.5rem] transition-all shadow-2xl font-black uppercase text-[10px] tracking-widest min-w-[120px]`}
                >
                  {cooldownTime > 0 ? `${cooldownTime}s` : loading ? '...' : 'Analyze'}
                </button>
              </div>
              <button type="button" onClick={handleGetCurrentLocation} disabled={isLocating || cooldownTime > 0} className="px-5 py-4 rounded-[1.5rem] border bg-white border-slate-200 text-slate-600 hover:bg-slate-50 active:scale-95 shadow-xl transition-all">
                {isLocating ? <div className="w-5 h-5 border-2 border-blue-600 border-t-transparent rounded-full animate-spin"></div> : "📍"}
              </button>
            </form>
            {searchResults.length > 0 && !useCoords && (
              <div className="absolute top-full left-0 right-0 bg-white/95 backdrop-blur-xl shadow-[0_32px_64px_-16px_rgba(0,0,0,0.2)] rounded-[2rem] mt-4 z-50 border border-slate-100 overflow-hidden max-h-[350px] overflow-y-auto fade-in">
                {searchResults.map((loc, i) => (
                  <button key={i} onClick={() => selectLocation(loc)} className="w-full text-left px-7 py-5 hover:bg-blue-600 hover:text-white transition-all group border-b border-slate-50 last:border-none">
                    <span className="font-black block text-sm group-hover:translate-x-1 transition-transform">{loc.name}</span>
                    <span className="text-[10px] opacity-60 font-mono mt-1 block">GRID COORDINATES: {loc.lat.toFixed(3)}, {loc.lng.toFixed(3)}</span>
                  </button>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>

      {error && <ErrorCard error={error} />}

      {loading && !data ? (
        <div className="flex flex-col items-center justify-center py-40 fade-in">
           <div className="relative">
             <div className="w-20 h-20 rounded-full border-4 border-slate-100 border-t-blue-600 animate-spin"></div>
             <div className="absolute inset-0 flex items-center justify-center text-xl">📡</div>
           </div>
           <p className="text-slate-800 font-black text-2xl mt-8">Synthesizing Grids...</p>
           <p className="text-slate-400 text-sm font-bold uppercase tracking-widest mt-2">Connecting to ERA5 Reanalysis servers</p>
        </div>
      ) : data && (
        <>
          <Header data={data} insights={insights} />
          <nav className="flex overflow-x-auto gap-2 mb-12 bg-white/80 p-2.5 rounded-[3rem] shadow-xl border border-slate-100 scrollbar-hide sticky top-6 z-40 backdrop-blur-2xl">
            {[
              { id: Page.OVERVIEW, label: "Overview", icon: "🌎" },
              { id: Page.SUNNY, label: "Sunny", icon: "☀️" },
              { id: Page.RAINY, label: "Rainy", icon: "🌧️" },
              { id: Page.WINTER, label: "Winter", icon: "❄️" },
              { id: Page.STATS, label: "Data", icon: "📊" },
              { id: Page.GRAPHS, label: "Graphs", icon: "📈" },
            ].map(tab => (
              <button key={tab.id} onClick={() => setCurrentPage(tab.id as Page)} className={`flex items-center gap-2.5 px-7 py-4 rounded-[2.2rem] transition-all ${currentPage === tab.id ? 'bg-slate-900 text-white shadow-[0_20px_40px_-10px_rgba(0,0,0,0.3)] -translate-y-1' : 'text-slate-500 hover:bg-white hover:text-slate-800 font-bold text-sm'}`}>
                <span className="text-xl">{tab.icon}</span>
                <span className="font-black tracking-tighter uppercase text-[10px]">{tab.label}</span>
              </button>
            ))}
          </nav>
          <main className="fade-in">
            {currentPage === Page.OVERVIEW && <Overview data={data} />}
            {currentPage === Page.SUNNY && <SeasonalDetail data={data} type="sunny" />}
            {currentPage === Page.RAINY && <SeasonalDetail data={data} type="rainy" />}
            {currentPage === Page.WINTER && <SeasonalDetail data={data} type="winter" />}
            {currentPage === Page.STATS && <StatsTable data={data} />}
            {currentPage === Page.GRAPHS && <Visuals data={data} />}
          </main>
        </>
      )}
    </div>
  );
};

