                      dataKey="frequency"
                      stroke="#0d9488"
                      strokeWidth={3}
                      fill="#0d9488"
                      fillOpacity={0.15}
                    />
                    <Tooltip 
                      contentStyle={{ borderRadius: '24px', border: 'none', boxShadow: '0 20px 40px rgba(0,0,0,0.1)' }}
                      formatter={(value: any, name: string) => [value, name === 'frequency' ? 'Months Dominant' : name]}
                    />
                  </RadarChart>
