                  <Area name="Min Temp" type="monotone" dataKey="tempMin" stroke="#3b82f6" strokeWidth={5} fill="transparent" />
                </AreaChart>
              </ResponsiveContainer>
            </div>
          </section>
        </div>
      )}
    </div>
  );
};

